-- Poems batch 337
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('87bc2079-d839-4b61-b4a0-1557bd79270c','句  其九九','釋惠崇','宋','宋诗','song-poetry','','[]','門掩前朝樹，心垂別郡峰。',12,'全唐诗/poet.song.6000.json','["門掩前朝樹，心垂別郡峰。"]'),
('aecff9ea-0864-4ad0-ab0e-1634a5c4892e','句  其一○○','釋惠崇','宋','宋诗','song-poetry','','[]','秋聲動羣木，暮色起千山。',12,'全唐诗/poet.song.6000.json','["秋聲動羣木，暮色起千山。"]'),
('ea690383-a3c8-4e01-a8bf-be06f4e63a6c','句  其一○一','釋惠崇','宋','宋诗','song-poetry','','[]','人遊曲江少，草入未央深。',12,'全唐诗/poet.song.6000.json','["人遊曲江少，草入未央深。"]'),
('c7365797-804e-4186-87c5-fb4073d85a99','句  其一○二','釋惠崇','宋','宋诗','song-poetry','','[]','曉風飄磬遠，暮雪入廊深。',12,'全唐诗/poet.song.6000.json','["曉風飄磬遠，暮雪入廊深。"]'),
('2b5c033a-3d12-44c2-9247-10687b1c234e','句  其一○三','釋惠崇','宋','宋诗','song-poetry','','[]','潏潏藥泉來石竇，霏霏茶靄出林梢。',16,'全唐诗/poet.song.6000.json','["潏潏藥泉來石竇，霏霏茶靄出林梢。"]'),
('89a2339a-186b-427a-9c52-10440b5cfede','句  其一○四','釋惠崇','宋','宋诗','song-poetry','','[]','花月病懷看酒譜，雲蘿幽信著茶經。',16,'全唐诗/poet.song.6000.json','["花月病懷看酒譜，雲蘿幽信著茶經。"]'),
('c7a170a2-7bfa-406f-ac9b-e958eea9c01b','句  其一○五','釋惠崇','宋','宋诗','song-poetry','','[]','峰後月明秋嘯去，水邊林影晚樵還。',16,'全唐诗/poet.song.6000.json','["峰後月明秋嘯去，水邊林影晚樵還。"]'),
('79cb3c4a-966b-4208-b7a8-3571ef49a834','夕陽','釋宇昭','宋','宋诗','song-poetry','','[]','向夕江天迥，微微接水平。',48,'全唐诗/poet.song.6000.json','["向夕江天迥，微微接水平。", "带帆歸極浦，隨客上荒城。", "雲外僧看落，山西鳥過明。", "何人對幽景，苒苒敗沙並。"]'),
('d2c30ef3-f1be-4f2f-b260-0be64531d23d','塞上贈王太尉','釋宇昭','宋','宋诗','song-poetry','','[]','嫖姚立大勳，萬里絕妖氛。',48,'全唐诗/poet.song.6000.json','["嫖姚立大勳，萬里絕妖氛。", "馬放降來地，雕閑戰後雲。", "月侵孤壘沒，燒徹遠蕪分。", "不慣爲邊客，宵笳懶欲聞。"]'),
('b569f9f5-b740-4ce0-aa80-b4717e3442f2','宿丁學士宅朱嚴希晝不至','釋宇昭','宋','宋诗','song-poetry','','[]','幽期不可見，牢落望君情。',48,'全唐诗/poet.song.6000.json','["幽期不可見，牢落望君情。", "坐久詩源寂，談餘井浪平。", "月依寒木盡，蛩背冷燈鳴。", "空聽溝西寺，宵鐘出禁清。"]'),
('d1cae340-07a8-4284-8c29-69c328c91990','廢井','釋宇昭','宋','宋诗','song-poetry','','[]','古院無僧住，荒涼樹石閑。',48,'全唐诗/poet.song.6000.json','["古院無僧住，荒涼樹石閑。", "停汙寒甃缺，廢汲遠泉慳。", "雨漲蛙疑聚，宵晴月自還。", "因尋成獨感，吟繞見衰顔。"]'),
('7bba1186-b094-4a12-bd0d-9053fef1a3dc','送曹商之宿州兼簡駱偃','釋宇昭','宋','宋诗','song-poetry','','[]','病起春城暮，行心暗結愁。',48,'全唐诗/poet.song.6000.json','["病起春城暮，行心暗結愁。", "全吳無舊業，半世祇羈遊。", "島霧沈晴樹，汀煙入夜舟。", "故人應老大，佐幕久淹流。"]'),
('e57efb3b-9467-435a-8320-e87287d057c8','寄保暹師','釋宇昭','宋','宋诗','song-poetry','','[]','吟會失秋期，荒山寄病時。',49,'全唐诗/poet.song.6000.json','["吟會失秋期，荒山寄病時。", "客髭生白早，叢木落青遲。", "渴狖窺沒莎井，陰蟲占菊籬。", "歸心何以見，霜月下天涯。"]'),
('1d84f905-dc6d-478e-bc26-9344b69290a1','上集賢錢侍郎','釋宇昭','宋','宋诗','song-poetry','','[]','解職因求養，清名冠集賢。',48,'全唐诗/poet.song.6000.json','["解職因求養，清名冠集賢。", "優遊書府裏，談笑板輿前。", "鶴氅朝時脫，山圖臥處懸。", "江僧閑獨訪，時得話林泉。"]'),
('d08e308b-6155-44b7-b42a-6c9c7241c2fb','喜惟鳳師關中回','釋宇昭','宋','宋诗','song-poetry','','[]','孤錫依京侍，詩愁上鬢新。',48,'全唐诗/poet.song.6000.json','["孤錫依京侍，詩愁上鬢新。", "跡離三輔晚，夢落九江頻。", "草入松根井，磬通花外鄰。", "重來知未倦，閑趣自相親。"]'),
('fa8ebb00-e5e5-4948-9bc5-bda5d1961b2e','松柄','釋宇昭','宋','宋诗','song-poetry','','[]','澗底分貞幹，寧將麈尾同。',48,'全唐诗/poet.song.6000.json','["澗底分貞幹，寧將麈尾同。", "坐閑長滴翠，話次忽生風。", "影落孤燈外，聲寒靜室中。", "有誰知外意，林下石叢叢。"]'),
('8908b35d-d21b-4407-89aa-af50f4c00360','幽居即事','釋宇昭','宋','宋诗','song-poetry','','[]','掃苔人跡外，漸老喜深藏。',48,'全唐诗/poet.song.6000.json','["掃苔人跡外，漸老喜深藏。", "路僻閑行遠，春晴晝睡長。", "餘花留暮蝶，幽草戀殘陽。", "盡日空林下，孤禪念石霜。"]'),
('cf6966ea-f81e-4003-96a1-f1020599e6c6','送從律師','釋宇昭','宋','宋诗','song-poetry','','[]','病起辭吟社，出京無舊房。',48,'全唐诗/poet.song.6000.json','["病起辭吟社，出京無舊房。", "關中行半月，詩外祇空囊。", "白道沿嵩直，青蕪夾渭長。", "勝遊多杜曲，風景似吾鄉。"]'),
('be4480c4-d88d-45c6-91d8-fb757e86d58b','贈魏野','釋宇昭','宋','宋诗','song-poetry','','[]','別業唯栽竹，多閑亦好奇。',48,'全唐诗/poet.song.6000.json','["別業唯栽竹，多閑亦好奇。", "試泉尋寺遠，買鶴到家遲。", "藥就全離母，詩高祇教兒。", "未能終住此，共有海山期。"]'),
('8208005d-02c7-45e4-91af-cf01450d1235','存目','釋宇昭','宋','宋诗','song-poetry','','[]','詩題：曉發山居首句：蓐食少人家。',16,'全唐诗/poet.song.6000.json','["詩題：曉發山居首句：蓐食少人家。"]'),
('469e0726-7b91-4191-a960-d6b6bb8881e1','送田錫下第歸寧','釋懷古','宋','宋诗','song-poetry','','[]','念別孤親久，無成萬里歸。',48,'全唐诗/poet.song.6000.json','["念別孤親久，無成萬里歸。", "算程芳草盡，去國故人稀。", "棧閣浮空險，刀州入望微。", "前期有公薦，莫愧老萊衣。"]'),
('28d14105-0679-4805-a901-7487dc676510','原居早秋','釋懷古','宋','宋诗','song-poetry','','[]','秋生深徑裏，老病眼慵開。',48,'全唐诗/poet.song.6000.json','["秋生深徑裏，老病眼慵開。", "戶外行人絕，林閑朔吹回。", "亂蛩鳴古塹，殘日照荒臺。", "唯有他山約，相親入望來。"]'),
('d2e9b641-0595-4a19-a264-8662bba6084e','聞蛩','釋懷古','宋','宋诗','song-poetry','','[]','幽蟲侵暮急，斷續苦相親。',48,'全唐诗/poet.song.6000.json','["幽蟲侵暮急，斷續苦相親。", "夜魄沈荒壘，寒聲出壤鄰。", "霜清空思切，秋永幾愁新。", "徒感流年鬢，莖莖暗結銀。"]'),
('0bbefa91-ce1c-496c-8563-1c1d1466671b','寺居寄簡長','釋懷古','宋','宋诗','song-poetry','','[]','雪苑東山寺，山深少往還。',48,'全唐诗/poet.song.6000.json','["雪苑東山寺，山深少往還。", "紅塵無夢想，白日自安閑。", "杖履苔花上，香燈樹影閑。", "何須更飛錫，歸隱沃洲山。"]'),
('6e1e20e1-ba62-447a-b08a-7b83de088945','灞陵秋居酬友人見寄','釋懷古','宋','宋诗','song-poetry','','[]','灞陵秋負期，獨客自懷悲。',48,'全唐诗/poet.song.6000.json','["灞陵秋負期，獨客自懷悲。", "遠水去無極，離人來幾時。", "暝煙沈古道，寒日墮喬枝。", "寄信遙天外，殷勤說白髭。"]'),
('d02eabdc-f0e8-4136-a375-a56bfafb4e3a','草','釋懷古','宋','宋诗','song-poetry','','[]','漠漠更離離，閑吟笑復悲。',48,'全唐诗/poet.song.6000.json','["漠漠更離離，閑吟笑復悲。", "六朝爭戰處，千載寂寥時。", "陣闊圍空壘，叢疏露斷碑。", "不堪殘照外，牧笛隔煙吹。"]'),
('d1d688e0-0c1d-4e49-a143-80a4aba3d308','和鄧慎思天啟有少年真喜事之句用其韵和','李公麟','宋','宋诗','song-poetry','','[]','秋日同文館，凄風動九回。',48,'全唐诗/poet.song.60000.json','["秋日同文館，凄風動九回。", "亂雲收暑去，一雨送寒來。", "猥與英躔接，慚非藻鑒陪。", "雍畿茲籲俊，元祐看新魁。"]'),
('15552906-764a-4237-a0a2-3a5454646b02','和鄧慎思初入試院','李公麟','宋','宋诗','song-poetry','','[]','敕使書囊問隊行，聚星深館粲諸英。',64,'全唐诗/poet.song.60000.json','["敕使書囊問隊行，聚星深館粲諸英。", "雲隨襟袖來蓬島，香散房櫳宿化城。", "振鷺充庭天有幕，珊瑚入網海無聲。", "範模一世尊先覺，况此提平慰後生。"]'),
('00ed620c-573b-4c9e-97e5-827782a12da0','和余樗年試院即事呈諸公','李公麟','宋','宋诗','song-poetry','','[]','盍簪聞善若江河，簾幕疏閒笑語過。',64,'全唐诗/poet.song.60000.json','["盍簪聞善若江河，簾幕疏閒笑語過。", "月照飛牋穿戶綺，風生揮麈動衣羅。", "已張英彀收三俊，更賦離騷續九歌。", "凉夜沉沉清不寐，空庭無奈葉聲何。"]'),
('388df771-1fe4-4e9e-80ae-6d4b4f7e91ca','和鄧慎思重九考罷試卷書呈同院諸公二首  其一','李公麟','宋','宋诗','song-poetry','','[]','籲俊天畿合辟雍，愧將瓦釜綴黄鐘。',64,'全唐诗/poet.song.60000.json','["籲俊天畿合辟雍，愧將瓦釜綴黄鐘。", "聽窮一一竽無濫，撥遍磷磷玉似逢。", "龜列春庭先壤奠，龍飛天路得雲從。", "吾曹莫念拘縈久，求稱公朝慶賞濃。"]'),
('fb5d7e13-37fe-46c8-b898-e474f319a68a','和鄧慎思重九考罷試卷書呈同院諸公二首  其二','李公麟','宋','宋诗','song-poetry','','[]','鞅掌棲遲一畝宮，憤聽更柝及晨鐘。',64,'全唐诗/poet.song.60000.json','["鞅掌棲遲一畝宮，憤聽更柝及晨鐘。", "黄華慰眼祗爾許，綠蟻於人亦漫逢。", "幾日囊篇賡不逮，三時庭步笑相從。", "近來尋却家山夢，投枕和衣睡更濃。"]'),
('d86c19d0-ab72-46d0-9c93-1ebfe740212d','和鄧慎思己未年春與伯時校試南宮同年被命者六人今茲西館唯同伯時一人而已因書奉呈','李公麟','宋','宋诗','song-poetry','','[]','憶鎖南宮會友文，天梯相攝看雲津。',32,'全唐诗/poet.song.60000.json','["憶鎖南宮會友文，天梯相攝看雲津。", "白頭笑我成今日，青眼逢君尚昔人。"]'),
('966cd50b-3684-41b0-b5c1-793b0c817324','謹次元韵奉酬慎思學士年友','李公麟','宋','宋诗','song-poetry','','[]','君家祝融水一方，平生書闈食可忘。',352,'全唐诗/poet.song.60000.json','["君家祝融水一方，平生書闈食可忘。", "雲河潄潤搴瑶芳，天帝璧府讎書郎。", "馳騁千載凌子長，神清骨秀顔色蒼。", "書淫傳癖笑輿狂，十年此會同都堂。", "上樓吟春碾旗槍，詩筒吳歈賡楚羌。", "一律校文公否臧，日飽大官沆瀣糧。", "朱鸞入網空南岡，賢書奏牘紛滿床。", "朝出粉闈暮帝旁，駸駸天路羣龍驤。", "病鴟帖帖乃汙隍，白雲隴望因俶裝。", "放歌長林聲激揚，佩蘭思馨雖朋亡。", "雲出鳥還聊自償，羽扇麈尾隨經囊。", "龍眠乃是無何鄉，朝游不辭麋鹿行。", "歸卧展圖觀驌驦，憲貧頌古時歌商。", "徜徉興罷住雲房，焚柏翻經究法王。", "冉冉暗度歲月光，山頭草青還葉黄。", "洞明已死閒骨香，凡志未就嗟凉凉。", "親顛向白每稱觴，旨甘鞭後難翱翔。", "朅來竊食天中央，古人千歲空相望。", "同文鎖密御史霜，得公再集評文章。", "亦說種松輞口莊，使我夢蝶栩栩忙。", "便欲負郭占農祥，門開儻容倚孔牆。", "想挽北斗下挹漿，箜篌更對高秋張。"]'),
('6712dbd8-2ff0-48b9-95f9-1b151d58d40b','贈蔡天啟','李公麟','宋','宋诗','song-poetry','','[]','上泝虞姒亦易爾，下者始置周秦間。',32,'全唐诗/poet.song.60000.json','["上泝虞姒亦易爾，下者始置周秦間。", "造端宏大町畦絕，往往世俗遭譏訕。"]'),
('9d33be31-afc6-4774-936b-2949925cbae2','小詩並畫卷奉送汾叟同年機宜奉議赴熙河幕府','李公麟','宋','宋诗','song-poetry','','[]','畫出離筵已愴神，那堪真別渭城春。',32,'全唐诗/poet.song.60000.json','["畫出離筵已愴神，那堪真別渭城春。", "渭城柳色休相惱，西出陽關有故人。"]'),
('9fc5bf35-1f78-4a12-bfa6-9bb0ac235aa1','醉卧圖詩帖','李公麟','宋','宋诗','song-poetry','','[]','有道難行不如醉，有口難言不如睡。',32,'全唐诗/poet.song.60000.json','["有道難行不如醉，有口難言不如睡。", "先生醉卧在石間，萬古無人知此意。"]'),
('b63cfb55-7eb9-402e-8e3f-3aa53b6004f0','春社出郊','李公麟','宋','宋诗','song-poetry','','[]','千尋古櫟笑聲中，此日春風屬社公。',64,'全唐诗/poet.song.60000.json','["千尋古櫟笑聲中，此日春風屬社公。", "開眼已憐花壓帽，放懷聊喜酒治聾。", "携刀割肉餘風在，卜瓦傳神俚俗同。", "聞說已栽桃李徑，隔溪遥認淺深紅。"]'),
('1249bd66-8da4-47b7-a541-be2f25b413b0','題醒心亭','常安民','宋','宋诗','song-poetry','','[]','爲愛昌黎湖上句，醉來直上醒心亭。',32,'全唐诗/poet.song.60000.json','["爲愛昌黎湖上句，醉來直上醒心亭。", "煩酲不待山風解，卧讀殘碑已自醒。"]'),
('0117225b-5363-4d4d-b916-987fb76ddf7e','懷嵩樓','常安民','宋','宋诗','song-poetry','','[]','當年謾作嵩山想，末路難回瘴海身。',32,'全唐诗/poet.song.60000.json','["當年謾作嵩山想，末路難回瘴海身。", "斜日西風總如昨，風流只欠倚欄人。"]'),
('be03fb07-4ffe-49b5-8c8f-bb557d324791','遊師埪寺留題','程奇','宋','宋诗','song-poetry','','[]','塵中總總誰青眼，黄髮蒼顔世情短。',64,'全唐诗/poet.song.60000.json','["塵中總總誰青眼，黄髮蒼顔世情短。", "坐看前溪一片雲，安得相從任舒卷。", "浩歌聊詠北山薇，不有歸心真自欺。", "欲借養和延晝夢，數聲啼鳥日平西。"]'),
('3655087a-82be-4f92-b28d-a009486ced02','劉阮洞','王沔之','宋','宋诗','song-poetry','','[]','流傳晨肇隠無蹤，搜發仙源屬鄭公。',64,'全唐诗/poet.song.60000.json','["流傳晨肇隠無蹤，搜發仙源屬鄭公。", "百尺靈泉清澈底，千尋蒼玉勢凌空。", "飄香故跡人雖到，採藥巔崖路不通。", "二女深沉斷消息，桃花依舊笑春風。"]'),
('429d112c-ddeb-4285-b5dd-cdb4cb9d9852','題耿氏溫凊堂','滿中行','宋','宋诗','song-poetry','','[]','密牖疏櫺次第施，却寒清暑兩相宜。',64,'全唐诗/poet.song.60000.json','["密牖疏櫺次第施，却寒清暑兩相宜。", "惟知堂上雙親樂，不覺人間四序移。", "美酒先春和氣滿，茂林亭午綠陰垂。", "閒居就養如君少，無負南陔孝子詩。"]'),
('a95d279a-39a4-4293-9d05-8672abb1cb66','真仙巖二首  其一','錢師孟','宋','宋诗','song-poetry','','[]','巨石何爭此結成，老君有像亦難名。',32,'全唐诗/poet.song.60000.json','["巨石何爭此結成，老君有像亦難名。", "以身爲患言猶在，漫使當時分重輕。"]'),
('04a39521-3c53-4d64-bd40-5919dac785cb','真仙巖二首  其二','錢師孟','宋','宋诗','song-poetry','','[]','巖前流水碧潺潺，鶴馭翩翩去復還。',32,'全唐诗/poet.song.60000.json','["巖前流水碧潺潺，鶴馭翩翩去復還。", "堪笑世人求不死，豈知得道有無閒。"]'),
('47b010b3-a163-4608-b68b-cf87b14135c5','題汝墳驛壁三首  其一','廖正一','宋','宋诗','song-poetry','','[]','阿憐二十頗有餘，秀眉豐頰冰瓊膚。',32,'全唐诗/poet.song.60000.json','["阿憐二十頗有餘，秀眉豐頰冰瓊膚。", "無端欲作商人婦，更枉方尋海畔夫。"]'),
('727339fa-4639-4820-81b3-860b234a6ca4','題汝墳驛壁三首  其二','廖正一','宋','宋诗','song-poetry','','[]','阿梅笄歲得同歡，懊惱情深解夢蘭。',32,'全唐诗/poet.song.60000.json','["阿梅笄歲得同歡，懊惱情深解夢蘭。", "鶑語輕清花裏話，柳條柔嫩掌中看。"]'),
('0ed3f89d-db7d-42db-b907-f14f48e3e42e','題汝墳驛壁三首  其三','廖正一','宋','宋诗','song-poetry','','[]','淮源距襄陽，亭候逾十舍。',48,'全唐诗/poet.song.60000.json','["淮源距襄陽，亭候逾十舍。", "征鞍背繡幃，雲雨□四夜。", "雙艷盡傾城，一姝偏擅價。", "獨怒蕙心輕，誤許商人嫁。"]'),
('a3245d60-90ca-4fa3-b44c-c0d2bfc835a4','答張十八畫','廖正一','宋','宋诗','song-poetry','','[]','玉人風味夙相親，骨法多奇巫峽神。',32,'全唐诗/poet.song.60000.json','["玉人風味夙相親，骨法多奇巫峽神。", "何幸丹青煩右相，坐令虛室四時春。"]'),
('d411c784-286b-4408-adbc-bcbe7f37cd5c','和吳可權長官','廖正一','宋','宋诗','song-poetry','','[]','士元應展驥，百里聊爾絆。',24,'全唐诗/poet.song.60000.json','["士元應展驥，百里聊爾絆。", "函繼三異聲，江述憑東觀。"]'),
('f4b70bf7-5217-431d-be6c-fcd30d46ed29','和李主簿彥和','廖正一','宋','宋诗','song-poetry','','[]','李侯持尺璧，十五城不換。',60,'全唐诗/poet.song.60000.json','["李侯持尺璧，十五城不換。", "倦飛偶棲棘，孤鳴異巢鸛。", "淮海一俊乂，博洽識理亂。", "國論匪與聞，偷將經術斷。", "君家文多豪，陵嶠賀白觀。"]'),
('2984da18-8c60-42dc-b082-2693e44ee4d5','和補之梅花','廖正一','宋','宋诗','song-poetry','','[]','蕙蘭芳草久睽離，偶洩春光此一枝。',64,'全唐诗/poet.song.60000.json','["蕙蘭芳草久睽離，偶洩春光此一枝。", "自許輕盈羞粉白，何人閒麗得鄰窺。", "寒欺薄酒魂消夜，月入重簾夢破時。", "幸有暗香襟袖暖，江南歸信不應遲。"]'),
('0ab7d470-9910-41d5-b28c-7364b7eb53d6','劉阮洞','鄭至道','宋','宋诗','song-poetry','','[]','採藥歸來世代賒，洞門方此掃烟霞。',64,'全唐诗/poet.song.60000.json','["採藥歸來世代賒，洞門方此掃烟霞。", "碧潭清泚弄明月，翠巘高低飄落花。", "芳草已迷當日路，白雲空想舊人家。", "自慚不是浮觴侶，謾向山前醉帽斜。"]'),
('78f9dab1-9a7f-4e0c-95d8-af6ba78ea9df','句','鄭至道','宋','宋诗','song-poetry','','[]','近村得雨遠村同，上圳流波下圳通。',16,'全唐诗/poet.song.60000.json','["近村得雨遠村同，上圳流波下圳通。"]'),
('2b927de5-4a90-40b6-bfb2-613d921a0f86','安適軒','唐最','宋','宋诗','song-poetry','','[]','卧聽潮音坐看山，烟蘿靜處閉禪關。',64,'全唐诗/poet.song.60000.json','["卧聽潮音坐看山，烟蘿靜處閉禪關。", "都將物外紅塵隔，占得壺中白日閒。", "吟罷寒猿號木末，定回清磬落雲間。", "高僧隠几無餘事，應笑勞生去又還。"]'),
('8a76f3d8-67ac-4e76-8a9d-55da4f7d1b66','高蓋名山院二首  其一','施常','宋','宋诗','song-poetry','','[]','白雲來去自閑閑，鎖勒千山與萬山。',32,'全唐诗/poet.song.60000.json','["白雲來去自閑閑，鎖勒千山與萬山。", "仙客已歸霄漢去，虛堂流水漫潺潺。"]'),
('fb0dabc3-f525-478a-a1a3-ee74b69e0ebf','高蓋名山院二首  其二','施常','宋','宋诗','song-poetry','','[]','步盡千山與萬山，白雲步處叩禪關。',32,'全唐诗/poet.song.60000.json','["步盡千山與萬山，白雲步處叩禪關。", "曉猿夜鶴應相笑，笑問勞生幾度閑。"]'),
('4b6112b1-65d4-4bf3-b738-b4c8fe511558','擊甌樓','邵叶','宋','宋诗','song-poetry','','[]','駐旌元帥遺風在，擊缶高人逸興酣。',32,'全唐诗/poet.song.60000.json','["駐旌元帥遺風在，擊缶高人逸興酣。", "水轉巴文清溜急，山連蒙岫翠光涵。"]'),
('9f5244ba-a622-4400-b895-23f42a9759d1','麓陰亭','邵叶','宋','宋诗','song-poetry','','[]','山腰路轉響灣泉，一徑悠然陟翠巔。',64,'全唐诗/poet.song.60000.json','["山腰路轉響灣泉，一徑悠然陟翠巔。", "滿眼祥雲繞法供，刊岩瑞像儼金仙。", "元戎孝感諸天護，古木歌題峭壁鎸。", "俯仰巖亭盡幽絕，夜深燈火更流連。"]'),
('d63bd132-811b-4f02-9a59-11c5e55a0ee7','句','徐常','宋','宋诗','song-poetry','','[]','詞賦切宜師二宋，文章須是學三蘇。',16,'全唐诗/poet.song.60000.json','["詞賦切宜師二宋，文章須是學三蘇。"]'),
('09bc21fc-db34-4a1e-91da-b831d06158ff','遺賈耘老蟹','沈偕','宋','宋诗','song-poetry','','[]','黄秔稻熟墜西風，肥入江南十月雄。',64,'全唐诗/poet.song.60000.json','["黄秔稻熟墜西風，肥入江南十月雄。", "橫跪蹣跚鉗齒白，圓臍吸脅斗膏紅。", "虀須園老香研柚，羹藉庖丁細擘葱。", "分寄橫塘溪上客，持螯莫放酒杯空。"]'),
('345cf38a-b580-48d3-8c8a-2f1fe38f1406','報賈耘老詩仍次韵','沈偕','宋','宋诗','song-poetry','','[]','蟲腹無端苦動風，團雌還却勝尖雄。',64,'全唐诗/poet.song.60000.json','["蟲腹無端苦動風，團雌還却勝尖雄。", "水寒且弄雙鉗利，湯老難逃一背紅。", "液入幾家煩海滷，醢成何處污園葱。", "好收心躁潜蛇穴，毋使雷驚族類空。"]'),
('5f66d260-8aed-4096-9648-128c93d64a6a','贈歐陽𣲤','劉祕','宋','宋诗','song-poetry','','[]','妙筆君今第一人，心欺造化奪天真。',32,'全唐诗/poet.song.60000.json','["妙筆君今第一人，心欺造化奪天真。", "精明形骨從來一，移入青縑作兩身。"]'),
('bea215fd-dadb-4adf-8a30-767d8bf0e03b','烟雨樓','李丹','宋','宋诗','song-poetry','','[]','乾坤交泰氣氤氳，烟雨標名望意云。',32,'全唐诗/poet.song.60000.json','["乾坤交泰氣氤氳，烟雨標名望意云。", "自是聖時多瑞靄，莫疑蠻徼有妖氛。"]'),
('48ef8420-dded-4a6a-b1f7-c8d22e321753','天堂地獄偈','李丹','宋','宋诗','song-poetry','','[]','釋迦生中國，設教如周孔。',48,'全唐诗/poet.song.60000.json','["釋迦生中國，設教如周孔。", "周孔生西方，設教如釋迦。", "天堂無則已，有則君子登。", "地獄無則已，有則小人入。"]'),
('a724ec51-5ecf-4083-95c6-62ab15a9a2f5','留題真陽南山','李丹','宋','宋诗','song-poetry','','[]','南山地久與天長，磐石安基勢永昌。',32,'全唐诗/poet.song.60000.json','["南山地久與天長，磐石安基勢永昌。", "億世皇圖齊不拔，萬年聖壽等無疆。"]'),
('7f3fe258-6a7f-48ef-b913-2137b74b4faf','句','李丹','宋','宋诗','song-poetry','','[]','二頃田園祇舊時。',8,'全唐诗/poet.song.60000.json','["二頃田園祇舊時。"]'),
('e34d4931-18c5-4b96-819d-0e3f6737d72a','蝗不入青丘','林磐','宋','宋诗','song-poetry','','[]','賑濟饑荒尚未蘇，旱蝗何幸我疆無。',32,'全唐诗/poet.song.60000.json','["賑濟饑荒尚未蘇，旱蝗何幸我疆無。", "悲愁遠宦天應閔，不復鄉村鬧鼓桴。"]'),
('86174d9c-48da-4d6c-a451-9ac7642fd174','同黄秘校遊連江玉泉','林迥','宋','宋诗','song-poetry','','[]','泉山好景微，權尹訟庭希。',48,'全唐诗/poet.song.60000.json','["泉山好景微，權尹訟庭希。", "曉馬破雲去，夜船乘月歸。", "妓歌珠不斷，人醉玉相依。", "薄宦自拘者，咄哉多是非。"]'),
('f8953bb6-f734-46c8-a233-26310abb8c84','四時山丹','林迥','宋','宋诗','song-poetry','','[]','葉剪青油藥渥丹，春風隨衆出欄干。',32,'全唐诗/poet.song.60000.json','["葉剪青油藥渥丹，春風隨衆出欄干。", "碧桃黄菊凋殘後，誰伴長松到歲寒。"]'),
('a9502947-3042-4bf8-8684-f354639b5239','長春','林迥','宋','宋诗','song-poetry','','[]','洞門深不放春歸，客到尋芳莫問時。',32,'全唐诗/poet.song.60000.json','["洞門深不放春歸，客到尋芳莫問時。", "遲日暖風花草麗，照人紅艷一枝枝。"]'),
('36a19d6e-f225-4dc1-a3c8-1e720c3a7c54','題林子默隠居','林迥','宋','宋诗','song-poetry','','[]','先生平昔命何非，萬卷詩書一布衣。',32,'全唐诗/poet.song.60000.json','["先生平昔命何非，萬卷詩書一布衣。", "回首長安成底事，吳山蒼翠幾時歸。"]'),
('67a5dca6-36a2-4a07-a013-f72a131ddcbd','留題宿猿洞','林迥','宋','宋诗','song-poetry','','[]','幾年形勝晦南州，一旦聲名藹湛侯。',64,'全唐诗/poet.song.60000.json','["幾年形勝晦南州，一旦聲名藹湛侯。", "夜色併來三島月，水光分破五湖秋。", "荔枝影裏安吟榻，紅藕香中繫釣舟。", "金印解還天子後，詔書徵起不回頭。"]'),
('f768722b-94b1-4010-b713-c2ec207e8e49','句  其一','林迥','宋','宋诗','song-poetry','','[]','門前紅日海千里，池上白蓮山四鄰。',16,'全唐诗/poet.song.60000.json','["門前紅日海千里，池上白蓮山四鄰。"]'),
('7755a866-8410-41c7-a10e-15c479f54f3b','句  其二','林迥','宋','宋诗','song-poetry','','[]','青韮供盤餠面圓。',8,'全唐诗/poet.song.60000.json','["青韮供盤餠面圓。"]'),
('f38553a3-b0bd-4584-8b82-46dc88cbc52f','句  其三','林迥','宋','宋诗','song-poetry','','[]','春晚花王在處稀，山中還信正芳菲。',16,'全唐诗/poet.song.60000.json','["春晚花王在處稀，山中還信正芳菲。"]'),
('e16efdd6-c6d5-42b7-ab3b-3261cb90317e','句  其四','林迥','宋','宋诗','song-poetry','','[]','多謝東君深屬意。',8,'全唐诗/poet.song.60000.json','["多謝東君深屬意。"]'),
('cbf27fc1-4f5e-4b39-b67d-afa8fde57f28','句  其五','林迥','宋','宋诗','song-poetry','','[]','過門人指朝郎宅，入室渾如野老家。',16,'全唐诗/poet.song.60000.json','["過門人指朝郎宅，入室渾如野老家。"]'),
('73610b73-9553-4709-80dd-752397ff330b','句  其六','林迥','宋','宋诗','song-poetry','','[]','尺書中夜至，清曉即揚鞭。',12,'全唐诗/poet.song.60000.json','["尺書中夜至，清曉即揚鞭。"]'),
('973a3789-f135-4ad5-b564-b1a7242c7016','句  其七','林迥','宋','宋诗','song-poetry','','[]','汲水僧歸林下寺。',8,'全唐诗/poet.song.60000.json','["汲水僧歸林下寺。"]'),
('b49733a2-7301-443c-a746-f024236b13f7','句  其八','林迥','宋','宋诗','song-poetry','','[]','當年春榜首傳名，對御如君有幾人。',16,'全唐诗/poet.song.60000.json','["當年春榜首傳名，對御如君有幾人。"]'),
('554ac3fd-7bc5-4a52-a81c-02e1a1c2aab8','元明觀鄒希衍丹室','都頡','宋','宋诗','song-poetry','','[]','嘉樹團團蔽紫烟，黄冠師作地行仙。',64,'全唐诗/poet.song.60000.json','["嘉樹團團蔽紫烟，黄冠師作地行仙。", "留形住室真餘事，鍊氣精思本自然。", "鶴警喬松常見月，龜藏浮葉不知年。", "坐中應到諸天上，曾侍玉皇香案前。"]'),
('5f81ec1e-dabf-48f6-8c18-3b3467e0fe67','贈呂本中弟','劉斯川','宋','宋诗','song-poetry','','[]','大阮平生余所愛，小阮相逢亦傾蓋。',64,'全唐诗/poet.song.60000.json','["大阮平生余所愛，小阮相逢亦傾蓋。", "濟陰未識情更親，信手新詩落珠貝。", "楊氏作公誰料理，臧孫有後誠可喜。", "長亭水落風雨多，無酒飲君如別何。"]'),
('05bb5feb-4d60-4d90-86ca-c1cdc72edc53','絕句','紆川','宋','宋诗','song-poetry','','[]','小徑緣溪綠，低簷傍樹陰。',24,'全唐诗/poet.song.60000.json','["小徑緣溪綠，低簷傍樹陰。", "好峰秋入眼，清月夜窺林。"]'),
('10632e53-1e3d-40e0-ae43-a56b2801459a','四時四首 春','梅窗','宋','宋诗','song-poetry','','[]','晝永春庭邃，雙飛燕隔簾。',24,'全唐诗/poet.song.60000.json','["晝永春庭邃，雙飛燕隔簾。", "袖隨簾捲翠，時見玉纖纖。"]'),
('8229bd19-1ccc-4876-a2a0-164677ede037','四時四首 夏','梅窗','宋','宋诗','song-poetry','','[]','曲澗跳珠碎，叢山疊翠濃。',24,'全唐诗/poet.song.60000.json','["曲澗跳珠碎，叢山疊翠濃。", "竹新敷影薄，閒看倚枝筇。"]'),
('fb30276b-60c5-4491-addf-65d757a2f803','四時四首 秋','梅窗','宋','宋诗','song-poetry','','[]','小雨凉添夜，蘭芬潤襲衣。',24,'全唐诗/poet.song.60000.json','["小雨凉添夜，蘭芬潤襲衣。", "曉屏山曲曲，長若夢思歸。"]'),
('302d2808-b1b8-43b7-9899-d9c068b917ac','四時四首 冬','梅窗','宋','宋诗','song-poetry','','[]','曲徑穿叢密，香清爲客來。',24,'全唐诗/poet.song.60000.json','["曲徑穿叢密，香清爲客來。", "玉梢梢外雪，苔古暈疏梅。"]'),
('4da48d3d-777a-4615-beb4-74743124bdf9','秋江寫望','梅窗','宋','宋诗','song-poetry','','[]','寒江暮泊小舟輕，白鷺棲烟叢葦鳴。',32,'全唐诗/poet.song.60000.json','["寒江暮泊小舟輕，白鷺棲烟叢葦鳴。", "寬望遠空浮湛碧，老蟾驚玉弄秋清。"]'),
('f5fdfae4-eae6-4644-a969-36d54ab43e28','西湖戲書二首  其一','梅窗','宋','宋诗','song-poetry','','["\u897f\u6e56"]','蜿蜿翠麓秋烟漲，灧灧金波夜月澄。',32,'全唐诗/poet.song.60000.json','["蜿蜿翠麓秋烟漲，灧灧金波夜月澄。", "樽酒具時隨興遣，景多逢處曲欄憑。"]'),
('44f52c81-d2ab-4dbf-9843-55ac8e4a0ccf','西湖戲書二首  其二','梅窗','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雲巢望斷望西湖，竹護梅藏隠士居。',32,'全唐诗/poet.song.60000.json','["雲巢望斷望西湖，竹護梅藏隠士居。", "芬草綠深春盎盎，客來同攬一山孤。"]'),
('4a7ed74b-6379-4430-9351-a3cadfaf3f96','春望','梅窗','宋','宋诗','song-poetry','','[]','絲絲柳翠連雲幕，點點鷗輕漾晚波。',32,'全唐诗/poet.song.60000.json','["絲絲柳翠連雲幕，點點鷗輕漾晚波。", "時事無心隨興遠，日長閒處理衣蓑。"]'),
('db4633a7-5bf3-400b-841b-0530327f55e7','因小兒學琴終夜不寐作','陳子高','宋','宋诗','song-poetry','','[]','鳴鶴操音清，興幽發性情。',24,'全唐诗/poet.song.60000.json','["鳴鶴操音清，興幽發性情。", "聽琴愛夜半，明月上殘更。"]'),
('9782642a-5828-47ac-96dd-5f51aac24a9b','客懷','陳子高','宋','宋诗','song-poetry','','[]','遠山雲夢斷，長路客愁新。',24,'全唐诗/poet.song.60000.json','["遠山雲夢斷，長路客愁新。", "殘漏悲鐘急，香車碾暗塵。"]'),
('84e3e4e6-b8f8-490b-95db-a3810514f18b','暮春','陳子高','宋','宋诗','song-poetry','','[]','纖纖亂草平灘，冉冉雲歸遠山。',28,'全唐诗/poet.song.60000.json','["纖纖亂草平灘，冉冉雲歸遠山。", "簾捲深空日永，鳥鳴花落春殘。"]'),
('53baa633-7f58-4cbf-8a16-860caa4481d1','春晝','陳子高','宋','宋诗','song-poetry','','[]','悠悠亂片花空舞，冉冉輕絲晴晝長。',32,'全唐诗/poet.song.60000.json','["悠悠亂片花空舞，冉冉輕絲晴晝長。", "樓下怯寒香袖薄，破愁春酌濁醪香。"]'),
('c36f5179-3c81-4afe-8cbc-62c2bd62f169','宿龜山次韵','陳子高','宋','宋诗','song-poetry','','[]','潮回浪濺細沙傾，岸柳平波映眼明。',64,'全唐诗/poet.song.60000.json','["潮回浪濺細沙傾，岸柳平波映眼明。", "橋接短亭連野迥，艇橫長笛带風清。", "迢迢翠草寒烟暝，隠隠疏林暮靄晴。", "遥見疊峰清淺黛，客心傷處碧雲輕。"]'),
('60e33f4c-0105-4bc9-b2a2-b70a341eea6f','詠梅','茹芝翁','宋','宋诗','song-poetry','','[]','東溪小步晚烟隨，玉點花疏竹外枝。',32,'全唐诗/poet.song.60000.json','["東溪小步晚烟隨，玉點花疏竹外枝。", "風襲袖香清滿徑，匆匆好處恨來遲。"]'),
('ea3f7ea8-124a-4acf-9979-9040059ee827','秋月收兵獻鍾侍郎','茹芝翁','宋','宋诗','song-poetry','','[]','强兵義勇威嚴令，化靖由來不戰征。',64,'全唐诗/poet.song.60000.json','["强兵義勇威嚴令，化靖由來不戰征。", "疆境復時歸馬健，鼓鼙休處亂雲輕。", "霜凝積恨懷邊戍，月落衝寒夜上城。", "黄葉樹頭風凜凜，碧波江遠路平平。"]'),
('c3bca0ed-248c-405d-b6b0-a2d4d047a303','留題南山','時彥','宋','宋诗','song-poetry','','[]','青松夾道英州路，終日千巖萬壑間。',32,'全唐诗/poet.song.60000.json','["青松夾道英州路，終日千巖萬壑間。", "唯是看山心不足，又携兵妓看南山。"]'),
('ba7d8867-73c0-4650-9013-8d467427c37e','寄劉仲平','劉跂','宋','宋诗','song-poetry','','[]','移居逼城阿，頗似山中住。',72,'全唐诗/poet.song.60000.json','["移居逼城阿，頗似山中住。", "當軒列佳石，繞舍紛高樹。", "園林便爲主，魚鳥欣相聚。", "春來物物好，適意隨所遇。", "是適本無因，亦復無定處。", "當有忘機人，知我此中趣。"]'),
('5e80ebdb-875c-47b6-a381-9ab11d31ff71','重寄','劉跂','宋','宋诗','song-poetry','','[]','憶昨去國初，置傳史所監。',288,'全唐诗/poet.song.60000.json','["憶昨去國初，置傳史所監。", "季也行泣隨，往舍都城南。", "沐我屢飯我，終此一日淹。", "明作分嶺水，苦別心如惔。", "遄歸護孥重，却掛東川帆。", "停橈憩汴泗，攬轡趨霍灊。", "間關又相對，共被栖窮簷。", "未畢十日懽，已復秣征驂。", "猗嗟季行役，曷日弛負擔。", "長懷芳草句，未讀衣已沾。", "先人門戶事，駑力詎克堪。", "一朝奇禍發，熾甚烈火炎。", "頑迷得憂辱，自取非謗讒。", "危巢風雨漂，菅蒯不足芟。", "于時季來歸，棄官不待占。", "收合敗散餘，頼此守獨嚴。", "闔門數百指，一一恩意涵。", "輯睦乖迕情，牢不見隙纖。", "聚糧非短轂，千里均屬厭。", "囊書動高聽，恩環賜東漸。", "吾親所奇貴，挺立故不凡。", "晚節就難冀，前非掩多慚。", "正如已躄人，欻起蒙鍼砭。", "衰顔積霜雪，幸亦解羈銜。"]'),
('2dd8203e-7bf9-4b5a-9d1f-6e5e578c6bc1','集句寄斯川','劉跂','宋','宋诗','song-poetry','','[]','渺渺孤舟逝，計日望舊居。',120,'全唐诗/poet.song.60000.json','["渺渺孤舟逝，計日望舊居。", "萬族各有託，吾亦愛吾廬。", "栖栖失羣鳥，暫與田園疏。", "令日始復來，再喜見友于。", "緬然睇崇丘，負疴不獲俱。", "試携子姪輩，且還讀我書。", "親戚共一處，過此奚所須。", "起晚眠常早，誰謂形迹拘。", "厚恩固難忘，慨然念黄虞。", "養真衡茅下，不樂復何如。"]'),
('7f98fa66-4bf3-4d79-b8d3-9e465aad0c4d','寄馬全玉','劉跂','宋','宋诗','song-poetry','','[]','歲月如歸鴻，秋至欻將翔。',120,'全唐诗/poet.song.60000.json','["歲月如歸鴻，秋至欻將翔。", "郊原带爽氣，榆柳媚無光。", "客子抱幽獨，耿耿誰與明。", "不辭青鞋賤，來躡君子堂。", "君子松檜姿，勁不慘風霜。", "其交淡如水，衆口未易嘗。", "忘言默領會，此意却難忘。", "不飲知酒趣，聊復酌公漿。", "寒燈夜寥閴，一笑未渠央。", "誰令別離此，夢寐長相望。"]'),
('8190125b-ba4f-4483-b252-fa7864d1bea3','寄尹遷介叔  其一','劉跂','宋','宋诗','song-poetry','','[]','我生非良材，頑礦不受礪。',48,'全唐诗/poet.song.60000.json','["我生非良材，頑礦不受礪。", "讀書但漁獵，初不名一藝。", "形骸弱如柳，暑雨更疲曳。", "清風何時生，一掃去酷吏。"]'),
('dc05fd39-5398-42a5-b647-9a7134249c72','寄尹遷介叔  其二','劉跂','宋','宋诗','song-poetry','','[]','孫友太瘦生，相遇一何闊。',48,'全唐诗/poet.song.60000.json','["孫友太瘦生，相遇一何闊。", "途窮欲改操，冉冉在故轍。", "贈君七年艾，輒爲兒女奪。", "養生有標本，姑息良已末。"]'),
('c1aa513f-eaad-46ad-8d50-d820dc3249c7','寄尹遷介叔  其三','劉跂','宋','宋诗','song-poetry','','[]','我有好詩酒，端爲舅氏作。',48,'全唐诗/poet.song.60000.json','["我有好詩酒，端爲舅氏作。", "陳遵見張竦，雖見不改樂。", "小官未朝謁，日日事飲博。", "書來託天真，笑我守糟粕。"]'),
('d642b5bf-e878-4ac9-8348-d515b2fd7997','寄尹遷介叔  其四','劉跂','宋','宋诗','song-poetry','','[]','二尹山東秀，一第安足賀。',48,'全唐诗/poet.song.60000.json','["二尹山東秀，一第安足賀。", "滕侯薦鶚書，極口良未過。", "青衫五斗米，所要脫饑餓。", "自重士當然，蓄積非爲貨。"]'),
('21f02e34-99dc-47fc-8734-0151284ed4d4','寄尹遷介叔  其五','劉跂','宋','宋诗','song-poetry','','[]','前年郭法曹，寓直經略院。',48,'全唐诗/poet.song.60000.json','["前年郭法曹，寓直經略院。", "同時幕府歸，獨送兩秋燕。", "新書滿百帙，鉛槧老不倦。", "他時淮南子，試爲離騷傳。"]'),
('8f197a4d-2fbd-4bb2-b6d8-a9cbfbdcacdb','寄尹遷介叔  其六','劉跂','宋','宋诗','song-poetry','','[]','養志如養力，益峻在益礪。',48,'全唐诗/poet.song.60000.json','["養志如養力，益峻在益礪。", "大方略畦畛，小智私才藝。", "古來要倔彊，檻折不可曳。", "何謂薛贛君，小生敢相吏。"]'),
('745610df-f93f-4811-bd03-60375ea5fa3c','寄尹遷介叔  其七','劉跂','宋','宋诗','song-poetry','','[]','擇術患不終，未易笑迂闊。',48,'全唐诗/poet.song.60000.json','["擇術患不終，未易笑迂闊。", "發軔三尺輪，不改萬里轍。", "死生漢節共，巨猾氣爲奪。", "坐令李都尉，慟哭天壤末。"]'),
('64a01017-96a8-45be-87b6-5ba314474fc8','寄尹遷介叔  其八','劉跂','宋','宋诗','song-poetry','','[]','鴟夷笑井瓶，同是意匠作。',48,'全唐诗/poet.song.60000.json','["鴟夷笑井瓶，同是意匠作。", "拘方等歸盡，放意差獨樂。", "往時二千石，天子償負博。", "彼視淑德侯，何堪貯糟粕。"]'),
('6e9b9fd9-88da-4588-afd3-806dc8a65c58','寄尹遷介叔  其九','劉跂','宋','宋诗','song-poetry','','[]','歌詞郢中來，未數白與賀。',48,'全唐诗/poet.song.60000.json','["歌詞郢中來，未數白與賀。", "一斑昧全虎，端似隙中過。", "可憐光萬丈，不救妻子餓。", "平生嚴鄭公，皂隸有餘貨。"]'),
('4e42928e-a36e-4108-ad19-60eed65ebc7a','寄尹遷介叔  其一○','劉跂','宋','宋诗','song-poetry','','[]','吏隠非山林，州府爲道院。',48,'全唐诗/poet.song.60000.json','["吏隠非山林，州府爲道院。", "莫夸非食肉，虎頭頷如燕。", "公田亦種秫，瞥去飛鳥倦。", "何用蕭德施，先生自爲傳。"]'),
('8af1c8d0-f2a0-4880-942c-3841875eb6b5','送陳述之','劉跂','宋','宋诗','song-poetry','','[]','羸軀抱肺惡，喘甚劇奔豚。',144,'全唐诗/poet.song.60000.json','["羸軀抱肺惡，喘甚劇奔豚。", "水飯輒短氣，矧敢近酒尊。", "君亦謝嵇阮，力釂不盈分。", "相看但蕭索，何以慰離羣。", "往昔各少年，束带登橋門。", "白眼霄漢際，冥鴻注孤鶱。", "我髯今蒼黄，君髮亦翩翻。", "同吏一州縣，凍螢彊相溫。", "豗頹歲月去，此事更誰怨。", "願君愛玉體，長使百憂諼。", "非關易斗粟，政恐耕耘煩。", "他時老相問，一笑坐忘言。"]'),
('9acec60e-2457-4600-aa6c-a82a5761ae77','送徐彥榮','劉跂','宋','宋诗','song-poetry','','[]','嬋娟水邊楊，宛是渭川竹。',96,'全唐诗/poet.song.60000.json','["嬋娟水邊楊，宛是渭川竹。", "光翠相動搖，照我尊酒綠。", "松風含衆籟，雲月澹華燭。", "何必簫與鼓，清言媚幽獨。", "當年妙風致，文采自膏沐。", "會逢百煉明，照此燕趙玉。", "晨風惜行色，車騎喧出宿。", "一笑如未忘，新詩寓歸僕。"]'),
('16de7c00-5557-4895-aff2-3197d3401a7a','送劉貢甫貶衡州','劉跂','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭木葉下，衡陽鴻雁飛。',144,'全唐诗/poet.song.60000.json','["洞庭木葉下，衡陽鴻雁飛。", "放舟河之水，歲暮以爲期。", "豈曰無徑路，大直固逶迤。", "波平弭桂棹，風清捲蘭旗。", "紫蟹間丹鯉，霜蓴兼露葵。", "醉歌搴杜若，還以寄相思。", "不厭道里遠，所嗟時序移。", "會登崑崙丘，遂索玄珠遺。", "以茲鼓枻去，瞠若不可追。", "乃知體道人，涉世自有宜。", "入獸不亂羣，安肯陋九夷。", "如何錄錄者，反笑抱關爲。"]'),
('67d1001f-2ad5-4158-8aec-a07e2e14c4cc','次黄完仲見寄韵','劉跂','宋','宋诗','song-poetry','','[]','讀書老無味，記一輒忘十。',264,'全唐诗/poet.song.60000.json','["讀書老無味，記一輒忘十。", "視昔那得超，但覺有不及。", "誰能求甚解，拘窘被書縶。", "爲文亦爾爾，造語須易給。", "未足解客嘲，况復令鬼泣。", "柴門一鵲噪，童稚迎信入。", "開緘故人書，快閱驚喜集。", "新詩瑩病目，儼若冰玉立。", "才兼劉柳健，思鄙郊島澀。", "定從西山來，爽氣扶岌嶪。", "惠然遠見屬，疑我故閑習。", "叢臺三晉舊，鎮靜無警急。", "府寬郎幕尊，森衛走呼吸。", "以茲書檄省，頻歲息篇什。", "神交庶暫對，怳不閡川隰。", "盧溪白士藪，野處分屣笠。", "如聞趣歸裝，早作下車揖。", "吾廬雖庳陋，雅亦便樵汲。", "無酒或過雄，有酒誰饋伋。", "何時甲乙第，版築見君葺。", "比鄰或借倩，梨棗亦得拾。", "不恥共禿翁，相携走城邑。"]'),
('bfb0d708-4f50-4294-8f5a-f8d9c62ad283','次孫元中至後五日遊蔡氏園韵','劉跂','宋','宋诗','song-poetry','','[]','林深宜夏炎，亦復便冬冷。',132,'全唐诗/poet.song.60000.json','["林深宜夏炎，亦復便冬冷。", "居然安穩處，合是招提境。", "晴烟起屋脊，煦日下天井。", "飽飯策杖出，如行贊公嶺。", "平生一丘壑，快眼春睡醒。", "誰言城市喧，能比郊原靜。", "人間會合少，萬事等泡影。", "適意不自取，兀立真土梗。", "時平日月好，歲熟羈旅幸。", "逢人但懽喜，得酒便酩酊。", "知我非子誰，頻來不須請。"]'),
('79143425-b0c9-4a51-a2e6-d922b872203f','費家風次韵二首  其一','劉跂','宋','宋诗','song-poetry','','[]','行年病肺熱，當暑極燔炮。',120,'全唐诗/poet.song.60000.json','["行年病肺熱，當暑極燔炮。", "宵分偶小息，起步駐凉飈。", "咄此怪事發，天北起喧囂。", "扶搖駕霹靂，萬竅爭怒號。", "雙耳不及掩，對語何由交。", "木作蔴葦拔，瓦如埃𡏖飄。", "顛呶怖欲死，一一驚兒曹。", "所憂吾其魚，遑賦屋上茅。", "須臾事亦定，骨肉相勤勞。", "東方漸杲杲，音響爲誰銷。"]'),
('28923a75-2dc5-41b6-b402-01a05499a2ee','費家風次韵二首  其二','劉跂','宋','宋诗','song-poetry','','[]','風雷助神物，茲理古不空。',120,'全唐诗/poet.song.60000.json','["風雷助神物，茲理古不空。", "邂逅一夕事，知有費家風。", "洛橋誦書女，涇川牧羊童。", "不知費氏子，業力與誰同。", "便能役蜚廉，頗復鼓豐隆。", "坐令城郭人，在爾動用中。", "劍出延平水，竹化葛陂翁。", "况爾得人趣，變現豈易窮。", "時時要雨澤，袢暑殊未終。", "勿逢金翅王，非爾能長雄。"]'),
('2709fdea-262f-42e5-b163-a7d7705c6aba','子和惠貺佳什惇敘世契誦詠感慨情見乎辭因次其韵','劉跂','宋','宋诗','song-poetry','','[]','恭聞裕陵初，文物萬古先。',288,'全唐诗/poet.song.60000.json','["恭聞裕陵初，文物萬古先。", "仁英所造士，臺閣徧招延。", "堂堂丹陽公，發軔自賓筵。", "維我先大夫，整駕亦周旋。", "一時起接武，千里稱比肩。", "俱陳曲臺議，共校天祿編。", "心期久相契，燥濕無改弦。", "晚登廊廟席，玉筍照華顛。", "廐馬並飛蓋，齋榻連脩椽。", "到今啟事帖，尺牘餘藤牋。", "憶我既冠後，羣趨集英前。", "公持柱史橐，水鏡資平銓。", "謂宜掇上第，擊節稱奏篇。", "聲名竟寂寂，感遇空拳拳。", "事過劇脫兔，邇來三十年。", "翰墨恍未落，拱水森已圓。", "嗟哉最孤露，罪戾深益纏。", "迷途雖云指，頑質何由鎸。", "以茲衆惡歸，白首猶迍邅。", "屢驚流夜郎，敢望尉通泉。", "弦腸恐齊斷，身璧欲俱捐。", "豈知巢傾覆，胎卵却復全。", "聖主日方中，照曜無黨偏。", "宸筆下霄漢，一洗空宿愆。"]'),
('2318ec71-3331-435f-b130-89faa6cb1a8e','秋夜次四姪韵五首  其一','劉跂','宋','宋诗','song-poetry','','[]','凉颸起天末，倏已掃庭戶。',48,'全唐诗/poet.song.60000.json','["凉颸起天末，倏已掃庭戶。", "光鮮向時柳，慘淡非其故。", "鉛華不足恃，美人抱幽素。", "窮吾分當爾，不爲讀書誤。"]'),
('6703ca5f-0b12-4398-a09a-9b259f6ae125','秋夜次四姪韵五首  其二','劉跂','宋','宋诗','song-poetry','','[]','行樂北山路，綿力涉逶迤。',48,'全唐诗/poet.song.60000.json','["行樂北山路，綿力涉逶迤。", "諸郎騁逸足，掩冉去莫羈。", "歸坐獨兀兀，糜粥聊自資。", "狂瀾成止水，吾病真吾師。"]'),
('81a24ee9-8fee-48fe-b282-e4135bbdc7e7','秋夜次四姪韵五首  其三','劉跂','宋','宋诗','song-poetry','','[]','顥氣日且肅，鳴弦此其時。',48,'全唐诗/poet.song.60000.json','["顥氣日且肅，鳴弦此其時。", "泠泠矢古音，慷慨不勝悲。", "翔飈媚百卉，苦雨何紛披。", "曲罷自澄寂，霜氣皎冰姿。"]'),
('99363d26-bded-402d-a4d1-2d72ab6b5c4f','秋夜次四姪韵五首  其四','劉跂','宋','宋诗','song-poetry','','[]','千古柴桑翁，于酒頗能全。',48,'全唐诗/poet.song.60000.json','["千古柴桑翁，于酒頗能全。", "絕知閒居樂，雅乏從事賢。", "傾心禱王母，更欲丐長年。", "緬思東籬下，想望故悠然。"]'),
('db06b182-6c88-48f1-a6f0-639e43139356','秋夜次四姪韵五首  其五','劉跂','宋','宋诗','song-poetry','','[]','窮簷詎云陋，霜月粲孤明。',48,'全唐诗/poet.song.60000.json','["窮簷詎云陋，霜月粲孤明。", "空山值饑虛，秋菊餐落英。", "吾衰抱沈瘵，玩物得我生。", "循分各有適，天公一何平。"]'),
('b7262bea-ca50-4e53-9166-4dd958b2699b','宿靈泉寺二首  其一','劉跂','宋','宋诗','song-poetry','','[]','石磴排林端，路轉陰嶺滑。',36,'全唐诗/poet.song.60000.json','["石磴排林端，路轉陰嶺滑。", "側身長風外，凜落天爲闊。", "冉冉光風浮，金輪起天末。"]'),
('f4c18c67-5033-4762-adf9-869a681e3ecc','宿靈泉寺二首  其二','劉跂','宋','宋诗','song-poetry','','[]','團團芳桂樹，隠隠巖之幽。',36,'全唐诗/poet.song.60000.json','["團團芳桂樹，隠隠巖之幽。", "敷坐翳其陰，酌彼飛泉流。", "絲桐懷友人，寫我心離憂。"]'),
('468db4d6-b351-41aa-9b1b-63c16f8152d8','滑家橋逢壞舟者有感而作','劉跂','宋','宋诗','song-poetry','','[]','橋傾若車翻，舟破如瓦解。',288,'全唐诗/poet.song.60000.json','["橋傾若車翻，舟破如瓦解。", "二禍適相觸，生此大狼狽。", "齊生海邊人，試吏今得代。", "鄉閭恍在望，舟檝信所快。", "頗知大道夷，不避小物礙。", "撐夫虎豹健，力出馳突外。", "何其一跌傷，脫若葱與蒯。", "疾雷不及聽，生理欻焉壞。", "瓦飛昆陽戰，鶴唳淝水敗。", "身非呂梁叟，沈沒豈不殆。", "嬌兒年十五，八歲又其妹。", "豈伊瞬息間，生死不相頼。", "死者長已矣，生者心破碎。", "泣盡繼以血，耳目坐盲聵。", "哀哀天無情，皦日爲昏憒。", "徐觀水中意，波浪自澎湃。", "我來獨心惻，涕出增感慨。", "頃年岳陽下，憂患亦顛沛。", "豗頹萬死中，血肉偶俱在。", "今此溝澮狹，豈復江湖大。", "咄汝豈不仁，曾獨與禍會。", "冥冥倘有主，焚溺甚葅醢。", "不然遭無辜，神理良汝紿。", "從今十手指，永是後車戒。"]'),
('b7ca0763-70a8-4e00-b5e9-a656ed82216c','宴左山二首  其一','劉跂','宋','宋诗','song-poetry','','[]','閏冬節物晏，十月猶素秋。',72,'全唐诗/poet.song.60000.json','["閏冬節物晏，十月猶素秋。", "招提陽岡路，宛在峴山頭。", "史君有高致，尊酒擅一丘。", "歡顔動長嘯，松菊含春柔。", "風清宿霧斷，地迥行潦收。", "時令將凜落，飛光爲誰留。"]'),
('4c179302-f319-4164-8831-795020925847','宴左山二首  其二','劉跂','宋','宋诗','song-poetry','','[]','行飯轉北岡，如登贊公嶺。',72,'全唐诗/poet.song.60000.json','["行飯轉北岡，如登贊公嶺。", "悠然竟晴日，終比城市永。", "殘霞澹微照，遥林耿疏影。", "天空氣象杳，落落見此境。", "彼哉不自愛，快意烹五鼎。", "來日苦大難，忘言得深領。"]'),
('0afb9e87-0b24-4529-ba3f-d84333ff5ded','題束道輔懷疏亭二首  其一','劉跂','宋','宋诗','song-poetry','','[]','逢時樂宦達，既達貴蚤休。',120,'全唐诗/poet.song.60000.json','["逢時樂宦達，既達貴蚤休。", "東門兩歸客，冉冉不可留。", "大夫名賢後，出處亦俱優。", "築室在何許，南郭林塘幽。", "安車搖佩魚，步屧隨杖鳩。", "勝日至佳客，懽顔終獻酬。", "鄙人最樗散，世用一何繆。", "政以無事身，尊俎常見收。", "令年掃三徑，近不隔虎丘。", "欲問杜陵老，來往幾風流。"]'),
('266f06db-7a9f-4d2c-ae1b-1f22d37e9816','題束道輔懷疏亭二首  其二','劉跂','宋','宋诗','song-poetry','','[]','賢哉疏太傅，遺榮歸印綬。',168,'全唐诗/poet.song.60000.json','["賢哉疏太傅，遺榮歸印綬。", "當時漢廷臣，未省出其右。", "進爲豈不能，止足吾所守。", "驅車曉出關，祖帳已芻狗。", "惟餘清風在，竹帛端不朽。", "大夫懷家聲，相望千年後。", "結廬離城郭，與致寄林藪。", "華髮映童顔，如公殆無有。", "何必松與喬，豈弟神所壽。", "嗟余真漫浪，持是終安取。", "敢言六百石，固已愧升斗。", "行當自免去，執謁隨鄰叟。", "縱復無新詩，猶期飲醇酒。", "但問客如此，亦許登亭否。"]'),
('6d7733eb-dc8f-490d-9c16-061244889387','秋夜自瀘溪泛舟入澤濼二首  其一','劉跂','宋','宋诗','song-poetry','','[]','浮舟入浩渺，有楫任逶遲。',36,'全唐诗/poet.song.60000.json','["浮舟入浩渺，有楫任逶遲。", "望迷烟樹合，影迴星漢移。", "清靜水月界，身到始應知。"]'),
('a14cad13-d51a-4976-8ec3-d37d8693bf75','秋夜自瀘溪泛舟入澤濼二首  其二','劉跂','宋','宋诗','song-poetry','','[]','山橫染黛碧，波散湧金明。',36,'全唐诗/poet.song.60000.json','["山橫染黛碧，波散湧金明。", "風微葭葦靜，露寒魚鳥驚。", "絕境不得到，愁隨歸棹生。"]'),
('6efb3aa9-d1c3-451e-9dc3-4a4fdaa1ec28','舟行懷斯川用王介甫韵','劉跂','宋','宋诗','song-poetry','','[]','遄往欲何之，緩行聊爾爾。',96,'全唐诗/poet.song.60000.json','["遄往欲何之，緩行聊爾爾。", "悟身無期會，在彼猶在此。", "輕舠類短鞍，安取途九軌。", "所嗟湍流長，汩沒未及已。", "蒹葭雁鶩澤，清淺良可喜。", "美人詎云遠，耿耿隔一水。", "憐我抱沈痛，藥劑厭餘滓。", "談笑何時來，幽憂頼湔洗。"]'),
('8199df0b-bd68-4f10-901e-14edd7aa2043','晁端州秀宴席','劉跂','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','同寮貴公子，好事敵原嘗。',120,'全唐诗/poet.song.60000.json','["同寮貴公子，好事敵原嘗。", "晁侯更蕭散，不愛囊中裝。", "步兵玉觥滑，洞庭金丸香。", "宛轉蓴带細，紛綸鱠縷長。", "鰒魚三百飣，豈必河之魴。", "咄嗟事便辦，侍御色不忙。", "熙熙春臺上，醉語各相忘。", "湯餠最後出，雖飽別有腸。", "願君善遇客，懽樂殊未央。", "不須投車轄，敬舉主人觴。"]'),
('d113fedb-bc87-4240-bd32-d548bf983f18','和梁十登三學閣','劉跂','宋','宋诗','song-poetry','','[]','屏居倦煩促，約此塵外遊。',144,'全唐诗/poet.song.60000.json','["屏居倦煩促，約此塵外遊。", "于我快兩目，云誰翻百憂。", "蒼山東北秀，野水西南浮。", "平生林壑心，今老此一丘。", "悲風入叢薄，掃迹瓜芋疇。", "高樹未搖落，鼎鼎彌道周。", "感此節物化，淟涊何當休。", "幻事涉苦海，禪心得中州。", "徙倚到無言，風鈴聲更幽。", "新詩出肺腑，明月非暗投。", "終篇不及酒，似非我一流。", "願爲靈泉去，醉語看橫秋。"]'),
('f5eb0504-c4f7-40a8-abec-0a5519d12251','與諸人步郊外作寄舍弟斯川','劉跂','宋','宋诗','song-poetry','','[]','行年踰六十，衰墮百慮休。',120,'全唐诗/poet.song.60000.json','["行年踰六十，衰墮百慮休。", "新春逢佳日，忽漫思出遊。", "鄰曲四五人，風味成一流。", "步屧相後先，散若水上鷗。", "重城未云遠，乃得此林丘。", "緬懷斜川人，疏野更無儔。", "千載今日歡，政爾聊相酬。", "誰言恨枯槁，茲語當信不。", "阿連最領此，欲語翻離憂。", "寄聲早歸來，二仲須羊求。"]'),
('3a2cd58d-751d-4a2d-9b1d-06dc322e6d2b','夢與舍弟登靈泉步趨如無疾既覺感而賦詩用王介甫韵','劉跂','宋','宋诗','song-poetry','','[]','老夫東歸喜，豈復念西悲。',144,'全唐诗/poet.song.60000.json','["老夫東歸喜，豈復念西悲。", "心安體當佳，抱病如何其。", "欲成蹇士賦，應作半人詩。", "丘園窺不得，溘死恐無時。", "誰令北山夢，彊健變衰遲。", "陟巘石岌岌，班荆草離離。", "季也遮我留，更與道人期。", "夢中差獨樂，不類覺時爲。", "晝夕代乘除，勞逸更共之。", "我豈不有瘳，陰若相扶持。", "福雖未盈眥，自怪盛如茨。", "從今愛吾生，糜粥養蕃滋。"]'),
('cfde73a3-2e46-40ec-a165-4d544e2f56a5','題古器物銘贈得甫兼簡諸友','劉跂','宋','宋诗','song-poetry','','[]','往者李龍眠，監河國城岸。',168,'全唐诗/poet.song.60000.json','["往者李龍眠，監河國城岸。", "家多古時器，羅列供客玩。", "爵觚屢飲我，鼎鬲貯肴膳。", "到今李侯書，一展如對面。", "邇來三十載，復向趙卿見。", "收藏又何富，摹寫粲黄卷。", "沈酣夏商周，餘嗜到兩漢。", "銘識文字祖，曾玄成籀篆。", "頗通蒼雅學，不畏魚魯眩。", "遂將傳琬琰，索我序且讚。", "我衰心力薄，游不出里閈。", "孔懷忘年友，契闊異州縣。", "深慚千里駕，請畢十日燕。", "諸賢共留連，更頼三語掾。"]'),
('59cb4ba1-1386-4e15-875a-cc404afb877c','見蘇黄邦字韵詩戲示王倅安國二首  其一','劉跂','宋','宋诗','song-poetry','','[]','與君南北人，斗粟聚此邦。',120,'全唐诗/poet.song.60000.json','["與君南北人，斗粟聚此邦。", "維彼惡少年，潢池稱下江。", "白晝射大屋，屋破無完窗。", "繡衣募壯士，受馘不受降。", "我弱異都盧，豈敢學尋撞。", "君才過烏獲，九鼎一臂扛。", "懸金八十萬，何啻白璧雙。", "胡不騎赤兔，斫樹收死龐。", "坐寬刺史憂，不復念政厖。", "凱旋夾道迎，父老集瓶缸。"]'),
('d8b6ad57-d98c-48ff-8f2f-63d3d92a035c','見蘇黄邦字韵詩戲示王倅安國二首  其二','劉跂','宋','宋诗','song-poetry','','[]','天下本無事，此語僅興邦。',120,'全唐诗/poet.song.60000.json','["天下本無事，此語僅興邦。", "得志不與物，誓心有如江。", "腐儒若腐螢，槁死讀書窗。", "誰能守筆研，心大云何降。", "終然氣相許，霜鐘不須撞。", "道雖千鈞重，努力期自扛。", "他時僑與札，日月聲名雙。", "秖應南海趙，便是襄陽龐。", "慎毋彊揀擇，貴純不貴厖。", "請見胸中物，止水琉璃缸。"]'),
('9111f04c-4124-4044-bb27-c0a7936432d8','答王允中聖推','劉跂','宋','宋诗','song-poetry','','[]','長安重行樂，寒食及佳辰。',216,'全唐诗/poet.song.60000.json','["長安重行樂，寒食及佳辰。", "聯翩出遊宴，閭巷無居人。", "動靜各有趣，拂我朱絲塵。", "分將幽獨心，守此濩落身。", "斯豈衆所然，獨子何殷勤。", "叩門隨謁入，俯仰色甚真。", "從容一笑粲，不覺傾蓋新。", "念昔各從宦，宿亳爲近鄰。", "溢言相引重，嗟我曾未聞。", "乃知國寶拙，不悟王綏仁。", "高談喜未定，佳句意益珍。", "幾有按劍感，驚怪惠好頻。", "子方赴吏集，朝暮旅食貧。", "不忍拜馬足，會且掃朱門。", "獨肯閒見我，惟子欲何云。", "乃言人生世，取舍理莫均。", "譬之平地水，東西南北分。", "感此重拜嘉，幸子長相親。"]'),
('f29b15d1-40fd-407b-8bb9-4a2e0e1000e7','答王升之','劉跂','宋','宋诗','song-poetry','','[]','去家今來歸，川陸萬里長。',240,'全唐诗/poet.song.60000.json','["去家今來歸，川陸萬里長。", "有官無祿食，生理劇微茫。", "饑創何時瘳，麥隴得扁倉。", "丁稚八九人，我老自裹糧。", "不辭終歲勤，一飽幸見償。", "所願杯椀足，何取玉無當。", "向來無數青，渾作可憐黄。", "想見冰玉姿，膏沐出沸湯。", "誰作不祥語，詛呪甚砭傷。", "妒人神所呵，坐使天雨霶。", "翁媼拜相賀，懽欲插翅翔。", "新詩果來謝，追悔如負芒。", "君惟文字戲，竿木故逢場。", "豈顧狷狹人，爲虐變炎凉。", "且復置是事，釀玉滿君堂。", "垂涎得涓滴，渴夢轉顛狂。", "不嫌餠餌惡，雖賤敢獨嘗。", "交易儻許可，寧復有他腸。", "且毌火我屋，亦未穴君牆。", "乘除各醉飽，前事永相忘。"]'),
('63a740c0-f0b1-4743-ac5b-217eac07337f','作蜂室','劉跂','宋','宋诗','song-poetry','','[]','栽基植甓作蜂室，其陽分孔便出入。',96,'全唐诗/poet.song.60000.json','["栽基植甓作蜂室，其陽分孔便出入。", "懸窠毒螫非爾匹，百卉芳華登股膝。", "孫息蟬聯深洞房，露結膏凝如截肪。", "比功九粒冠百味，削滓猶堪資夜光。", "憐爾于人甚無負，一世分甘身獨苦。", "高崖熏灼彌更難，且復留連小環堵。"]'),
('e7b80956-5ef9-4ccd-bf9c-5426f507441f','寄晁以道','劉跂','宋','宋诗','song-poetry','','[]','江東野老羹蓴絲，弗羨肉山酒爲池。',144,'全唐诗/poet.song.60000.json','["江東野老羹蓴絲，弗羨肉山酒爲池。", "啖我故人吏未歸，脚靴手板方苦饑。", "豈無盤飧置璧圭，我乏是物君非宜。", "近聞示病作居士，不似齊州稱主司。", "歲惡無乃饞所爲，自是不當食肉糜。", "書來中有七字詩，問訊勞苦開人眉。", "墨丸不減官隃麋，著書寂寞來孔時。", "我曹老矣善自持，莫擬狂瘦勝癡肥。", "他鄉異縣久別離，明月千里長相思。"]'),
('9fee62bb-15e7-4e15-a770-a6392a5b3708','送高將永亨','劉跂','宋','宋诗','song-poetry','','[]','大高殺身如伍尚，弟有子胥天未喪。',128,'全唐诗/poet.song.60000.json','["大高殺身如伍尚，弟有子胥天未喪。", "小高自慕顔太師，能言兄守常山時。", "事隨日往長已矣，邂逅相逢識其弟。", "誰言恨不見古人，兩意恐非今人比。", "結髮行陣初齊名，志同不在同生死。", "苦遭文吏巧見詆，邊人至今猶墜淚。", "三年默默趨戎行，驊騮捕鼠非所長。", "趣裝定返雲中守，上書今遇尚書郎。"]'),
('5de30877-14f0-4c3f-83e4-77c995a746ad','次資道韵','劉跂','宋','宋诗','song-poetry','','[]','今我不樂何所爲，調笑盍各言其好。',96,'全唐诗/poet.song.60000.json','["今我不樂何所爲，調笑盍各言其好。", "不願擊水南溟飛，但愛乘風北窗傲。", "大夫聲名過單父，即日去受東朝誥。", "固知爲偶我非齊，莫忘相從君與操。", "駿辯瑰章殆希有，玉堂金馬應須到。", "功成却記雞黍期，同著青鞋映黄帽。"]'),
('ae5771ce-3380-47ff-96c8-d8cc26ef6f49','次韵大人正月十四日作','劉跂','宋','宋诗','song-poetry','','[]','端闈夜許都人望，紅繖亭亭坐南向。',195,'全唐诗/poet.song.60000.json','["端闈夜許都人望，紅繖亭亭坐南向。", "燭龍影落陸海中，廣樂聲在鈞天上。", "華嚴寶藏光景出，雙鸞飛下蓬萊嶂。", "大平天子千萬歲，呼舞共作嵩山唱。", "小臣躑躅百寮底，未許外班陪末行。", "今來淪落一何極，山城裝點成窮相。", "苦吟漫欲酬節物，擁膝句作酸寒狀。", "搜抉渾如餌毒藥，畏縮更似藏私釀。", "詩成竟亦勿交涉，欲取樓蘭經樂浪。", "典衣聊復沽市酒，一飲徑醉成昏忘。", "黄昏陋巷燈火絕，守把不費城門將。", "豈不見人生懽樂易生悲，惟有靜默長無量。"]'),
('f7bf1a71-3e4c-4ce6-a2d8-b48b3c04ab6c','隴上遇雨','劉跂','宋','宋诗','song-poetry','','[]','隴上怕雨竟遇雨，空山路窮避無所。',224,'全唐诗/poet.song.60000.json','["隴上怕雨竟遇雨，空山路窮避無所。", "昆陽之戰飛屋瓦，白登之圍矢交下。", "從者散去馬可憐，故人借我非我馬。", "上坡歷塊已欹側，下坡流滑攢四脚。", "既僨而起倏復顛，墮策失轡心茫然。", "從者好在無自苦，履穿衣敝吾償汝。", "我亦短褐不得完，掛樹一裂長尺五。", "此生辛勤身不辭，七歲嬌女三歲兒。", "泥塗模糊啼午饑，買餠一百汝勿啼。", "滹沱麥飯蕪蔞粥，咄汝豈得長食肉。", "仰天長嘆冠纓絕，下馬納屨踵亦决。", "張儀舌在雖自知，范叔衣寒一何切。", "人生貧賤烏足悲，行吟不顧妻駡隨。", "寄聲公等勿誚我，富貴莫忘牛衣時。"]'),
('26a04d06-26ac-4c5f-9b71-2a721d7bd884','答純益書懷','劉跂','宋','宋诗','song-poetry','','[]','矯矯林間鶴，汎汎水際鷗。',168,'全唐诗/poet.song.60000.json','["矯矯林間鶴，汎汎水際鷗。", "俱非鼎俎用，斗粟誰爲留。", "君師蔡義我施讎，同時聲名今白頭。", "博士弟子動千數，遑記軍中陳與劉。", "黄金絡馬錦臂鞲，印組丈二鳴八騶。", "席間設胾竟何味，車上負芒終可憂。", "人生在世各有趣，江東且復客曹丘。", "田橫刎頸亦義事，感知捐軀非所羞。", "此心會與君意合，今無古人何處求。", "不如置之酌美酒，同郡諸公皆舊遊。", "耳熱眼花付一醉，雞蟲蚌鷸何時休。"]'),
('f5b62425-e1a7-43d8-ad69-10b1492efd7c','重答','劉跂','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','君文有如太史遷，多至萬字少千言。',128,'全唐诗/poet.song.60000.json','["君文有如太史遷，多至萬字少千言。", "小詩未足見馳騁，要當著書名雋永。", "詞源一深幾千丈，苦恨舉世無長綆。", "少時白眼視嚴徐，老傍君門冉冉趨。", "聲價若許金滿斗，倦游銷減一毫無。", "雖貧終非兒女態，倔强時時編虎鬚。", "食貧我亦懷抱惡，泰山不毛秋濯濯。", "糜乾黍空酒味薄，饑死不學東方朔。"]'),
('ea96f962-25e9-4424-9bcd-4fae6b50bc45','以郿絛贈晁掾','劉跂','宋','宋诗','song-poetry','','[]','握手喜相逢，何以贈契闊。',108,'全唐诗/poet.song.60000.json','["握手喜相逢，何以贈契闊。", "解我郿縣墨絲絛，繫君南海穀皮褐。", "結君歡愛君勿忘，祝君玄髮如許長。", "带圍莫作沈家令，腰腹須稱東平王。", "秖憂道人骨相發，王塗駸駸弦上筈。", "金璽盭綬丙丁文，魚鬚寶笏搢錦紳。", "此時此絛亦相尚，參禪問道裴丞相。"]'),
('70eb4f68-3051-457e-9352-ad61d23f63c6','碾茶','劉跂','宋','宋诗','song-poetry','','[]','玉川涕泣訟月蝕，蟾蜍無光玳瑁魄。',112,'全唐诗/poet.song.60000.json','["玉川涕泣訟月蝕，蟾蜍無光玳瑁魄。", "委照墨海鸚鵒石，恐是雲龍小蒼璧。", "我家得之天人家，天家金盤薦玉食。", "豈堪書生漱糠覈，床頭什襲封未拆。", "不辭屑玉遺君飲，要君錦繡生肝膈。", "意中佳句甚了了，口不能道空脈脈。", "諸公椽筆好相過，莫道彭城譏水厄。"]'),
('0d420438-1dfc-46c7-8312-5719383b0daf','寄人','劉跂','宋','宋诗','song-poetry','','[]','聞道江家宅，椒蘭春自榮。',48,'全唐诗/poet.song.60000.json','["聞道江家宅，椒蘭春自榮。", "道人今好在，歸馬太遲生。", "飛鳥山南路，浮雲隴上城。", "相看各多病，搗藥待君烹。"]'),
('6d6975e3-0fc9-4136-b16f-516d062a8331','送成都漕','劉跂','宋','宋诗','song-poetry','','[]','里巷居偏近，生平月亦同。',48,'全唐诗/poet.song.60000.json','["里巷居偏近，生平月亦同。", "開懷一笑語，轉首兩西東。", "共是塵勞內，全輸吏隠中。", "魚來勤尺素，淮汴古來通。"]'),
('ebef7563-4bb5-4091-a1ce-168270eea460','送東之','劉跂','宋','宋诗','song-poetry','','[]','受業師高第，居官郡右曹。',48,'全唐诗/poet.song.60000.json','["受業師高第，居官郡右曹。", "掾非蠻語得，才有鶚書褒。", "會是人難及，胡然力獨勞。", "府趨空冉冉，誰得呂虔刀。"]'),
('2ba0e7ea-9691-4c9f-ba90-68e974a15210','送王升之','劉跂','宋','宋诗','song-poetry','','[]','翩翩捧檄喜，便作放舟行。',48,'全唐诗/poet.song.60000.json','["翩翩捧檄喜，便作放舟行。", "愛客懷抱好，能詩膚骨清。", "蹇余身濩落，況此歲崢嶸。", "自是愁成醉，離觴不復傾。"]'),
('c894bb62-655f-493f-abc5-c9125cc4cf3f','諸公見過野飯晚步輔之有詩因次其韵','劉跂','宋','宋诗','song-poetry','','[]','野人城下住，巷底更誰鄰。',48,'全唐诗/poet.song.60000.json','["野人城下住，巷底更誰鄰。", "秖有携筇路，應無躍馬塵。", "客非俗士駕，詩似古人淳。", "載酒催公等，藜羹難重陳。"]'),
('8b82ad39-b43c-49ea-8c0f-6b70a2bcb7c1','西溪次韵九首  其一','劉跂','宋','宋诗','song-poetry','','[]','終年倦城郭，夢入水雲鄉。',48,'全唐诗/poet.song.60000.json','["終年倦城郭，夢入水雲鄉。", "酒美俱中聖，詩成獨擅場。", "高風助悲壯，皎月照清狂。", "露下如鉛水，沾衣笑淚浪。"]'),
('3066979f-c78d-42ff-a82f-f0b361d5201c','西溪次韵九首  其二','劉跂','宋','宋诗','song-poetry','','[]','携手西溪陌，懽顔共舉觴。',48,'全唐诗/poet.song.60000.json','["携手西溪陌，懽顔共舉觴。", "雲山滿目靜，風月一襟凉。", "但得杯中玉，那知鬢後霜。", "何妨擊尊破，故作聽歌長。"]'),
('2673066d-bd59-40e0-984a-bb05c5e39e7d','西溪次韵九首  其三','劉跂','宋','宋诗','song-poetry','','[]','英英數君子，貧甚亦清門。',48,'全唐诗/poet.song.60000.json','["英英數君子，貧甚亦清門。", "蕭散俱相好，疏慵每見原。", "玄談得涇渭，芳意有蘭蓀。", "從此窺名理，金篦刮眼昏。"]'),
('6e81dcb7-2494-497b-8599-da37f7f401b8','西溪次韵九首  其四','劉跂','宋','宋诗','song-poetry','','[]','漁人一竿老，麤糲半饑虛。',48,'全唐诗/poet.song.60000.json','["漁人一竿老，麤糲半饑虛。", "豈有令鉤直，惟應恨網疏。", "有時脚不襪，自笑食無魚。", "我自餘尊在，愁眉爾暫舒。"]'),
('5d1e8a85-63b3-4b3f-b506-9a08ea361b63','西溪次韵九首  其五','劉跂','宋','宋诗','song-poetry','','[]','秋風漲川谷，小汊亦容舠。',48,'全唐诗/poet.song.60000.json','["秋風漲川谷，小汊亦容舠。", "落照收長纜，隨流試短篙。", "隔溪聞鼓枻，臨海試觀濤。", "解賦南州浦，前身何水曹。"]'),
('f87624b0-34d3-4718-9f34-94a3bd1b1033','西溪次韵九首  其六','劉跂','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭明月下，天地一冰壺。',48,'全唐诗/poet.song.60000.json','["洞庭明月下，天地一冰壺。", "怳對瑶池雪，驚逢甓社珠。", "窮鄉悲百粵，勝槩憶三吳。", "誰作稽山伴，秋風入鏡湖。"]'),
('4776829e-e56b-4057-b35b-049e62d0f163','西溪次韵九首  其七','劉跂','宋','宋诗','song-poetry','','[]','輕雲巧迎月，高柳媚疏光。',48,'全唐诗/poet.song.60000.json','["輕雲巧迎月，高柳媚疏光。", "城堞傳嚴鼓，尊罍動急觴。", "望迷山四面，影占水中央。", "清絕無人地，居然五友鄉。"]'),
('2eff2983-d1de-4ab9-96fb-8b0ef4a97404','西溪次韵九首  其八','劉跂','宋','宋诗','song-poetry','','[]','幽人若幽鳥，適意但卑飛。',48,'全唐诗/poet.song.60000.json','["幽人若幽鳥，適意但卑飛。", "宦拙羞潘岳，才多笑陸機。", "不堪屍馬革，幸未泣牛衣。", "來往瀘溪上，鄰翁有釣磯。"]'),
('f2d24da6-f3e5-4cd9-bbb9-3458f2148f15','西溪次韵九首  其九','劉跂','宋','宋诗','song-poetry','','[]','柯亭三弄笛，憀栗易悲風。',48,'全唐诗/poet.song.60000.json','["柯亭三弄笛，憀栗易悲風。", "妙曲來天上，飛花落酒中。", "翠屏虛在望，玉鏡迥當空。", "摹寫何人解，王維老畫工。"]'),
('7a9ac666-ddb4-4c8c-b1e6-d6ba11d50f65','次畢將叔韵寄壽陽三首  其一','劉跂','宋','宋诗','song-poetry','','[]','撫枕得滂湃，開軒延翠微。',48,'全唐诗/poet.song.60000.json','["撫枕得滂湃，開軒延翠微。", "乃翁故時客，何許更言歸。", "有興添書滴，無心傍釣磯。", "惟應一大事，策杖到禪扉。"]'),
('67888377-07d1-420d-99ef-2855e47ebec7','次畢將叔韵寄壽陽三首  其二','劉跂','宋','宋诗','song-poetry','','[]','苦竹湓江宅，黄山秋浦亭。',48,'全唐诗/poet.song.60000.json','["苦竹湓江宅，黄山秋浦亭。", "猿聲作頭白，客淚對衫青。", "笑爾悲鳬脛，知吾寄水萍。", "時時頼嚴尹，小隊出郊坰。"]'),
('8cf163dc-2fa9-446d-b1ba-7fe96b26dc0d','次畢將叔韵寄壽陽三首  其三','劉跂','宋','宋诗','song-poetry','','[]','丈人文力健，能事與心違。',48,'全唐诗/poet.song.60000.json','["丈人文力健，能事與心違。", "彭澤秔田少，襄陽菰菜肥。", "紫團生雪液，蒼餠破雲衣。", "持許無人寄，殷勤小陟歸。"]'),
('ffef5ae6-ff93-4b37-a1e1-7d574cdfbdda','題張氏園亭二首  其一','劉跂','宋','宋诗','song-poetry','','[]','蒼頭奉筇竹，稚子試春衫。',48,'全唐诗/poet.song.60000.json','["蒼頭奉筇竹，稚子試春衫。", "共著野人服，來遊居士巖。", "園蔬佐酒椀，藥錄貯書函。", "草草非難得，從今不計凡。"]'),
('dbf7ff4b-99ee-47c8-9f52-63f4f612c58a','題張氏園亭二首  其二','劉跂','宋','宋诗','song-poetry','','[]','岸薺隨漁屨，林桃映舞衫。',48,'全唐诗/poet.song.60000.json','["岸薺隨漁屨，林桃映舞衫。", "定非銅雀榭，似是雨花巖。", "僮有家千指，書多日百函。", "斯人太高語，吾意秖塵凡。"]'),
('35589cd6-1647-44d9-adac-ef8022d833ad','與李深梁山泊分韵得輕風生浪遲五首  其一','劉跂','宋','宋诗','song-poetry','','[]','大澤水常滿，秋來洲渚平。',48,'全唐诗/poet.song.60000.json','["大澤水常滿，秋來洲渚平。", "游鱗不能渡，短棹若爲行。", "氣吐西江蜃，風摶北海鵬。", "波濤未可料，汩沒恐身輕。"]'),
('c0354d46-22a6-48df-bdc1-7a317c3bd802','與李深梁山泊分韵得輕風生浪遲五首  其二','劉跂','宋','宋诗','song-poetry','','[]','從今魚易得，居與水相通。',48,'全唐诗/poet.song.60000.json','["從今魚易得，居與水相通。", "世事青天外，生涯高浪中。", "蒲深疑落日，萍轉覺回風。", "勸爾終身計，鴟夷是范公。"]'),
('ea06263a-50c4-4348-a55c-db1583611a20','與李深梁山泊分韵得輕風生浪遲五首  其三','劉跂','宋','宋诗','song-poetry','','[]','爲問風多逆，舟行太緩生。',48,'全唐诗/poet.song.60000.json','["爲問風多逆，舟行太緩生。", "漁歌不用調，水宿莫論程。", "飽有雕胡飯，香無錦带羹。", "相看乏酒飲，愁劇似淵明。"]'),
('fa208258-4085-4e84-8041-8067405d4341','與李深梁山泊分韵得輕風生浪遲五首  其四','劉跂','宋','宋诗','song-poetry','','[]','莊生語逍遥，元子稱漫浪。',48,'全唐诗/poet.song.60000.json','["莊生語逍遥，元子稱漫浪。", "此身如土梗，雕刻不成樣。", "何心解賓戲，猶欲避官謗。", "默默難具論，幽愁浩盈望。"]'),
('b84d84f4-ea6b-49dc-bdef-812775670a56','與李深梁山泊分韵得輕風生浪遲五首  其五','劉跂','宋','宋诗','song-poetry','','[]','丹鳳不出世，整翮上林枝。',48,'全唐诗/poet.song.60000.json','["丹鳳不出世，整翮上林枝。", "黄鵠非所擬，翔集偶爲期。", "風高不易到，歲晏仍苦饑。", "扶持幸有托，敢厭路逶遲。"]'),
('f10e99b7-ba76-4264-b690-bb4192f0393c','舟中二首  其一','劉跂','宋','宋诗','song-poetry','','[]','野水今年長，青田入白湖。',48,'全唐诗/poet.song.60000.json','["野水今年長，青田入白湖。", "鄉音聞驛馬，風力驗檣烏。", "永夜眠雖著，高秋病未蘇。", "常憂北山拜，辛苦倩人扶。"]'),
('a81bae55-fe45-419b-9950-6ed228aa2cbd','舟中二首  其二','劉跂','宋','宋诗','song-poetry','','[]','故國風烟外，飄零隔歲淹。',48,'全唐诗/poet.song.60000.json','["故國風烟外，飄零隔歲淹。", "今茲去拘窘，行復見安恬。", "未擬親酒盞，何當疏藥奩。", "酬恩無處所，香火供瞿聃。"]'),
('67790654-f1ee-47ad-994d-3b10a3abfe67','使遼作十四首  其一','劉跂','宋','宋诗','song-poetry','','[]','自昔和戎便，於今出使光。',48,'全唐诗/poet.song.60000.json','["自昔和戎便，於今出使光。", "胡星宵不見，漢節歲相望。", "州邑三餐返，溝封一葦航。", "太平無險固，道德是金湯。"]'),
('5f0765db-3dc4-4a8d-9d6d-b0a4caaf2243','使遼作十四首  其二','劉跂','宋','宋诗','song-poetry','','[]','虎北奚南迥，居然带礪全。',48,'全唐诗/poet.song.60000.json','["虎北奚南迥，居然带礪全。", "百尋天上樹，千里掌中川。", "毳幕宜逃漢，山戎莫病燕。", "即今甌脫地，渾占兩河田。"]'),
('ce2057a6-f7e0-4f74-a54f-720e698595c7','使遼作十四首  其三','劉跂','宋','宋诗','song-poetry','','[]','禮爲王人重，關亭道路除。',48,'全唐诗/poet.song.60000.json','["禮爲王人重，關亭道路除。", "荒城初部落，名鎮古巫閭。", "習俗便乘馬，生男薄負鋤。", "傳聞斷腕地，歲歲作樓居。"]'),
('66f444b0-5663-4412-b06b-ea17bf2e3070','使遼作十四首  其四','劉跂','宋','宋诗','song-poetry','','[]','但逐銀牌使，何堪記驛程。',48,'全唐诗/poet.song.60000.json','["但逐銀牌使，何堪記驛程。", "路迷如欲盡，山轉忽通行。", "列仗新羅騎，先驅渤海兵。", "鑿空誰計此，曾未及長纓。"]'),
('9ff7fea0-728d-4b16-b16b-b39fde66f6df','使遼作十四首  其五','劉跂','宋','宋诗','song-poetry','','[]','寒日川原暗，顛風草木昏。',48,'全唐诗/poet.song.60000.json','["寒日川原暗，顛風草木昏。", "捉襟愁肘見，語客畏聲吞。", "曠蕩疑人少，倉皇覺馬奔。", "勿驚銷髀肉，長遣節旄存。"]'),
('9ef19459-0a38-463d-85b5-aebe5d4bd65f','使遼作十四首  其六','劉跂','宋','宋诗','song-poetry','','[]','神水堅冰合，沙場寸草無。',48,'全唐诗/poet.song.60000.json','["神水堅冰合，沙場寸草無。", "長疑淚是血，誤喜唾成珠。", "晝出驚貂鼠，宵鳴厭訓狐。", "悲歌人不應，自覺寸心孤。"]'),
('009a65bb-270c-42e8-8e6d-2cc28a6caa45','使遼作十四首  其七','劉跂','宋','宋诗','song-poetry','','[]','北嶺能捫斗，南岡欲摘星。',48,'全唐诗/poet.song.60000.json','["北嶺能捫斗，南岡欲摘星。", "舊聞空耳滿，異域得身經。", "好築嫖姚塚，仍刊車騎銘。", "莫言天作限，關路有松亭。"]'),
('734f1bd5-7ae7-4da1-89e3-277ec77cbba0','使遼作十四首  其八','劉跂','宋','宋诗','song-poetry','','[]','鼓角霜初曉，簫笳日欲曛。',48,'全唐诗/poet.song.60000.json','["鼓角霜初曉，簫笳日欲曛。", "莫爲天外意，只作夢中聞。", "問道無人迹，嘶風有馬羣。", "山高飛鳥急，决眥入層雲。"]'),
('2cbb922e-e114-4f2a-955a-277b8b7adef7','使遼作十四首  其九','劉跂','宋','宋诗','song-poetry','','[]','一作重山去，頻看破鏡飛。',48,'全唐诗/poet.song.60000.json','["一作重山去，頻看破鏡飛。", "長悲青塚怨，莫忘白登圍。", "禮覺周旋異，心知笑語非。", "南飛何處鳥，安得與俱歸。"]'),
('358bf09d-ae68-4e8d-9dd1-6bbb7808dfdf','使遼作十四首  其一○','劉跂','宋','宋诗','song-poetry','','[]','喜鬭人皆勇，誅求俗故貪。',48,'全唐诗/poet.song.60000.json','["喜鬭人皆勇，誅求俗故貪。", "爲謀不耐暑，嗜味獨便鹽。", "已怪今生到，寧能一夕淹。", "長安遠如日，北斗望爲南。"]'),
('cd94e496-4f65-4eaf-a58b-8c374ee35d18','使遼作十四首  其一一','劉跂','宋','宋诗','song-poetry','','[]','今日朝元仗，千官兩掖門。',48,'全唐诗/poet.song.60000.json','["今日朝元仗，千官兩掖門。", "從容魚藻宴，供奉栢梁尊。", "厭服貂裘敝，愁看桂酒溫。", "誰知廣文淀，水面箔爲藩。"]'),
('32f627ad-e5fb-45db-aa3c-650b7d6cebab','使遼作十四首  其一二','劉跂','宋','宋诗','song-poetry','','[]','置酒穹廬曉，僧山合管弦。',48,'全唐诗/poet.song.60000.json','["置酒穹廬曉，僧山合管弦。", "應緣地褊小，難遣舞回旋。", "風急皮毛重，霜清湩酪羶。", "君看東嚮坐，貴重盡童顛。"]'),
('3029bb91-2092-4d62-a646-88bd81f4ebea','使遼作十四首  其一三','劉跂','宋','宋诗','song-poetry','','[]','王春今日是，虜曆自相忘。',48,'全唐诗/poet.song.60000.json','["王春今日是，虜曆自相忘。", "厭食乾羊味，如聞生菜香。", "隴梅渾破臘，燕雁正隨陽。", "時節催歸興，憑陵天際翔。"]'),
('b62b38ea-2847-4fac-a957-a7dba2e5c2ac','使遼作十四首  其一四','劉跂','宋','宋诗','song-poetry','','[]','日覺筋骸耗，中宵慘未寧。',48,'全唐诗/poet.song.60000.json','["日覺筋骸耗，中宵慘未寧。", "厭看山濯濯，快見栢青青。", "記里無官堠，更衣有短亭。", "心驚此何地，生死一流萍。"]'),
('62afcdf3-12df-4fc9-a030-5789eab4c8d2','病中','劉跂','宋','宋诗','song-poetry','','[]','病如漳浦卧，一腹果然浮。',48,'全唐诗/poet.song.60000.json','["病如漳浦卧，一腹果然浮。", "不著三升飯，能容萬斛愁。", "水聲回別浦，山影到中流。", "遣興須憑酒，殷勤爲汝留。"]'),
('72662234-ea0f-4963-9f64-088ba43fdf61','曹紘陷交阯十七年與其母逃歸得官汶上求詩','劉跂','宋','宋诗','song-poetry','','[]','曹侯將家子，異域久飄颻。',48,'全唐诗/poet.song.60000.json','["曹侯將家子，異域久飄颻。", "人獨憂羝乳，天方借海橋。", "亡弓終在楚，去鶴會歸遼。", "凜凜今如許，風霜看後凋。"]'),
('4e0258b3-f112-4ade-bdd2-4b323cd03458','答景亮二首  其一','劉跂','宋','宋诗','song-poetry','','[]','門無車馬迹，卧榻兩閒人。',48,'全唐诗/poet.song.60000.json','["門無車馬迹，卧榻兩閒人。", "野服風前薄，園蔬雨後新。", "絲桐叔夜操，香火浄名真。", "斜日穿簷入，悠悠對隙塵。"]'),
('65602fd9-4272-4a0a-88f1-c3f9daef7c30','答景亮二首  其二','劉跂','宋','宋诗','song-poetry','','[]','吾廬亦自愛，況屬仲春中。',48,'全唐诗/poet.song.60000.json','["吾廬亦自愛，況屬仲春中。", "賓榻疏簾隔，鄰園小徑通。", "何妨書袠亂，未遽酒尊空。", "更約高人過，當軒看偃松。"]'),
('29bb602d-1a32-49eb-a5ab-b2febd6ea439','七夕','劉跂','宋','宋诗','song-poetry','','[]','夜永風露下，庭空簾幕秋。',48,'全唐诗/poet.song.60000.json','["夜永風露下，庭空簾幕秋。", "盃盤延素魄，針縷動雙眸。", "天上秖今夕，人間寧少留。", "如何一水際，歲歲此相求。"]'),
('d794bfe5-9643-4792-ba6c-4e33fc112b38','寄贈','劉跂','宋','宋诗','song-poetry','','[]','絕世丹青業，中臺雨露辰。',264,'全唐诗/poet.song.60000.json','["絕世丹青業，中臺雨露辰。", "師門推上第，王室見名臣。", "磊落儒林丈，風流畫省賓。", "燕朝分錦仗，儤值近楓宸。", "鳴鳳丹山穴，占星潁水濱。", "殿廬俄厭直，藩社此班春。", "山節還銅虎，京符換玉麟。", "威行三輔地，歌浹兩川民。", "已喜徵黄霸，無勞借寇恂。", "即應公簡上，會見俗還淳。", "歎昔時難偶，逢今勢莫均。", "楚材難入晉，漢法近沿秦。", "稽古皆前列，希風絕後塵。", "斯文如汩沒，吾道久湮淪。", "海嶽功歸聖，熊羆釣有人。", "藍田仍産玉，郢匠早揮斤。", "周曆方開永，蕭規欲盡循。", "天時知會遇，人力漫紛綸。", "夙有摻弦便，今逢斂板親。", "猥慚牛下走，敢玷席中珍。", "迹遠龍門峻，心懷燕厦仁。", "緒言聞已舊，從此更書紳。"]'),
('27e7800c-5161-4613-8e2e-021cbd3c3d4f','答資道','劉跂','宋','宋诗','song-poetry','','[]','都尉聲名後，篇章不乏才。',120,'全唐诗/poet.song.60000.json','["都尉聲名後，篇章不乏才。", "談高正始際，詩自建安來。", "險怪探龍頷，甘珍味豹胎。", "陰何長有思，郊島漫相猜。", "白雪憑誰聽，黄花入衆咍。", "楚醒搴水薜，蜀興動官梅。", "晚艇翩翩鳥，秋濤隠隠雷。", "水兼天浩蕩，山爲日崔嵬。", "麗藻煩三復，愁腸殆九回。", "自慚無世用，莊語笑迂駘。"]'),
('81113e5e-dcaa-461f-90c8-048e55ce98a8','七夕戲效西崑體','劉跂','宋','宋诗','song-poetry','','[]','終年情脈脈，此夕夜遲遲。',72,'全唐诗/poet.song.60000.json','["終年情脈脈，此夕夜遲遲。", "玉宇秋來闊，珠簾夜後宜。", "仙娥月爲姊，海實樹生兒。", "露共雲車下，風將鵲扇移。", "鮫盤空有淚，椽筆未成詩。", "借取揮戈便，金釭更百枝。"]'),
('bd702548-a480-47ef-9ed8-b48bd855ef3d','寄葉勤次其韵','劉跂','宋','宋诗','song-poetry','','[]','五斗折腰俱爲貧，詩書律令若爲分。',64,'全唐诗/poet.song.60000.json','["五斗折腰俱爲貧，詩書律令若爲分。", "西山今朝有爽氣，北闕無時飛白雲。", "一紙綢繆三歲字，七言憀慄九章文。", "故人好在長相憶，悵望江皋麋鹿羣。"]'),
('4053174e-a713-4623-9304-b8f78c588437','送趙侯思恭','劉跂','宋','宋诗','song-poetry','','[]','西城冠蓋日初曛，南浦笙歌夜嚮晨。',64,'全唐诗/poet.song.60000.json','["西城冠蓋日初曛，南浦笙歌夜嚮晨。", "何許烟波千頃隔，爾來霜月一鉤新。", "名花只許平泉有，開讌誰如北海頻。", "我亦尊前舊時客，獨將衰白卧漳濱。"]'),
('69fca0ac-f494-4bb3-b089-be7a6560dbf7','用公允韵送介叔東歸','劉跂','宋','宋诗','song-poetry','','[]','曾曳長裾何處門，楚聲悲壯不堪聞。',64,'全唐诗/poet.song.60000.json','["曾曳長裾何處門，楚聲悲壯不堪聞。", "侵陵急景東都雪，觸忤新愁南浦雲。", "未信書生歌嶽嶽，要令天子禪云云。", "少年持許今安在，拭目翱翔鴛鷺羣。"]'),
('00d6e6a6-9c9f-416c-b45f-52c002dff425','次王彥昭寄蘇景謨青社園亭韵二首  其一','劉跂','宋','宋诗','song-poetry','','[]','丞掾分曹付舊規，翩翩文彩妙當時。',64,'全唐诗/poet.song.60000.json','["丞掾分曹付舊規，翩翩文彩妙當時。", "何人誤讀雌霓賦，他日真成幼婦碑。", "曲水流觴如故事，平山行樂有新詩。", "春來想見棠陰盛，可但詩人別後思。"]'),
('8332a448-e8de-4470-874e-f9a49c9daf56','次王彥昭寄蘇景謨青社園亭韵二首  其二','劉跂','宋','宋诗','song-poetry','','[]','誰道前賢迹已塵，園林氣象邇來新。',64,'全唐诗/poet.song.60000.json','["誰道前賢迹已塵，園林氣象邇來新。", "高山流水有深意，翠竹黄花如故人。", "小隊郊坰時訪客，後堂歌吹獨留賓。", "汶陽寂寞無佳賞，卧閣蕭然過一春。"]'),
('c3ae1479-28f6-4fa1-9288-94d0e56eab66','涵輝閣次韵','劉跂','宋','宋诗','song-poetry','','[]','光風冉冉動平湖，花草幽香滿坐隅。',64,'全唐诗/poet.song.60000.json','["光風冉冉動平湖，花草幽香滿坐隅。", "薰暖頗如懽伯在，蕭閒宜與此君俱。", "可無剡水乘舟興，端是郊居作賦圖。", "借與禪翁有幽事，一支筇竹倚圓蒲。"]'),
('59d6fc67-ab64-4802-bdf3-19af8af2cd79','行次長風沙次韵','劉跂','宋','宋诗','song-poetry','','[]','清晨喜氣動江流，兩見新篇到小舟。',64,'全唐诗/poet.song.60000.json','["清晨喜氣動江流，兩見新篇到小舟。", "石裂崖頹非快意，風聲鶴唳亦消憂。", "已令雙鯉隨梅使，更不飛烏倚柁樓。", "興味從今得嘉境，著書應不號窮愁。"]'),
('0bbbd4c9-cc8e-4206-ac6e-963000f5a2f9','遊白雲山次韵二首  其一','劉跂','宋','宋诗','song-poetry','','[]','不到山中寧久如，兩日闕然或闊疏。',64,'全唐诗/poet.song.60000.json','["不到山中寧久如，兩日闕然或闊疏。", "每憐身留只意往，何事子行令我居。", "莫向山僧疑入定，但從溪友試觀漁。", "朝來新作幾兩屐，更待西原春雨餘。"]'),
('218b0cb9-25fd-49d1-b27d-2a85c33c153d','遊白雲山次韵二首  其二','劉跂','宋','宋诗','song-poetry','','[]','數子讀書渾欲狂，深山縱汝共徜徉。',64,'全唐诗/poet.song.60000.json','["數子讀書渾欲狂，深山縱汝共徜徉。", "千鈞脚力有底健，萬丈心情如許長。", "對景吟哦亦有意，逢人笑傲若無旁。", "幽花細草何足賞，歲歲天邊仙桂芳。"]'),
('39ab82c2-0aba-4fa1-a67c-2ba6c7d38e95','次孫君汝弼晚步韵','劉跂','宋','宋诗','song-poetry','','[]','寂寥誰過仲宣樓，邂逅斯人肯小留。',64,'全唐诗/poet.song.60000.json','["寂寥誰過仲宣樓，邂逅斯人肯小留。", "多病兒童便食粥，忘機鷗鳥共臨流。", "賦成擬學張平子，志大空慚馬少游。", "載酒從今相煖熱，著書應不號窮愁。"]'),
('c34e31ca-60b3-4d49-98f9-30be9b215d59','張大年覽文與可墨竹及先人所題與可挽詩見惠長句因次其韵','劉跂','宋','宋诗','song-poetry','','[]','墨妙蒼筤雙玉枝，賞音悲壯七哀詩。',64,'全唐诗/poet.song.60000.json','["墨妙蒼筤雙玉枝，賞音悲壯七哀詩。", "多慚寂寞青氈地，又得風流黄絹詞。", "往事白楊無數拱，餘生衰鬢不堪垂。", "聲沈影絕何人識，頼有柯亭可見思。"]'),
('836b7f49-6d6b-4f45-9e4e-c3ff0bca0936','次介叔韵','劉跂','宋','宋诗','song-poetry','','[]','酒船定向江東去，知有風流賀季真。',64,'全唐诗/poet.song.60000.json','["酒船定向江東去，知有風流賀季真。", "北嶺南岡元自熟，短楊高柳邇來新。", "老吾官職渾無味，壯子文章最有神。", "知欲弦歌且三徑，徵君莫自傍風塵。"]'),
('c23e5f1c-a078-4628-aa63-47909ef79d00','次胡伸道韵并簡公允弟','劉跂','宋','宋诗','song-poetry','','[]','幾年書不到江東，知我忘形事事慵。',64,'全唐诗/poet.song.60000.json','["幾年書不到江東，知我忘形事事慵。", "南阮最貧方遠宦，阿連同調且相從。", "狂生肯信原非病，妄校須慚廣未封。", "安得論文如定力，不眠長聽五更鐘。"]'),
('6fc38d76-f825-46a4-850b-b3471fcbb3fb','次大人二月三日過吳德仁韵二首  其一','劉跂','宋','宋诗','song-poetry','','[]','溪上高人稱福吳，一尊深喜共爲娛。',64,'全唐诗/poet.song.60000.json','["溪上高人稱福吳，一尊深喜共爲娛。", "步行可是困公子，日晏不應驕灌夫。", "縱履全勝驅下澤，緩歌長欲聽提壺。", "行年八十心如水，正覺公非嵇阮徒。"]'),
('9d068545-f91e-40f1-886a-c7f676f39c55','次大人二月三日過吳德仁韵二首  其二','劉跂','宋','宋诗','song-poetry','','[]','一一郊原春事催，客愁今日爲君開。',64,'全唐诗/poet.song.60000.json','["一一郊原春事催，客愁今日爲君開。", "柳枝鸜鵒未成舞，溪面葡萄初潑醅。", "曲水便應詩句滿，稽山那復酒船迴。", "海棠徑裏紋楸石，爲爾從今得得來。"]'),
('b6f94825-2ade-42aa-adc4-a1697485f5af','次竇子野韵','劉跂','宋','宋诗','song-poetry','','[]','不辭身熱野田風，水引膏環入眼中。',64,'全唐诗/poet.song.60000.json','["不辭身熱野田風，水引膏環入眼中。", "麴米顧公多樂事，鉏犁憐我有深功。", "博聞可但百間屋，愛客未嫌三斗葱。", "天麥毒人安敢獻，莫令堂上一尊空。"]'),
('c8ba1c9e-95d2-425b-bf91-9610fecc112f','次黄完仲韵','劉跂','宋','宋诗','song-poetry','','[]','幾年流落喜東歸，笑語相懽此一時。',64,'全唐诗/poet.song.60000.json','["幾年流落喜東歸，笑語相懽此一時。", "轣轆小車真快意，伶俜短杖且扶危。", "新詩遣興幾成癖，濁酒忘懷定不癡。", "政恐爲官拋我去，除書聞已下京師。"]'),
('b467c48b-09d6-490b-ae0c-0127d3b5223d','題僧道誠應緣菴用李端叔韵','劉跂','宋','宋诗','song-poetry','','[]','歷歷孤寒不可羣，應緣聊寄夢中身。',64,'全唐诗/poet.song.60000.json','["歷歷孤寒不可羣，應緣聊寄夢中身。", "無弦琴裏本來曲，枯木巖前元自春。", "詩句已多猶恐少，禪機雖舊不妨新。", "鄉山更好莫歸去，且伴蒲團夜坐人。"]'),
('65c88cf7-ad70-4d08-a46c-94847a743b30','惠山寺','劉跂','宋','宋诗','song-poetry','','[]','從來未到山頭寺，應在武陵深處藏。',64,'全唐诗/poet.song.60000.json','["從來未到山頭寺，應在武陵深處藏。", "漢水文人生自拙，香山居士興何長。", "四旁島嶼娟娟綠，萬頃菰蒲靡靡香。", "且醉尊中眼前物，瀛洲蓬島兩微茫。"]'),
('11c580a9-6038-4f6d-935a-112071099eb1','龍山寺','劉跂','宋','宋诗','song-poetry','','[]','曉色翩翩烏帽輕，道人瞥去不關情。',64,'全唐诗/poet.song.60000.json','["曉色翩翩烏帽輕，道人瞥去不關情。", "高山流水爲誰說，翠竹黄花空自生。", "急雨欲來先暑氣，凉風已過却秋聲。", "後期好取歸時月，照我深巖處處行。"]'),
('d142db19-850a-4aea-a8b1-0cf8882181eb','又泛西溪','劉跂','宋','宋诗','song-poetry','','[]','春晚西溪入勝遊，白楊花亂綠波浮。',64,'全唐诗/poet.song.60000.json','["春晚西溪入勝遊，白楊花亂綠波浮。", "欲延笑語遲行酒，要盡溪山緩放舟。", "灘上時看魚撥剌，林間靜聽鳥鉤輈。", "年來偷活干戈際，强把閒吟寫我憂。"]'),
('9e92bbc9-aeb6-4e58-be7e-8099ca57211e','題半隠堂','劉跂','宋','宋诗','song-poetry','','[]','一堂圖籍自陶冶，三逕蕭蘭俱歲華。',64,'全唐诗/poet.song.60000.json','["一堂圖籍自陶冶，三逕蕭蘭俱歲華。", "定非平恩許侯宅，會是仲長公理家。", "端居雅不煩摒擋，佳設頗嘗成咄嗟。", "惟我身閒數來往，徽弦一泛即生涯。"]'),
('da6e56ee-bff8-4acd-a960-88e609e84b8a','和長歷賦紙閣用王介甫韵','劉跂','宋','宋诗','song-poetry','','[]','頂還平直得中方，肯作僧庵半夜床。',64,'全唐诗/poet.song.60000.json','["頂還平直得中方，肯作僧庵半夜床。", "脫帽不憂風栗烈，熾爐仍助日蒼凉。", "賞音正自鳴琴便，宴坐何辭問疾妨。", "我有陟釐三百幅，禦冬真欲倒歸囊。"]'),
('c7bfe4fe-52d1-4145-b470-738ef11e5b32','和石友','劉跂','宋','宋诗','song-poetry','','[]','卜居無頼款郊扉，忽忽春還樂事微。',64,'全唐诗/poet.song.60000.json','["卜居無頼款郊扉，忽忽春還樂事微。", "莫道身貧非是病，由來人瘦不知肥。", "讙呼豈肯觴三爵，落魄誰如带十圍。", "富貴功名更誰是，且來同醉莫相違。"]'),
('8e14c3c1-0451-41cd-b6aa-a10c8b82d357','和曾存之約遊北園','劉跂','宋','宋诗','song-poetry','','[]','主家韋曲小桃溪，客有詩名杜拾遺。',64,'全唐诗/poet.song.60000.json','["主家韋曲小桃溪，客有詩名杜拾遺。", "煮酒未成逃暑飲，夾衣猶及惜花時。", "樾間日下潭潭蓋，蘋末風生寸寸漪。", "一醉百篇供草聖，主人𢬵取墨爲池。"]'),
('97a1420a-9ab9-42b6-b6db-5eb01825f149','和王景亮席上','劉跂','宋','宋诗','song-poetry','','[]','兒曹付汝莫相關，來伴詩翁作醉顔。',64,'全唐诗/poet.song.60000.json','["兒曹付汝莫相關，來伴詩翁作醉顔。", "花似有情憐客老，竹應無意惜春還。", "已憑玉麈消爐篆，不怕金輪照屋山。", "尊俎重開定何日，北溪流水正回環。"]'),
('d846780d-6707-4a8c-95b1-b2e4df5ffbc5','東南秀羅亦佳山而近用前韵約遊','劉跂','宋','宋诗','song-poetry','','[]','邂逅飛蓬身事輕，異鄉風物不勝情。',64,'全唐诗/poet.song.60000.json','["邂逅飛蓬身事輕，異鄉風物不勝情。", "出無輿馬自憐許，食有蛙魚空瘦生。", "失路漫漫迷日影，並溪瀝瀝灌田聲。", "似聞更有佳山在，試卜東南十里行。"]'),
('af4e247f-1b8c-41a9-b89a-321eda650819','答尹彌爾','劉跂','宋','宋诗','song-poetry','','[]','門巷相看經幾時，重來新事如弈棋。',64,'全唐诗/poet.song.60000.json','["門巷相看經幾時，重來新事如弈棋。", "從今碌碌自我拙，爾後錚錚非子誰。", "每驚咳唾盡珠玉，定有錦繡生肝脾。", "人生蓋棺事乃已，一笑一嚬安足悲。"]'),
('f770a7a7-ac95-41dd-81fe-67974ec74ca9','答劉槩石豫','劉跂','宋','宋诗','song-poetry','','[]','春來深覺境翛然，幽鳥簷頭接翅眠。',64,'全唐诗/poet.song.60000.json','["春來深覺境翛然，幽鳥簷頭接翅眠。", "落寞久知身是夢，安閒更喜日如年。", "江山南國樓臺外，桃李東風錦繡邊。", "野興暫成沂水浴，故人盍駕越溪船。"]'),
('8c30f82a-9df4-45cd-b86b-378ffe3d957f','贈秦帥吳子中','劉跂','宋','宋诗','song-poetry','','[]','河嶽根源稟植堅，金行鼎鼎應弧懸。',64,'全唐诗/poet.song.60000.json','["河嶽根源稟植堅，金行鼎鼎應弧懸。", "執珪阿閣三階上，建隼元戎十乘前。", "都護已高延壽最，中朝深記弱翁賢。", "從今看似張丞相，富貴康强一百年。"]'),
('637e348e-27d9-4951-8dc4-13e35c123f06','重葺前堂榜曰學易景亮六丈寵惠新詩謹賦二詩上謝  其一','劉跂','宋','宋诗','song-poetry','','[]','並舍荒蕪三四尋，稍營軒檻便幽深。',64,'全唐诗/poet.song.60000.json','["並舍荒蕪三四尋，稍營軒檻便幽深。", "已將種木待休影，未暇攤書聊洗心。", "投老篇章愁脈脈，隨緣香火靜愔愔。", "從今掃灑供雞黍，知有高人肯見臨。"]'),
('6f6da4f6-4909-4b3f-991a-9c822851f87c','重葺前堂榜曰學易景亮六丈寵惠新詩謹賦二詩上謝  其二','劉跂','宋','宋诗','song-poetry','','[]','草堂門徑邇來通，好事何人肯過雄。',64,'全唐诗/poet.song.60000.json','["草堂門徑邇來通，好事何人肯過雄。", "故與圖書爲伴侶，可無風月到簾櫳。", "生平適意絲桐內，老去忘懷麴米中。", "感激新詩百金重，貧裝從此不憂空。"]'),
('fb48d4e1-67ac-48ea-aae4-15350b423886','舍弟寄茶','劉跂','宋','宋诗','song-poetry','','[]','吾弟餉人真不惡，建芽來自禁烟前。',64,'全唐诗/poet.song.60000.json','["吾弟餉人真不惡，建芽來自禁烟前。", "一杯未易陽侯厄，四兩應爲蒙頂仙。", "病子頭風如得藥，酒家中聖殆忘眠。", "平頭奴子堪缾椀，可带樵青竹葉煎。"]'),
('89ccc97e-51d4-4ba4-9897-2dc1b0b30e1e','遣懷','劉跂','宋','宋诗','song-poetry','','[]','此身爲客幾東西，萬物須于一馬齊。',64,'全唐诗/poet.song.60000.json','["此身爲客幾東西，萬物須于一馬齊。", "山色不隨春草綠，邊聲長伴夜烏啼。", "宦遊碌碌憑誰記，簿領紛紛爲底迷。", "猶喜官輕無局事，不妨酣寢過晨雞。"]'),
('fb63fdb7-3129-4d25-9550-61baf1598ae7','坐進庵戲作  其一','劉跂','宋','宋诗','song-poetry','','[]','自吾營此庵，遷徙屢有無。',24,'全唐诗/poet.song.60000.json','["自吾營此庵，遷徙屢有無。", "壁間故人文，今獨與我俱。"]'),
('2db3be71-44bd-4157-811a-339bd4efd92a','坐進庵戲作  其二','劉跂','宋','宋诗','song-poetry','','[]','結以不根茅，闔之無鑰鎖。',24,'全唐诗/poet.song.60000.json','["結以不根茅，闔之無鑰鎖。", "堅密烏有身，非坐常宴坐。"]'),
('62d8a2e0-fc0b-4dbf-9ffe-ae7a10bac2eb','坐進庵戲作  其三','劉跂','宋','宋诗','song-poetry','','[]','圓蒲與方竹，伴我守幽閒。',24,'全唐诗/poet.song.60000.json','["圓蒲與方竹，伴我守幽閒。", "夜闌得禪趣，明月窺窗間。"]'),
('32f3f495-dba3-42a1-bb1d-e75a639dc656','王升之絕句以詩成有共賦酒熟無孤斟爲韵因次其韵  其一','劉跂','宋','宋诗','song-poetry','','[]','端居得韵語，不作凉秋悲。',24,'全唐诗/poet.song.60000.json','["端居得韵語，不作凉秋悲。", "快若彈丸轉，知是王家詩。"]'),
('68616144-f96a-46eb-96ad-1fa49a25fd05','王升之絕句以詩成有共賦酒熟無孤斟爲韵因次其韵  其二','劉跂','宋','宋诗','song-poetry','','[]','之人嫻辭令，病起猶越聲。',24,'全唐诗/poet.song.60000.json','["之人嫻辭令，病起猶越聲。", "不量蒼蒼鬢，屬和愁僅成。"]'),
('514fb91f-497b-40d9-b1e2-f0e276c0e161','王升之絕句以詩成有共賦酒熟無孤斟爲韵因次其韵  其三','劉跂','宋','宋诗','song-poetry','','[]','客來問玄解，付與尊中友。',24,'全唐诗/poet.song.60000.json','["客來問玄解，付與尊中友。", "我口不能言，此間甚多有。"]'),
('86192a19-2b0f-496e-9c1b-e10de213abe6','王升之絕句以詩成有共賦酒熟無孤斟爲韵因次其韵  其四','劉跂','宋','宋诗','song-poetry','','[]','欲逃蘇晉禪，苦乏陽城俸。',24,'全唐诗/poet.song.60000.json','["欲逃蘇晉禪，苦乏陽城俸。", "鄰家稱子貧，杯酌與君共。"]'),
('0081ed0f-a6c6-4148-84e7-815723d775aa','王升之絕句以詩成有共賦酒熟無孤斟爲韵因次其韵  其五','劉跂','宋','宋诗','song-poetry','','[]','憶昨艘檝間，月白雲水暮。',24,'全唐诗/poet.song.60000.json','["憶昨艘檝間，月白雲水暮。", "妙語同賞心，請君來重賦。"]'),
('158a2f09-b30b-42fb-b843-3f9d1740385f','王升之絕句以詩成有共賦酒熟無孤斟爲韵因次其韵  其六','劉跂','宋','宋诗','song-poetry','','[]','且無遽典衣，素書堪下酒。',24,'全唐诗/poet.song.60000.json','["且無遽典衣，素書堪下酒。", "旋斸金鈴黄，栽軒媚重九。"]'),
('9d578bef-b3e2-416e-bd92-0c3848a6b7d5','王升之絕句以詩成有共賦酒熟無孤斟爲韵因次其韵  其七','劉跂','宋','宋诗','song-poetry','','[]','念當歲崢嶸，少別友中玉。',24,'全唐诗/poet.song.60000.json','["念當歲崢嶸，少別友中玉。", "夢寐大刀頭，安得盧橘熟。"]'),
('d050c334-9217-45a8-b1e2-957549654e63','王升之絕句以詩成有共賦酒熟無孤斟爲韵因次其韵  其八','劉跂','宋','宋诗','song-poetry','','[]','霜蟹豐兩螯，磊落登盤盂。',24,'全唐诗/poet.song.60000.json','["霜蟹豐兩螯，磊落登盤盂。", "亹亹倦咀嚼，繄我愁獨無。"]'),
('e490d401-50e0-48a8-9b19-4db33932c6f3','王升之絕句以詩成有共賦酒熟無孤斟爲韵因次其韵  其九','劉跂','宋','宋诗','song-poetry','','[]','庭階脫葉靜，岌岌高井梧。',24,'全唐诗/poet.song.60000.json','["庭階脫葉靜，岌岌高井梧。", "雁聲排雲去，歷歷心不孤。"]'),
('32b52b13-756e-445e-9ddf-ae76330fa718','王升之絕句以詩成有共賦酒熟無孤斟爲韵因次其韵  其一○','劉跂','宋','宋诗','song-poetry','','[]','夜寒慘不寐，起坐彈鳴琴。',24,'全唐诗/poet.song.60000.json','["夜寒慘不寐，起坐彈鳴琴。", "之人邈雲漢，空盃難獨斟。"]'),
