('2a08b8bb-2d02-4281-9760-5f08004ba73b','恩赦放還集句先寄鄉中弟姪三首  其二','劉跂','宋','宋诗','song-poetry','','[]','櫓聲衝雨似鳴機，終日思歸此日歸。',32,'全唐诗/poet.song.60000.json','["櫓聲衝雨似鳴機，終日思歸此日歸。", "自爲野客尋幽慣，不用登臨歎落暉。"]'),
('330374f0-04f2-4cd1-a801-58de1458adbf','恩赦放還集句先寄鄉中弟姪三首  其三','劉跂','宋','宋诗','song-poetry','','[]','閒思往事似前身，羞見黄花無數新。',32,'全唐诗/poet.song.60000.json','["閒思往事似前身，羞見黄花無數新。", "我家孤姪在海浦，遍插茱萸少一人。"]'),
('fbe49b2b-847d-4e2f-bc4e-4b0a891f4afc','李氏繡佛贊  其一','劉跂','宋','宋诗','song-poetry','','[]','稽首慈悲父，相好光明藏。',96,'全唐诗/poet.song.60000.json','["稽首慈悲父，相好光明藏。", "應現行願力，針縷妙措成。", "我觀因緣空，亦非自然性。", "種種皆心造，是心非造者。", "佛子不思議，熾然一念生。", "諸聖所加持，具足千百億。", "我願如是故，造作及見聞。", "遇見未來等，同承佛記莂。"]'),
('e0963fa1-ba2a-4e8a-8e0d-69538588f99e','李氏繡佛贊  其二','劉跂','宋','宋诗','song-poetry','','[]','巍巍堂堂，妙莊嚴聚。',40,'全唐诗/poet.song.60000.json','["巍巍堂堂，妙莊嚴聚。", "一念現前，非針非縷。", "文聞已彰，何妨金露。", "滿月當空，誰知在處。"]'),
('a1da21df-5dfa-4cf7-8e5d-5f5d67f46c09','古器圖贊','劉跂','宋','宋诗','song-poetry','','[]','想古之人，悠哉邈乎。',80,'全唐诗/poet.song.60000.json','["想古之人，悠哉邈乎。", "我獲其器，賦象在圖。", "有客見之，笑此展轉。", "閱斯勤斯，其人云遠。", "我欲曉客，耿不能言。", "退觀古人，恍獨如存。", "千載寥寥，不在圖外。", "謂不信者，取器以對。"]'),
('3539ec44-b659-4a37-ba7d-0fd96f197733','虜中作四首  其一','劉跂','宋','宋诗','song-poetry','','[]','文物燕人士，衣冠漢典儀。',48,'全唐诗/poet.song.60000.json','["文物燕人士，衣冠漢典儀。", "舉知繒絮好，深厭血毛非。", "形勢今猶古，規模夏變夷。", "誰言無上策，會是有天時。"]'),
('c3e0c566-c006-4b26-a824-0d95005d5cb8','虜中作四首  其二','劉跂','宋','宋诗','song-poetry','','[]','甘作河南犬，休爲燕地人。',48,'全唐诗/poet.song.60000.json','["甘作河南犬，休爲燕地人。", "舉能羞石晉，誰復怨嬴秦。", "地扼遼東海，星占析木津。", "悲傷此邦舊，會遣一朝新。"]'),
('6bc7ae23-cc84-44a9-bdf1-1541cbabc4e5','虜中作四首  其三','劉跂','宋','宋诗','song-poetry','','[]','人物分多種，遷流不見經。',48,'全唐诗/poet.song.60000.json','["人物分多種，遷流不見經。", "已無燕代色，但有犬羊腥。", "海馬生難馭，山苗煮始青。", "舜韶方九奏，異類合來庭。"]'),
('da9b6e1c-946e-4975-8be7-ea3e8c92c24a','虜中作四首  其四','劉跂','宋','宋诗','song-poetry','','[]','聞有官軍士，生存仍宦胡。',48,'全唐诗/poet.song.60000.json','["聞有官軍士，生存仍宦胡。", "羞言隴西李，忍對杜陵蘇。", "椎髻心何似，環刀意豈無。", "陳湯那復得，衛律不勝誅。"]'),
('759b6f6c-c8d7-4113-a7ea-b869800d24c4','吳江長橋','劉跂','宋','宋诗','song-poetry','','[]','路隔銀潢鳥倦飛，行人恐犯女星機。',64,'全唐诗/poet.song.60000.json','["路隔銀潢鳥倦飛，行人恐犯女星機。", "長虹出浪無冬夏，老蜃浮空半是非。", "兩岸履聲雲內合，三州帆影月邊歸。", "欄干獨立秋風早，豈待鱸魚始拂衣。"]'),
('4588b799-2c7a-48fa-99a0-47da308258c3','句','劉跂','宋','宋诗','song-poetry','','[]','急雨欲來先暑氣，凉風過後却秋聲。',16,'全唐诗/poet.song.60000.json','["急雨欲來先暑氣，凉風過後却秋聲。"]'),
('6abf0a71-659f-43f6-a8bd-44488fa221bc','送程給事知越州  其一','周諶','宋','宋诗','song-poetry','','[]','公應夙世作詞臣，文采飄飄入眼新。',64,'全唐诗/poet.song.60000.json','["公應夙世作詞臣，文采飄飄入眼新。", "畫燭排空滕閣夜，紅旌照海越臺春。", "新篇錦繡盈南國，舊德鵷鴻綴北辰。", "白髮會稽還卧鎮，直將生理付陶鈞。"]'),
('55ace21a-52f7-49c4-9207-17b922b57b5b','送程給事知越州  其二','周諶','宋','宋诗','song-poetry','','[]','風烟初別武王臺，更向金河握節回。',64,'全唐诗/poet.song.60000.json','["風烟初別武王臺，更向金河握節回。", "日月違顔天縹緲，塵沙吹面玉摧頹。", "試看紫府驂鸞去，又見長安駟馬催。", "欲作東州遺愛錄，自慚詞筆乏鄒枚。"]'),
('ffec7a84-c895-4c4c-9cde-fa0f72ccfa18','句','陳瑊','宋','宋诗','song-poetry','','[]','自是古今無變異，豈因霜雪有枯榮。',16,'全唐诗/poet.song.60000.json','["自是古今無變異，豈因霜雪有枯榮。"]'),
('24875722-a386-4e26-8ecc-e427e60de87a','詩一首','孫子實','宋','宋诗','song-poetry','','[]','薛宣欲吏雲，季氏或招閔。',120,'全唐诗/poet.song.60000.json','["薛宣欲吏雲，季氏或招閔。", "此分冒中秋，萬物既收稛。", "賣藥偶知名，草玄非近準。", "才難不易得，志大略細謹。", "士生要弘毅，天地如蓋軫。", "驥令鹽車驂，井下知綆引。", "難甘吁爾食，聊寄粲然囅。", "誰能借前籌，還婦用束藴。", "吾聞調羹鼎，異味及粉槿。", "豈其供王羞，而棄會稽笋。"]'),
('43be786b-8ca5-493c-9798-f3dbf2c94a5d','與同舍諸公飲王詵都尉家有侍兒輩侍香求詩求字者以烟濃近侍香爲韵','曾誠','宋','宋诗','song-poetry','','[]','俯仰家人看墨蹤，和研親炷寶熏濃。',64,'全唐诗/poet.song.60000.json','["俯仰家人看墨蹤，和研親炷寶熏濃。", "詩情過筆當千里，妙思凝香欲萬重。", "山盎泄雲傾白酒，越羅霑露浥黄封。", "從來粉黛宜燈燭，妙手憑誰寫醉容。"]'),
('9a425e8b-b50c-411a-8027-82e3d20f62c7','七夕王都尉邀同舍置酒聽琵琶','曾誠','宋','宋诗','song-poetry','','[]','寶檻凌雲結綺高，小奩爭巧暮分曹。',64,'全唐诗/poet.song.60000.json','["寶檻凌雲結綺高，小奩爭巧暮分曹。", "春葱細撚龍香撥，秀頸偏明邏逤槽。", "牛既寫形呈粔籹，馬軍馳酒送蒲萄。", "淚珠散作人間露，最覺更闌潤錦絛。"]'),
('6c7d8ecd-ed84-4864-9454-cf482c115532','雪','曾誠','宋','宋诗','song-poetry','','[]','瞥看塵硯忽生冰，試出疏門雪已平。',64,'全唐诗/poet.song.60000.json','["瞥看塵硯忽生冰，試出疏門雪已平。", "棲鳥亂爭寒栱鬧，晚雞微傍凍樞鳴。", "風花半結乾尤重，雲葉初黄暗未晴。", "書罷擁衾渾不寐，夜長惟聽灑窗明。"]'),
('b93435c7-052b-408a-be59-f373d591bd33','句  其一','曾誠','宋','宋诗','song-poetry','','[]','從來釣竿手，不解叩黄扉。',12,'全唐诗/poet.song.60000.json','["從來釣竿手，不解叩黄扉。"]'),
('a8cefc73-6777-4fca-9f72-2d0793a87f34','句  其二','曾誠','宋','宋诗','song-poetry','','[]','椎冰小鯉應堪鱠，掃岸疏梅未放花。',16,'全唐诗/poet.song.60000.json','["椎冰小鯉應堪鱠，掃岸疏梅未放花。"]'),
('9098486c-a2e4-4b75-96f0-2a480392081b','句  其三','曾誠','宋','宋诗','song-poetry','','[]','年衰髮種種。',6,'全唐诗/poet.song.60000.json','["年衰髮種種。"]'),
('ed760916-e321-461a-b82c-318fa7a24ba0','句  其四','曾誠','宋','宋诗','song-poetry','','[]','幽襟失所從。',6,'全唐诗/poet.song.60000.json','["幽襟失所從。"]'),
('fcdf1f3b-d57e-41a7-8c3f-e0e7d903c4dc','句  其五','曾誠','宋','宋诗','song-poetry','','[]','侵岸疏梅已放花。',8,'全唐诗/poet.song.60000.json','["侵岸疏梅已放花。"]'),
('5b6f5610-c0d4-4cbf-8af8-a4c126649cf7','木香','范周','宋','宋诗','song-poetry','','[]','暖風吹麝入鉛華，不肯隨春到謝家。',32,'全唐诗/poet.song.60000.json','["暖風吹麝入鉛華，不肯隨春到謝家。", "半夜粉寒香泣露，也應和月怨梨花。"]'),
('607dff09-fd06-4d9d-acfc-8964b3adc16d','題監簿石存中園亭壁','范周','宋','宋诗','song-poetry','','[]','范周來謁石存中，未必存中似石崇。',32,'全唐诗/poet.song.60000.json','["范周來謁石存中，未必存中似石崇。", "可惜南山焦尾虎，低頭拜狗作烏龍。"]'),
('15b71966-ba01-425e-ba04-b679faabb6c6','與府庠諸坐巡夜','范周','宋','宋诗','song-poetry','','[]','自古輕儒孰若秦，山河社稷付他人。',32,'全唐诗/poet.song.60000.json','["自古輕儒孰若秦，山河社稷付他人。", "而今重士如周室，忍使書生作夜巡。"]'),
('ea540d41-f548-4772-a401-5e0fdefc6743','崑山','范周','宋','宋诗','song-poetry','','[]','萬疊青巒壓巨崑，四垂空闊水天分。',64,'全唐诗/poet.song.60000.json','["萬疊青巒壓巨崑，四垂空闊水天分。", "夜光寒带三江月，春色陰連百里雲。", "桂子鶴驚空半落，天香僧出定中聞。", "不將此境憑張益，三百年來屬老文。"]'),
('231a966c-ba06-4b8d-af55-011779e9ad5c','句','范周','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','一瓢有道泰山重，五鼎不義鴻毛輕。',16,'全唐诗/poet.song.60000.json','["一瓢有道泰山重，五鼎不義鴻毛輕。"]'),
('0b6861c7-5f0d-4150-8536-dca389d6a3b4','上方翫月','蔣晞顔','宋','宋诗','song-poetry','','[]','明月自當千里共，如何獨得占嬋娟。',32,'全唐诗/poet.song.60000.json','["明月自當千里共，如何獨得占嬋娟。", "只應飛閣侵天半，此外誰能近月邊。"]'),
('adf69b4b-0693-4dbd-91be-1f37c61fa692','趙康州徐夫子廟','苗仲淵','宋','宋诗','song-poetry','','[]','世惟忠與孝，訓俗知所止。',36,'全唐诗/poet.song.60000.json','["世惟忠與孝，訓俗知所止。", "殺身趙康州，錫類徐夫子。", "雖非萃一門，死葬同閭里。"]'),
('f3f9a692-2ce9-42e8-8701-89ffc4426850','頌','慈觀長老','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','龍牙答話只蘇嚧，借問諸方會也無。',32,'全唐诗/poet.song.60000.json','["龍牙答話只蘇嚧，借問諸方會也無。", "昨夜虛空開口笑，祝融吞却洞庭湖。"]'),
('5cfd0e95-6f6c-44e7-81d6-36c03da3aca4','寒食上塚至瀾洄莊追思祖烈感而爲詩','司馬康','宋','宋诗','song-poetry','','[]','祖學當年向此勤，子孫今日繼清芬。',64,'全唐诗/poet.song.60000.json','["祖學當年向此勤，子孫今日繼清芬。", "賢能自過高陽里，尊寵無慚萬石君。", "花滿一川紅蕊亂，渠環千頃翠波分。", "高門駟馬流餘慶，當見吾家世有聞。"]'),
('e3240162-3dda-4e56-afb8-3ffe21aa1425','示居士張戒二首  其一','釋系南','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','汝到廬山山到汝，更誰別我廬山去。',32,'全唐诗/poet.song.60000.json','["汝到廬山山到汝，更誰別我廬山去。", "出門問取嶺頭風，大道騰騰無本據。"]'),
('2bfbe0de-10f5-4334-ae37-0835f36a0f0b','示居士張戒二首  其二','釋系南','宋','宋诗','song-poetry','','[]','頭戴烏巾著白襴，山房借汝一年閒。',32,'全唐诗/poet.song.60000.json','["頭戴烏巾著白襴，山房借汝一年閒。", "出門爲說來時路，家在黄陂翠靄間。"]'),
('08db5ffa-0470-4381-bc79-b743b8a129fe','偈','釋系南','宋','宋诗','song-poetry','','[]','禪不禪，道不道，三寸舌頭胡亂掃。',56,'全唐诗/poet.song.60000.json','["禪不禪，道不道，三寸舌頭胡亂掃。", "昨夜日輪飄桂花，今朝月窟生芝草。", "呵呵呵，萬兩黄金無處討。", "一句絕思量，諸法不相到。"]'),
('6a8afe17-7f12-4e99-8a5c-6ae1dde82ab9','臨終偈','釋系南','宋','宋诗','song-poetry','','[]','羅漢今日，倒騎鐵馬，逆上須彌。',25,'全唐诗/poet.song.60000.json','["羅漢今日，倒騎鐵馬，逆上須彌。", "踏破虛空，不留朕迹。"]'),
('69aa1c36-7d10-402a-bf5d-0ad2d363be8c','別柳將軍廟','蔣靜','宋','宋诗','song-poetry','','[]','夢事雖非實，將軍默有靈。',48,'全唐诗/poet.song.60000.json','["夢事雖非實，將軍默有靈。", "舊祠從此煥，古檜蔚然青。", "甲馬宵中見，琴堂卧正冥。", "留詩非志怪，三五扣神扃。"]'),
('b419f2f9-fefa-4b32-bc43-c901448a8dbc','翠光亭','蔣靜','宋','宋诗','song-poetry','','[]','君山堆翠出危尖，練水浮光照短簷。',64,'全唐诗/poet.song.60000.json','["君山堆翠出危尖，練水浮光照短簷。", "夜鶴曉猿同冷淡，胡床麈尾獨安恬。", "雲來畫棟休遮眼，月到澄溪任透簾。", "還似棄官陶靖節，北窗高卧怕誰嫌。"]'),
('1b3ec030-7703-4023-8bda-a19d428d67ef','題蔣帝廟二首  其一','蔣靜','宋','宋诗','song-poetry','','[]','青骨沈埋恨未休，寒烟深鎖舊山愁。',64,'全唐诗/poet.song.60000.json','["青骨沈埋恨未休，寒烟深鎖舊山愁。", "悲風力掃欃槍日，勇氣平吞澤國秋。", "身殞一朝心報國，功褒千古首凝旒。", "當年白羽雲頭扇，還許仍來得見不。"]'),
('484fa651-491c-45a5-be97-e940d9efd018','題蔣帝廟二首  其二','蔣靜','宋','宋诗','song-poetry','','[]','鍾阜巍巍插太虛，祠堂高拱此山墟。',32,'全唐诗/poet.song.60000.json','["鍾阜巍巍插太虛，祠堂高拱此山墟。", "誰言荒草埋青骨，時有僊風掃舊廬。"]'),
('bcdb8bcd-72e9-4a89-83a4-1b7f9bea12a8','遊白龍山','蔣靜','宋','宋诗','song-poetry','','[]','駐馬白龍山，拂石青松下。',48,'全唐诗/poet.song.60000.json','["駐馬白龍山，拂石青松下。", "雲從潭底生，風向松枝灑。", "風雲了無心，聊隨白龍化。", "勿謂風雲擾，中含閑暇者。"]'),
('16e31ab9-73fd-44c2-a63a-915c570e376a','題毗山','蔣靜','宋','宋诗','song-poetry','','[]','四十年前掉臂遊，寺庭荒落易悲秋。',64,'全唐诗/poet.song.60000.json','["四十年前掉臂遊，寺庭荒落易悲秋。", "重來氣象渾非昔，滿院松杉翠欲流。", "方外故人惟白骨，壁間陳跡獨銀鈎。", "青春祗道堪行樂，獨倚僧窗萬斛愁。"]'),
('b734f124-8f60-4a64-ba36-efac6fbb6052','洗心亭睡起偶題','蔣靜','宋','宋诗','song-poetry','','[]','黄粱未熟酒猶醲，一夢南柯事已空。',64,'全唐诗/poet.song.60000.json','["黄粱未熟酒猶醲，一夢南柯事已空。", "水綠山青無限好，今來古往不知窮。", "龍吟竹笛秋江面，雪糝蘆花夜月中。", "清景阿誰偏占得，白頭波上釣魚翁。"]'),
('185d4b33-5dfa-47b2-8029-9f2d370b272c','句  其一','蔣靜','宋','宋诗','song-poetry','','[]','行藝已書丞相筆，姓名還結裕陵知。',16,'全唐诗/poet.song.60000.json','["行藝已書丞相筆，姓名還結裕陵知。"]'),
('01ae1abe-be62-4427-b7ad-7dbb592b0a2f','句  其二','蔣靜','宋','宋诗','song-poetry','','[]','他日如尋隠君子，女山深處一孤墳。',16,'全唐诗/poet.song.60000.json','["他日如尋隠君子，女山深處一孤墳。"]'),
('0d527d26-0cee-44f8-a5c7-87a49d3be3c3','金精山','孫勰','宋','宋诗','song-poetry','','[]','多病厭凡垢，思欲求道真。',120,'全唐诗/poet.song.60000.json','["多病厭凡垢，思欲求道真。", "金精古福地，中有超世人。", "駕言從之遊，洗我千劫塵。", "洞門無扃鎖，松竹四時春。", "泉聲散風韵，珩珮若有聞。", "九微何燿煜，百和方氤氳。", "稽首願乞靈，縹緲如相親。", "至妙非言說，蕭然清吾神。", "大道本自然，一悟不在勤。", "逍遥此岩下，當自觀其身。"]'),
('e6d4607f-f461-4fbf-9a1e-045b48e984e9','句','孫勰','宋','宋诗','song-poetry','','[]','端溪紫玉試自滌，磨動玄雲驅霹靂。',16,'全唐诗/poet.song.60000.json','["端溪紫玉試自滌，磨動玄雲驅霹靂。"]'),
('fe4fbca9-dec3-47bf-8084-1bc9288ae340','秋宵','錢遹','宋','宋诗','song-poetry','','[]','南鄰燈火冷，三歎愁夜永。',40,'全唐诗/poet.song.60000.json','["南鄰燈火冷，三歎愁夜永。", "北里歌未終，已驚初日紅。", "不知晝夜誰拘管，一等秋宵有長短。"]'),
('f714c08e-5058-404c-b593-1a4b983a2631','留題九龍巖','劉溫','宋','宋诗','song-poetry','','[]','繡嶺如屏倚梵宮，九龍疇昔隠巖空。',32,'全唐诗/poet.song.60000.json','["繡嶺如屏倚梵宮，九龍疇昔隠巖空。", "湖壖勝概嬉遊遍，名宦勞生西復東。"]'),
('7c2c67a6-1751-4e5b-8f67-3a9a3db0679a','題共樂堂','姚舜諧','宋','宋诗','song-poetry','','[]','秀氣清陰日滿前，仙瀛蓬閬景都全。',64,'全唐诗/poet.song.60000.json','["秀氣清陰日滿前，仙瀛蓬閬景都全。", "綵舟畫楫魚噴浪，綺席金爐麝吐烟。", "懽勝更思明月夜，飲酣惟恐夕陽天。", "主人報政榮塗近，淮浙重遊路接連。"]'),
('6444b156-9fef-431d-8e9a-4c9dcf931093','題東掖山承天院','姚舜諧','宋','宋诗','song-poetry','','[]','面勢崔嵬插斗牛，東分一掖鎮丹丘。',64,'全唐诗/poet.song.60000.json','["面勢崔嵬插斗牛，東分一掖鎮丹丘。", "玉毫金相祖師會，寶帙琅函海藏流。", "蒼檜茂林常蔭映，白蓮香社共熏修。", "紅塵斷處人難到，俗駕經年始此遊。"]'),
('98ec3ac7-6cb0-4e08-b0a5-e09cea0d8b53','崇慶寺','宋景瞻','宋','宋诗','song-poetry','','[]','峭壁青連古院松，疏林聲渡晚風鐘。',64,'全唐诗/poet.song.60000.json','["峭壁青連古院松，疏林聲渡晚風鐘。", "地擎鰲背中分勢，僧住天宮第幾重。", "泉落斷崖懸素練，樹蟠危石掛蒼龍。", "登臨遠與紅塵隔，疑在三山最上峰。"]'),
('7e799026-24d0-45c1-a458-dcd3f49a93bc','句','宋景瞻','宋','宋诗','song-poetry','','[]','可憐萬里南飛翼，肯向霜林借一枝。',16,'全唐诗/poet.song.60000.json','["可憐萬里南飛翼，肯向霜林借一枝。"]'),
('c9dd0101-61dd-46ba-9ec5-ae525bc8c4d5','陪諸公觀稼','張莊','宋','宋诗','song-poetry','','[]','山甫遄歸有詔期，省耕聊復輝幢麾。',64,'全唐诗/poet.song.60000.json','["山甫遄歸有詔期，省耕聊復輝幢麾。", "翠岑恰似千旗密，綠野何妨萬馬馳。", "雕鶚精神元老貴，鼎彝功業太平時。", "自惟晚進誠天幸，偶附台躔每處隨。"]'),
('318d0d47-cdb5-4493-b278-f289dd216151','題南龕寺  其一','家彬','宋','宋诗','song-poetry','','[]','巖下楩楠秋復春，當年觴詠悉名臣。',32,'全唐诗/poet.song.60000.json','["巖下楩楠秋復春，當年觴詠悉名臣。", "舊遊已去成陳迹，佳句還如見古人。"]'),
('ab3c3185-a6db-41a6-8462-1fcbc4c8362d','題南龕寺  其二','家彬','宋','宋诗','song-poetry','','[]','極目江山依夕照，回頭城市隔囂塵。',32,'全唐诗/poet.song.60000.json','["極目江山依夕照，回頭城市隔囂塵。", "登臨未久還西去，堪愧芸夫每問津。"]'),
('991e1d8f-2167-4e19-957f-f0ed9eadf795','春日有懷','林敏功','宋','宋诗','song-poetry','','[]','風高收雨急，日薄過窗微。',48,'全唐诗/poet.song.60000.json','["風高收雨急，日薄過窗微。", "梅萼初迎臘，春溪欲染衣。", "形容今日是，遊衍昔人非。", "節物關愁者，歸鴻正北飛。"]'),
('967a9386-7081-459c-b418-0edf0f1c9859','書吳熙老醉杜甫像','林敏功','宋','宋诗','song-poetry','','[]','清晨出尋酒家門，蹇馿破帽衣懸鶉。',96,'全唐诗/poet.song.60000.json','["清晨出尋酒家門，蹇馿破帽衣懸鶉。", "年年碧雞坊下路，野梅官柳慣尋春。", "酒錢有無俱醉倒，改罷新詩留腹稿。", "兒童拍手遮路衢，拾遺笑倩旁人扶。", "百年風雅前無古，沈宋曹劉安足數。", "後來一字人難補，君莫笑渠作詩苦。"]'),
('4297b4f0-d51d-48a2-b8ff-41fc08e380fe','題薛彥海墨竹','林敏功','宋','宋诗','song-poetry','','[]','修竹嘗連林，誰復訪清秀。',96,'全唐诗/poet.song.60000.json','["修竹嘗連林，誰復訪清秀。", "妙手拂素壁，直節乃一□。", "□□別孤芳，妙舞欺長袖。", "隻影媚澄潭，清風在中霤。", "山中歲言邁，慰我聊邂逅。", "臃腫門前樗，軟弱常□茂。", "固無斧斤厄，每犯霜雪叩。", "誰知彼樗肥，不如此君瘦。"]'),
('fba7be77-de60-42aa-9c96-df95cdfe46b1','子瞻畫扇','林敏功','宋','宋诗','song-poetry','','[]','夫子江湖客，毫端託渺茫。',48,'全唐诗/poet.song.60000.json','["夫子江湖客，毫端託渺茫。", "攢峰埋暮雨，古樹困天霜。", "偪側餘僧舍，溟濛失雁行。", "生死隨化盡，此意獨難忘。"]'),
('17047465-50ff-45a5-8d4e-29a0f893723d','絕句','林敏功','宋','宋诗','song-poetry','','[]','君心恨不走天涯，不比衰翁只戀家。',32,'全唐诗/poet.song.60000.json','["君心恨不走天涯，不比衰翁只戀家。", "最是橫塘黄葉路，今年無伴折梅花。"]'),
('63e44e5c-94fb-4adb-ae86-0f68c2362277','德章寺','林敏功','宋','宋诗','song-poetry','','[]','我行蘄州城，東望黄梅山。',48,'全唐诗/poet.song.60000.json','["我行蘄州城，東望黄梅山。", "謂言一驛地，何時可躋攀。", "今日復何日，籃輿到山間。", "林開德章寺，岫幌青雲關。"]'),
('55a7c427-bb54-4491-8218-4ce86d0d2744','與劉羲仲檢討別後有懷','林敏功','宋','宋诗','song-poetry','','[]','檠燈耿夜窗，夜雨欲達晨。',132,'全唐诗/poet.song.60000.json','["檠燈耿夜窗，夜雨欲達晨。", "寒雞催曉色，結束征車輪。", "車行馬上霜，送子西入秦。", "二年絕廩祿，此去當通津。", "人生萍托水，相遇即相親。", "況我與夫子，恩意踰天倫。", "屈指十日別，今君千里人。", "關山行役勞，欲雪風怒嗔。", "投身聲利區，納足冠蓋塵。", "銅墨不須歎，君心知愛民。", "歲晚勿滯留，歸及江南春。"]'),
('5912620b-5d5d-4fd0-a843-b859f151fca3','贈趙正之','林敏功','宋','宋诗','song-poetry','','[]','君爲稻田官，君非力田科。',144,'全唐诗/poet.song.60000.json','["君爲稻田官，君非力田科。", "我令耕田夫，爲君奏田歌。", "南畝茨粱稼，東郊烟雨蓑。", "田家不作苦，奈此歲暮何。", "憫憫望有年，一失成蹉跎。", "立苗非不疏，稊稗常苦多。", "小人剝良善，蓬蒿賤嘉禾。", "去惡藉老農，芟夷戒駢羅。", "夫君邦之彥，妙年加切磋。", "治國與治身，此道終靡他。", "人心不相遠，如以斧伐柯。", "願君日顯榮，吾言期不磨。"]'),
('0ee19a1a-7019-402e-b48e-137949ad095b','句  其一','林敏功','宋','宋诗','song-poetry','','[]','嘗憶他年接緒餘，饒三落托我迂疏。',32,'全唐诗/poet.song.60000.json','["嘗憶他年接緒餘，饒三落托我迂疏。", "谿橋幾換風前柳，僧壁今留醉後書。"]'),
('83a5ac93-7305-4d82-bb90-3e1874f5a9ec','句  其二','林敏功','宋','宋诗','song-poetry','','[]','心逐片雲閑。',6,'全唐诗/poet.song.60000.json','["心逐片雲閑。"]'),
('e7b1691e-9eee-40e7-b836-1125387fef6f','句  其三','林敏功','宋','宋诗','song-poetry','','[]','路尋流水遠。',6,'全唐诗/poet.song.60000.json','["路尋流水遠。"]'),
('20c039a2-425d-479b-9f69-269b3ad0287e','句  其四','林敏功','宋','宋诗','song-poetry','','[]','竹閒初折半斜枝。',8,'全唐诗/poet.song.60000.json','["竹閒初折半斜枝。"]'),
('5b879d58-faf1-4b91-a1d8-48928b5813ef','句  其五','林敏功','宋','宋诗','song-poetry','','[]','近方薝蔔黄，遠比茉莉小。',12,'全唐诗/poet.song.60000.json','["近方薝蔔黄，遠比茉莉小。"]'),
('a92f90ff-6af7-4b4d-9962-e9dc28782c00','無題','林敏功','宋','宋诗','song-poetry','','[]','琵琶起舞換新聲，總是關山舊客情。',32,'全唐诗/poet.song.60000.json','["琵琶起舞換新聲，總是關山舊客情。", "撩亂邊愁彈不盡，高高秋月照長城。"]'),
('ff41b3fe-fd90-483e-b1d8-297bce74d3db','竹溪','林敏修','宋','宋诗','song-poetry','','[]','幽閑古城陰，結屋清溪曲。',204,'全唐诗/poet.song.60000.json','["幽閑古城陰，結屋清溪曲。", "溪流湛回映，上有青青竹。", "漫郎欣得之，綠髮詠空谷。", "高風及前修，勝趣隨遠矚。", "惡客徒擾人，立談非我欲。", "麾去寧汝嗔，真意聊自足。", "或言不當爾，往往相謗讟。", "答云豈吾私，恐作林泉辱。", "源流別涇渭，臭味同草木。", "肯當百事勝，容此一物俗。", "獨餘嵇阮輩，蕩槳戒臣僕。", "濁醪澆古胸，日沒還秉燭。", "僕忝瓜葛後，意氣頗相屬。", "平生幾兩屐，共老三徑菊。", "行年事無定，此計諾已宿。", "徑須買牛衣，兒亦荷書簏。", "從子竹間遊，溪魚剁寒玉。"]'),
('30d8cffc-06c8-4963-bed2-aaf38c7674d6','閻立本畫醉道士圖','林敏修','宋','宋诗','song-poetry','','[]','破除萬事無過酒，有客何須計升斗。',133,'全唐诗/poet.song.60000.json','["破除萬事無過酒，有客何須計升斗。", "解將富貴等浮雲，醉鄉即是無何有。", "昔人繪事亦有神，丹青寫出畫天真。", "尊罍未耻月漸傾，更待曉出扶桑暾。", "餐霞服氣浪自苦，自厭神仙足官府。", "脫巾解带衣淋漓，眼花錯莫誰賓主。", "君不見炙手可熱唯權門，欲觀佳麗遭怒嗔。", "何如銜盃樂聖藉地飲，安用醉吐丞相茵。"]'),
('1995d6c9-42d6-45e7-b3d7-1319823068af','文湖州作山水橫軸吳希全家藏其子誠伯求蘇養直賦詩語特奇妙遂用其韵同賦','林敏修','宋','宋诗','song-poetry','','[]','明窗十日復五日，出此湖光與山色。',112,'全唐诗/poet.song.60000.json','["明窗十日復五日，出此湖光與山色。", "前身畫師語不妄，文侯乃是金門客。", "乍從雲際辨遠岫，爭數喬林誇眼力。", "沒漂菰米歲事空，水濱柱下南飛鴻。", "欲投曉渡喚舟子，急槳已入昏烟中。", "徑思天邊問歸路，錯認江鄉舊洲渚。", "能傳萬里在尺素，豪奪應防卷寒雨。"]'),
('f2a09a66-d683-42ca-a3cb-8a1e93ebbcf9','觀劉格非畫','林敏修','宋','宋诗','song-poetry','','[]','人言畫師非俗士，小技不妨聊戲耳。',96,'全唐诗/poet.song.60000.json','["人言畫師非俗士，小技不妨聊戲耳。", "欲搜萬象入詩句，未若丹青易盈紙。", "坐令晚景下鴻雁，力奪春工發紅紫。", "明眸破笑不作難，頃刻冰紈出西子。", "信能自適亦自累，好事終爲人所使。", "曷不窮年自寫真，奮髯箕踞走百鬼。"]'),
('708458ad-f1ae-422b-908e-baf35a63e0ef','歙硯','林敏修','宋','宋诗','song-poetry','','[]','瑟瑟方池霧縠紋，麝烟初散墨花春。',32,'全唐诗/poet.song.60000.json','["瑟瑟方池霧縠紋，麝烟初散墨花春。", "晴窗晝靜桐陰轉，筆下雲生字入神。"]'),
('27770ffc-aa47-4fe0-bcfd-600a10a757ce','送劉羲仲檢討','林敏修','宋','宋诗','song-poetry','','[]','二年食貧兒女煎，大寒客居衣裏穿。',176,'全唐诗/poet.song.60000.json','["二年食貧兒女煎，大寒客居衣裏穿。", "閉門窮巷氣不屈，誰問過午無炊烟。", "腹中萬卷自得飽，冷熱不假世人憐。", "思歸一日止舊隠，牆垣荆棘荒三椽。", "青山不肯埋妙器，幅巾却作康廬仙。", "今年再渡江北船，旋買走馬趨日邊。", "即今日月九天上，陛下旰食思求賢。", "結交老蒼半臺閣，亨衢插翼看翩翩。", "朱顔誰無起家念，壯志輸君先著鞭。", "我今憔悴類蟠木，斧斤不到終天年。", "病身無用聊自惜，對榻猶堪雨夜眠。"]'),
('178b564b-6678-460a-b535-ad1a7427b681','次韵寄檢討','林敏修','宋','宋诗','song-poetry','','[]','濟北淮南夢到稀，牢愁猶頼酒來微。',64,'全唐诗/poet.song.60000.json','["濟北淮南夢到稀，牢愁猶頼酒來微。", "欲知飯顆詩人瘦，政憶長鬚主簿肥。", "應世君方持手板，畏人我已著山衣。", "春來消息甚疏闊，徙倚高原惜寸暉。"]'),
('3f8dc26d-e44c-498e-ae45-c86818619bc6','喜到竹齋書事呈無位居士','林敏修','宋','宋诗','song-poetry','','[]','嶺上小梅初破萼，同雲作寒雪花落。',96,'全唐诗/poet.song.60000.json','["嶺上小梅初破萼，同雲作寒雪花落。", "千里南還喜見君，一杯相屬寧辭數。", "楚狂小子笑孔丘，杖屨謾學名山遊。", "二年勝景覽欲盡，贏得顔髮先驚秋。", "却歸竹下尋詩句，追講前歡禿千兔。", "竹間已有嗣宗狂，吟醉何妨陪杖屨。"]'),
('0adefaa5-f245-4028-a238-cd268a3cf404','蓮子','林敏修','宋','宋诗','song-poetry','','[]','落盡紅裳翠的生，甘泉金鑄馬蹄輕。',32,'全唐诗/poet.song.60000.json','["落盡紅裳翠的生，甘泉金鑄馬蹄輕。", "中心有意君知否，半是湘妃淚點成。"]'),
('93c53054-46b6-4582-86d1-2adabacc0ef3','句','林敏修','宋','宋诗','song-poetry','','[]','歲寒羣物慘無光。',8,'全唐诗/poet.song.60000.json','["歲寒羣物慘無光。"]'),
('7b9f651e-1045-4244-be5f-2ab0f9c4ea69','句','林膚','宋','宋诗','song-poetry','','[]','延平閣想張華劍，寶婺樓觀沈約詩。',16,'全唐诗/poet.song.60000.json','["延平閣想張華劍，寶婺樓觀沈約詩。"]'),
('6a0e27ba-c7b2-44e6-8c71-957c36184a73','落花','李陶子','宋','宋诗','song-poetry','','[]','流水難窮目，斜陽易斷腸。',24,'全唐诗/poet.song.60000.json','["流水難窮目，斜陽易斷腸。", "誰同砑光帽，一曲舞山香。"]'),
('d41ed986-7e14-44cb-b8ff-8f017325c64b','訪王主簿同泛菊茶','孫勴','宋','宋诗','song-poetry','','[]','妍暖春風蕩物華，初回午夢頗思茶。',32,'全唐诗/poet.song.60000.json','["妍暖春風蕩物華，初回午夢頗思茶。", "難尋北苑浮香雪，且就東籬擷嫩芽。"]'),
('a16f724e-6197-4447-bffd-4197b89da74c','題靖節祠  其一','孫勴','宋','宋诗','song-poetry','','[]','先生拂衣歸柴桑，視時富貴猶粃糠。',32,'全唐诗/poet.song.60000.json','["先生拂衣歸柴桑，視時富貴猶粃糠。", "義心耻食易代粟，督郵於我何低昂。"]'),
('df6b3066-3385-4202-bf71-41282e3ecd91','題靖節祠  其二','孫勴','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','五字高吟酒一瓢，廬山千載想風標。',32,'全唐诗/poet.song.60000.json','["五字高吟酒一瓢，廬山千載想風標。", "至今門外青青柳，似向東風懶折腰。"]'),
('ac307d76-c2d4-4acd-82bd-a47e6cae1579','玉枕石','楊槱','宋','宋诗','song-poetry','','[]','棧道險復險，客懷愁更愁。',24,'全唐诗/poet.song.60000.json','["棧道險復險，客懷愁更愁。", "萬山俱絕壁，一水不通舟。"]'),
('3ca21a57-ab04-4177-85e8-d5f72bd102d6','題寶雞縣','陶應','宋','宋诗','song-poetry','','[]','雪樓當月動清寒，渭水梁山鳥外看。',32,'全唐诗/poet.song.60000.json','["雪樓當月動清寒，渭水梁山鳥外看。", "聞說德宗曾到此，吟詩不敢倚欄干。"]'),
('710df030-2c19-4aaa-8d9c-278746190ca8','三德院','岑碩','宋','宋诗','song-poetry','','[]','齊朝立蘭若，曾廢會昌初。',48,'全唐诗/poet.song.60000.json','["齊朝立蘭若，曾廢會昌初。", "佛法滅不得，僧徒還此居。", "無碑傳古昔，有樹老扶疏。", "門外滌塵水，寒光浸太虛。"]'),
('b585a366-8d13-444c-bd8a-390f833c04d8','句  其一','岑碩','宋','宋诗','song-poetry','','[]','金屋暖猶積，玉關寒更深。',12,'全唐诗/poet.song.60000.json','["金屋暖猶積，玉關寒更深。"]'),
('d56dc405-c8d8-4db6-ab68-caa2447dfedf','句  其二','岑碩','宋','宋诗','song-poetry','','[]','伯噽肆讒吻，夫差失霸圖。',12,'全唐诗/poet.song.60000.json','["伯噽肆讒吻，夫差失霸圖。"]'),
('49026e93-7f8f-48a0-b037-186b02948d76','句  其三','岑碩','宋','宋诗','song-poetry','','[]','極目又芳草，捲簾非故山。',12,'全唐诗/poet.song.60000.json','["極目又芳草，捲簾非故山。"]'),
('1b0203b0-75b1-4553-a713-3a3df3285236','偈三首  其一','釋祖瑃','宋','宋诗','song-poetry','','[]','道無定亂，法離見知。',52,'全唐诗/poet.song.60000.json','["道無定亂，法離見知。", "言句相投，都無定義。", "自古龍門無宿客，至今鳥道絕行蹤。", "欲會箇中端的意，火裏蝍蟟吞大蟲。"]'),
('745019ea-0fca-4272-93a0-7948c4bb2308','偈三首  其二','釋祖瑃','宋','宋诗','song-poetry','','[]','雨下階頭濕，晴乾水不流。',24,'全唐诗/poet.song.60000.json','["雨下階頭濕，晴乾水不流。", "鳥巢滄海底，魚躍石山頭。"]'),
('1cc61f48-d961-40a3-92ad-db6cc56a78b3','偈三首  其三','釋祖瑃','宋','宋诗','song-poetry','','[]','祗見石磊磊，不見玉落落。',24,'全唐诗/poet.song.60000.json','["祗見石磊磊，不見玉落落。", "若見玉落落，方知道寬廓。"]'),
('669aa86c-c93e-420c-818b-1283a37bb21e','偈','釋聞一','宋','宋诗','song-poetry','','[]','拈花微笑虛勞力，立雪齊腰枉用功。',32,'全唐诗/poet.song.60000.json','["拈花微笑虛勞力，立雪齊腰枉用功。", "爭似老盧無用處，却傳衣鉢振真風。"]'),
('fa89fad3-b319-4640-aba2-d841821860c3','偈','釋惟爽','宋','宋诗','song-poetry','','[]','今朝六月旦，一年已過半。',48,'全唐诗/poet.song.60000.json','["今朝六月旦，一年已過半。", "奉報參玄人，識取娘生面。", "娘生面，薦不薦。", "鷺鷥飛入碧波中，抖擻一團銀繡線。"]'),
('09433c45-1008-4de9-8cc4-febf0cae104f','偈','念禪師','宋','宋诗','song-poetry','','[]','往復無際，動靜一源。',63,'全唐诗/poet.song.60000.json','["往復無際，動靜一源。", "含有德以還空，越無私而迥出。", "昔日日，今日日，照無兩明。", "昔日風，今日風，鼓無兩動。", "昔日雨，今日雨，澤無兩潤。"]'),
('f6308685-ce90-4f94-b253-303f0c21e1e8','頌三首  其一','念禪師','宋','宋诗','song-poetry','','[]','元正一，古佛家風從此出。',28,'全唐诗/poet.song.60000.json','["元正一，古佛家風從此出。", "不勞向上用工夫，歷劫何曾異今日。"]'),
('1d478e02-6429-40dd-9e2b-371de3c7c2e8','頌三首  其二','念禪師','宋','宋诗','song-poetry','','[]','元正二，寂寥冷淡無滋味。',28,'全唐诗/poet.song.60000.json','["元正二，寂寥冷淡無滋味。", "趙州相喚喫茶來，剔起眉毛須瞥地。"]'),
('62f77fa0-6a3d-4905-aa92-79d33919afdd','頌三首  其三','念禪師','宋','宋诗','song-poetry','','[]','元正三，上來稽首各和南。',28,'全唐诗/poet.song.60000.json','["元正三，上來稽首各和南。", "若問香山山裏事，靈源一派碧如藍。"]'),
('5308aeab-4450-4f5e-aca2-dbfd620c07f1','頌','什庵主','宋','宋诗','song-poetry','','[]','我有一柄拂子，用處別無調度。',28,'全唐诗/poet.song.60000.json','["我有一柄拂子，用處別無調度。", "有時挂在松枝，任他頭垂角露。"]'),
('46c3c718-e9c0-403e-b825-189786865ac3','贊法如禪師','釋圓極','宋','宋诗','song-poetry','','[]','生鐵面皮難湊泊，等閒舉步動乾坤。',32,'全唐诗/poet.song.60000.json','["生鐵面皮難湊泊，等閒舉步動乾坤。", "戲拈十智同真話，不負黄龍嫡骨孫。"]'),
('9667ce2d-63a0-4254-bbe6-ecfbe8c1d30a','頌','張戒','宋','宋诗','song-poetry','','[]','天不戴兮地不知，誰言南北與東西。',32,'全唐诗/poet.song.60000.json','["天不戴兮地不知，誰言南北與東西。", "身眠大海須彌枕，石笋抽條也大奇。"]'),
('b6bad12e-fd66-4afb-847e-b4e840c5e74f','西歸','晁端中','宋','宋诗','song-poetry','','[]','安得龍山潮，駕迴馬河水。',24,'全唐诗/poet.song.60000.json','["安得龍山潮，駕迴馬河水。", "水從樓前來，中有美人淚。"]'),
('8dc3dc42-fd01-45be-973e-2859e3d3c387','資聖院','孫諤','宋','宋诗','song-poetry','','[]','四山藏一寺，方丈壓諸峰。',24,'全唐诗/poet.song.60000.json','["四山藏一寺，方丈壓諸峰。", "回首坐禪處，白雲深幾重。"]'),
('3f36a11e-6db1-4a5d-844d-49fd3b2b68f9','題江濱驛','孫諤','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','渡江始至長江縣，返照雨餘村落明。',32,'全唐诗/poet.song.60000.json','["渡江始至長江縣，返照雨餘村落明。", "此地曾經詩客到，九秋風月至今清。"]'),
('6510faf6-7c5f-4191-8d63-73e7dcd1e250','文州','孫諤','宋','宋诗','song-poetry','','[]','烟籠合處日華明，龍女山橫擁郡城。',32,'全唐诗/poet.song.60000.json','["烟籠合處日華明，龍女山橫擁郡城。", "番馬遠隨流水至，邊人高入白雲耕。"]'),
('89ab5aaf-ff57-496d-9157-e7d3190b2a04','句','孫諤','宋','宋诗','song-poetry','','[]','秋空獨見周王廟，夜月猶懸蜀將營。',16,'全唐诗/poet.song.60000.json','["秋空獨見周王廟，夜月猶懸蜀將營。"]'),
('c9ba12f0-cb66-4f6d-8045-bc514d8cf3ef','題清芬閣','臧詢','宋','宋诗','song-poetry','','[]','舊隠固瀟灑，先生偏苦吟。',48,'全唐诗/poet.song.60000.json','["舊隠固瀟灑，先生偏苦吟。", "俗情隨水落，雅趣與山深。", "白日自朝暮，清風無古今。", "遠孫簪組盛，終有愛閑心。"]'),
('500d7edd-f7ef-4e74-a9a0-7585e0246b30','自漣漪寄薛紹彭','米芾','宋','宋诗','song-poetry','','[]','老來書興獨未忘，頗得薛老同徜徉。',192,'全唐诗/poet.song.60000.json','["老來書興獨未忘，頗得薛老同徜徉。", "天下有識推鑒定，龍宮無術療膏肓。", "淮風吹戟稀訟牒，典客閉閣閑壺漿。", "吟樹對山風景聚，墨池濯硯龜魚藏。", "珠臺寶氣每貫日，月觀桂實時飄香。", "銀淮燭天限織女，烟海括地生靈光。", "儁兒乃是翰墨侶，俠竹不使輿衛將。", "象管鈿軸映瑞錦，玉鱗棐几鋪雲肪。", "依依烟華動勃鬰，矯矯龍蛇起混茫。", "持此以爲風月伴，四時之樂樂未央。", "部刺不糾翰墨病，聖恩養在林泉鄉。", "風沙漲天烏帽客，胡不東來從北荒。"]'),
('1de68b5f-0ab6-4345-82f5-7c036014ca63','寄薛紹彭','米芾','宋','宋诗','song-poetry','','[]','歐怪褚妍不自持，猶能半蹈古人規。',144,'全唐诗/poet.song.60000.json','["歐怪褚妍不自持，猶能半蹈古人規。", "公權醜怪惡札祖，從茲古法蕩無遺。", "張顛與柳頗同罪，鼓吹俗子起亂離。", "懷素猲獠小解事，僅趨平淡如盲醫。", "可憐智永研空臼，去本一步呈千媸。", "已矣此生爲此困，有口能說手不隨。", "誰云心存乃筆到，天工自是祕精微。", "二王之前有高古，有志欲購無高貲。", "殷勤分付薛紹彭，散金購取重跋題。"]'),
('030597b3-704e-45a0-9e3c-9bdfd62d421d','寄題薛紹彭新收錢氏子敬帖','米芾','宋','宋诗','song-poetry','','[]','蕭李騃子弟，不收慰問帖。',60,'全唐诗/poet.song.60000.json','["蕭李騃子弟，不收慰問帖。", "妙迹固通神，水火土更劫。", "所存慰問者，班班在箱笈。", "使惡乃神護，不然無寸札。", "自此趣畫相，後人眼徒眨。"]'),
('53b17078-cf5f-4b48-b49a-85d24045a8bd','硾越竹學書作詩寄薛紹彭劉涇','米芾','宋','宋诗','song-poetry','','[]','越筠萬杵如金版，安用杭油與池繭。',64,'全唐诗/poet.song.60000.json','["越筠萬杵如金版，安用杭油與池繭。", "高壓巴郡烏絲欄，平欺澤國清華練。", "老無他物適心目，天使殘年同筆硯。", "圖書滿室翰墨香，劉薛何時眼中見。"]'),
('181510f9-8f7b-46ca-b4c4-efbbf8c1ccdd','劉涇收得子鸞字帖云是右軍余恐是陳子鸞薛紹彭亦云六朝書又得像余時在漣漪答以詩云','米芾','宋','宋诗','song-poetry','','[]','劉郎收畫早甚卑，折枝花草首徐熙。',176,'全唐诗/poet.song.60000.json','["劉郎收畫早甚卑，折枝花草首徐熙。", "十年之後始聞道，取吾韓戴爲神奇。", "邇來白首進道奧，學者信有髓與皮。", "始知什襲但遮壁，牛馬便可裹敝帷。", "峨峨太平老寺主，白紗帽首無冠蕤。", "武士後列肅大劍，宮女旁侍顰脩眉。", "神清眸子知寡慾，齒露唇反法定饑。", "世人見服似摩詰，不知六朝居士衣。", "後人勿輒亂唐突，梁人筆法了可知。", "道子見之必再拜，曹盧何物望藩籬。", "本當第一品天下，却緣顧筆在漣漪。"]'),
('650ea050-3a84-4039-a718-0878b73dc6a5','劉涇新收唐絹本蘭亭作詩詢之','米芾','宋','宋诗','song-poetry','','[]','劉郎無物可縈心，沉迷蠹縑與斷簡。',64,'全唐诗/poet.song.60000.json','["劉郎無物可縈心，沉迷蠹縑與斷簡。", "求新不獲狂時發，自謂下取且謾眼。", "猗嗟斯人今實尠，我欲從之官有限。", "何時大叫劉子前，跽閱墨皇三復返。"]'),
('5fe4bc0b-b0b6-4aaa-bbde-c1474a714af1','題蘇中令家故物薛稷鶴','米芾','宋','宋诗','song-poetry','','[]','遼海來稀顧螻蟻，仰霄孤唳留清耳。',128,'全唐诗/poet.song.60000.json','["遼海來稀顧螻蟻，仰霄孤唳留清耳。", "從容雅步在庭除，浩蕩閒心存萬里。", "乘軒未失入佳談，寫真不妄傳詩史。", "好藝心靈自不凡，臭穢功名皆一戲。", "武功中令應天人，束髮遼陽侍帝宸。", "連城照乘不稱寶，黄圖孔誥悉珍真。", "百齡生我欲公起，九原蕭蕭松薿薿。", "得公遺物非不多，賞物懷賢心不已。"]'),
('e778cb02-79d5-496d-b3a4-dce265d7709a','題子敬范新婦唐摹帖三首  其一','米芾','宋','宋诗','song-poetry','','[]','貞觀款書丈二紙，不許兒奇專父美。',64,'全唐诗/poet.song.60000.json','["貞觀款書丈二紙，不許兒奇專父美。", "何爲寥寥寶是似，遭亂真歸火兼水。", "千年誰人能繼趾，不自名家殊未智。", "嗟爾方來眼須洗，玉躞金題半歸米。"]'),
('5df3f669-7674-4772-a69f-36186f206d9a','題子敬范新婦唐摹帖三首  其二','米芾','宋','宋诗','song-poetry','','[]','雲物龍蛇慘動紙，父子王家真濟美。',64,'全唐诗/poet.song.60000.json','["雲物龍蛇慘動紙，父子王家真濟美。", "庾翼小兒寧近似，滄溟浩對蹄涔水。", "騰蛇無足蜈多趾，以假移真信用智。", "龜澼雖多手屢洗，卷不生毛誰似米。"]'),
('0559e5e7-c998-43d4-922a-5708271385e7','題子敬范新婦唐摹帖三首  其三','米芾','宋','宋诗','song-poetry','','[]','直裂紋勻真古紙，跋印多時俗眼美。',64,'全唐诗/poet.song.60000.json','["直裂紋勻真古紙，跋印多時俗眼美。", "誠懸尚復誤疑似，有渭方能辨涇水。", "真僞頭面摸趺趾，久假中分辨愚智。", "寶軸時開心一洗，百氏何人傳至米。"]'),
('9dccc23d-7b52-4d17-b2e8-d10dde5023d2','蕭閒堂詩','米芾','宋','宋诗','song-poetry','','[]','誰起蕭閒堂，圖贊凡醜質。',160,'全唐诗/poet.song.60000.json','["誰起蕭閒堂，圖贊凡醜質。", "昧昧起我思，有懷斯士吉。", "吾生終不逢，二陵已相失。", "苟養走四方，公卿更絕迹。", "向老交漸稀，背憎十六七。", "豐吾九畹蘭，任汝滿地棘。", "我豈蕭閒人，偶然得空壁。", "美哉何方彥，精絕入妙筆。", "君不愧顧長康，取媚桓溫圖九錫。", "我不愧孟浩然，緩策京山遇摩詰。", "前此交道久不康，紛紛白頭多不卒。", "嗚呼紛紛白頭多不卒，回首此君應辟易。"]'),
('501aac58-4cd1-432e-b383-02c80a138e9d','甘露歌上呈留守門下侍郎','米芾','宋','宋诗','song-poetry','','[]','太微淵默嚴不動，斗爲其車運中央。',156,'全唐诗/poet.song.60000.json','["太微淵默嚴不動，斗爲其車運中央。", "四序回旋變造化，一杓直指無偏傍。", "柄臣比之號八柱，一柱難闕各有當。", "紹聖元年圖舊德，更公玉麟使過國。", "屹然山立天子重，列作八柱扶天極。", "天極尊嚴物有道，不減不溢常不忒。", "均勞於外天闕柱，至今朝廷虛衮舄。", "皇皇辟君明如日，安用動威偃禾木，表以甘露太和液。", "飲太液，親壽益，公難老，歸致太平萬物好。"]'),
('a530dd81-dc0d-4417-90f7-f16401ef6d5e','某頓首今日去國之官謹成拙詩上獻相公汲公鈞席下執某頓首上','米芾','宋','宋诗','song-poetry','','[]','百尺青琅玕，浸以萬丈瀾。',288,'全唐诗/poet.song.60000.json','["百尺青琅玕，浸以萬丈瀾。", "我欲擷柯梗，一蠡酌知難。", "屢亦爲世有，豈不詰其端。", "嶷嶷呂汲公，捧日當碧天。", "簡直抱一氣，代理夫何言。", "有志隆宋業，無心崇黨偏。", "透璞辨珉玉，披蓁刈蘭蓀。", "腐儒自束髮，口誦六藝言。", "治亂甚白著，用舍豈一賢。", "明時貴知用，自古遲暮年。", "敢陳必堯舜，况時值媧軒。", "豈徒琢空文，文姦籠羣頑。", "汩沒俗眼順，妬嫉兒女諼。", "竊取爲利路，死棄等草菅。", "朝哦不求和，暮吟不揭竿。", "不歎歲不與，惟恐枉所存。", "願披向龜鑑，大叫出肺肝。", "精誠露皎皎，洞徹金石堅。", "康濟有次第，沿革自貫穿。", "刪除救災法，下民不棄田。", "剔抉經費壅，源源如流泉。", "思豫近習隙，不紊出納專。", "正姓以明本，捐賞以運邊。", "改弊貴無迹，移風當有筌。"]'),
('b7d4821d-fab6-478c-803c-f3052027b2b9','元祐辛未上元後一日同周文之劉瑞邁章縱矩游浮玉','米芾','宋','宋诗','song-poetry','','[]','近臈昔夾衣，入春今重裘。',192,'全唐诗/poet.song.60000.json','["近臈昔夾衣，入春今重裘。", "天運亦已廣，四序或不周。", "張燈兒戲歇，發興在滄洲。", "茲山通玄府，瑶壇帝曾遊。", "荷衣可薦藻，神清不沉牛。", "厭俗入喧亂，風波屢爲憂。", "昨夕浄名天，結客湧不留。", "一唈寄心契，江澄客漾舟。", "冰磴若見拒，寒荄如有愁。", "大塊欲動蟄，陰壑尚潜虬。", "重賞定誰與，春光會和柔。", "臨曠攝北若，持坏結東流。", "卧石带白雲，勒崖託千秋。", "焦公心賞佳，掃跡願相投。", "分山飛鳥爭，劃水遊鱗讎。", "借我一錫地，爲公瓢掛頭。"]'),
('bf1b6798-3b52-4946-ab51-0b6326ae08db','題永徽中所橅蘭亭敘','米芾','宋','宋诗','song-poetry','','[]','永和九年暮春月，內史山陰幽興發。',112,'全唐诗/poet.song.60000.json','["永和九年暮春月，內史山陰幽興發。", "羣賢題詠無足珍，敘引抽毫取奇札。", "好之寫來終不如，神助留爲後世法。", "二十八行三百字，模寫雖多誰定似。", "昭陵竟發不知歸，尚有異形終可秘。", "彥遠記模不記褚，要錄班班有名氏。", "後生有得苦求高，俗說紛紛那有是。"]'),
('b115e874-5a5c-41e3-b8be-ebccea9d14e8','太師行寄王太史彥舟','米芾','宋','宋诗','song-poetry','','[]','太師天源環賜第，自榜回鸞鴉雀避。',384,'全唐诗/poet.song.60000.json','["太師天源環賜第，自榜回鸞鴉雀避。", "好賓嗜古富圖書，玉軸牙籤捧珠翠。", "歌舞陳前慰俗人，不傾玉瀝發銀縢。", "王郎十八魁天下，招客同延貴客星。", "末出東晉十三帖，此第十一石藴瓊。", "絹標間是褚公寫，誤以右軍標作謝。", "我時指出一座驚，精神煥起光相射。", "磨墨要余定等差，謝公鬰勃冠烟華。", "當時傾笈換不得，歸來嘔血目生花。", "十五年間兩到國，朱門如舊無高牙。", "帖歸翰長以姻媾，忽然陳前興健嗟。", "開元璽封尋復出，永存珍秘相王涯。", "翰林印著建中歲，王謝炎靈傳更貴。", "副車侍中王貽永，出征不貨收文藝。", "太常借模真却還，郗愔入版餘皆棄。", "芳林鬻第書有行，次入太師重姓李。", "我識翰長自布衣，論文寫字不相非。", "知己酷好輟己好，惠然發篋手見歸。", "謝安談笑康江左，物外人標沒兩大。", "子敬合書只後批，天才物望都無那。", "治亂悠悠八百年，人隆偶聚散亦遄。", "兵火水土不隨劫，端使米老鋪案間。", "我生辛卯兩丙運，今歲步辛月亦然。", "丙申時宜辛丑日，此帖忽至庸非天。"]'),
('afaeb622-81b9-4d4f-a56c-da0d324d073e','天雞','米芾','宋','宋诗','song-poetry','','[]','天雞一叫凡雞和，戢戢萬靈驚起坐。',64,'全唐诗/poet.song.60000.json','["天雞一叫凡雞和，戢戢萬靈驚起坐。", "智驅慾使心機大，狗苟蠅營冀人墮。", "沉沉夜色還東起，身伏氈莞機暫止。", "昧昧萬殊俱默契，窮達於君寧智理。"]'),
('17f3b202-d8a6-47a1-a130-256389c21e63','晉陵龍掛行','米芾','宋','宋诗','song-poetry','','[]','萬聲齊呼一聲嚇，東望蒼旻兩龍掛。',80,'全唐诗/poet.song.60000.json','["萬聲齊呼一聲嚇，東望蒼旻兩龍掛。", "浩浩隨雲百川倒，隠隠雷車千兩駕。", "疲農望天手加顙，怕歉求豐心惘惘。", "老龍甲坼血流莽，取水雖多旱彌廣。", "暴尪囚魃精誠微，赫赫炎曦一輪榜。"]'),
('71a8b6c2-0757-4fdf-8b1d-2bcec980e885','題巨然海野圖','米芾','宋','宋诗','song-poetry','','[]','江郊海野坡陀闊，林遠烟疏淡天末。',128,'全唐诗/poet.song.60000.json','["江郊海野坡陀闊，林遠烟疏淡天末。", "枰分蓁町暮潮生，星列漁鄉夜梁活。", "關荆大圖矜秀拔，取巧施工不真絕。", "意全萬象無不括，維摩老手巨然奪。", "橋防忽覺來人物，接䍦肯更圖牛羯。", "淵渟浪洑開龍閱，汩入瀣翻下鯨吷。", "楠盤疑是少陵宅，蘆深恐有詹何客。", "黄塵蔽天歸興浩，時向虛齋一開滌。"]'),
('c2e69ddd-5d7f-42a6-bef2-9494ec53b339','硯山','米芾','宋','宋诗','song-poetry','','[]','九江有奇石，趺岱而嵩頭。',132,'全唐诗/poet.song.60000.json','["九江有奇石，趺岱而嵩頭。", "巨靈藐一擘，嶕嶢憶三休。", "屹嶪稟異質，嶒崚誰刻鏤。", "百疊天巧盡，九盤猿未愁。", "陽壁宜産芝，陰崖諒潜虬。", "危顛方壇結，玉秘金泥脩。", "垂手探杲日，朱輪運滄洲。", "一塵具一界，妙喜非難求。", "心欲躡赤霄，八極皆部婁。", "况茲對衆物，其致一揆收。", "啑啑分別子，交戈舂其喉。"]'),
('0ea56095-17b3-4215-bffa-7cf9d01f4b18','發潤州','米芾','宋','宋诗','song-poetry','','[]','氣就蛇須角，暌通豕負塗。',144,'全唐诗/poet.song.60000.json','["氣就蛇須角，暌通豕負塗。", "解衣同俗裸，酌水合狂夫。", "探社新銘禹，經韶舊弔虞。", "據鞍休示壯，寡要悔爲儒。", "爲弔忠遊楚，因崇讓過虞。", "要離葬終近，嚴子釣行須。", "御晏妻知辱，歆膺客自愚。", "誠修日難掩，醯在蚋還趨。", "和寡方聲越，知稀覺道腴。", "命齊都將相，義拙落江湖。", "南夢應隨雁，西風却背鱸。", "弓旌今正歇，多少定同鳬。"]'),
('249c4cd0-2400-47cd-8412-58531be034a9','讀杜甫集','米芾','宋','宋诗','song-poetry','','[]','少陵平生饑，乃以醉飽死。',120,'全唐诗/poet.song.60000.json','["少陵平生饑，乃以醉飽死。", "惜哉斯人窮，四海無寄趾。", "後傳水仙召，牛渚花相比。", "神怪反愛才，時人乃封豕。", "遺文何崛奇，岱輿載屭贔。", "貫穿破九流，突兀撐一氣。", "自嘆萬古名，寂寞身後事。", "此老遑遑心，懸鶉破無裏。", "我行自嘉禾，卧欹一蓬底。", "烈曦畏俄中，開卷爲磨洗。"]'),
('0acd5a44-7e9a-4fde-b59f-74dbc0ec352d','東坡居士作水陸於金山相招足瘡不能往作此以寄之','米芾','宋','宋诗','song-poetry','','[]','久陰障奪佳山川，長瀾四溢魚龍淵。',64,'全唐诗/poet.song.60000.json','["久陰障奪佳山川，長瀾四溢魚龍淵。", "衆看李郭渡浮玉，晴風掃出清明天。", "頗聞妙力開大施，足病不列諸方仙。", "想應蒼壁有垂露，照水百怪愁寒烟。"]'),
('691f2298-ef3a-47f1-a638-1ed9229ffc10','栖雲閣','米芾','宋','宋诗','song-poetry','','[]','雲出救世旱，澤浹雲尋歸。',48,'全唐诗/poet.song.60000.json','["雲出救世旱，澤浹雲尋歸。", "入石了不見，豐功已如遺。", "龍騫薦復起，抱石明幽姿。", "雲乎無定所，隠者當何栖。"]'),
('8eeab98d-b64e-45f9-bb96-ee7b9d3d03e0','過虎關','米芾','宋','宋诗','song-poetry','','[]','憑軾下虎關，揚舲下清洛。',96,'全唐诗/poet.song.60000.json','["憑軾下虎關，揚舲下清洛。", "川神秘幽姿，靈介破大樸。", "壯哉河山固，皆是大禹鑿。", "舟人歌大禹，水怪不敢作。", "功宣欲萬祀，人望只如昨。", "短哦復長詠，豪舉亦哀噱。", "夢寐三川勝，使事少行樂。", "無雨洗嵩少，春烟淡寥廓。"]'),
('21f36497-bfe4-4214-bd15-f8d5277cb26b','答紹彭書來論晉帖誤字','米芾','宋','宋诗','song-poetry','','[]','何必識難字，辛苦笑揚雄。',48,'全唐诗/poet.song.60000.json','["何必識難字，辛苦笑揚雄。", "自古寫字人，用字或不通。", "要之皆一戲，不當問拙工。", "意足我自足，放筆一戲空。"]'),
('4202bdf5-6a8c-4b27-9bf7-8b0274da0c32','甘露寺悼古','米芾','宋','宋诗','song-poetry','','[]','色改重重構，春歸戶戶嵐。',48,'全唐诗/poet.song.60000.json','["色改重重構，春歸戶戶嵐。", "槎浮龍委骨，畫失獸遺耽。", "神護衛公塔，天留米老菴。", "栢梁終厭勝，會副越人談。"]'),
('8a21051c-de4f-4db3-81d2-ed601c525cdf','題麟鳳碑','米芾','宋','宋诗','song-poetry','','[]','非篆非科璞已彫，形容振振與蕭蕭。',64,'全唐诗/poet.song.60000.json','["非篆非科璞已彫，形容振振與蕭蕭。", "曾因忠厚方周德，坐想訏謨覽舜韶。", "漢德已衰還應孽，魯邦既弱不爲妖。", "虛齋自是驚人玩，不勝雄狐逐怒鵰。"]'),
('33a3184f-3da7-4418-af62-1bceb877aad7','題南昌縣君臨偃竹','米芾','宋','宋诗','song-poetry','','[]','偃蹇宜如季，揮毫已逼翁。',48,'全唐诗/poet.song.60000.json','["偃蹇宜如季，揮毫已逼翁。", "衛書無曲妙，琰慧有遺工。", "乍睹虬如物，初披颯有風。", "顧藏維謹鑰，化去或難窮。"]'),
('8383f744-6f81-4f95-ba18-d56a8d074dfa','詩送吳丈賓州使君元豐乙未長沙掾舍真禧道館書','米芾','宋','宋诗','song-poetry','','[]','萬里相分又一時，憐君身世半差池。',64,'全唐诗/poet.song.60000.json','["萬里相分又一時，憐君身世半差池。", "老來猶得安城守，夜召尚淹宣室思。", "越嶺寒橫迎吏謁，荆雲暮合燕歸遲。", "江湖還送天涯客，憔悴江湖更別離。"]'),
('13e4f7aa-af05-41e6-ac95-09cab2c776ca','送大夫孫公鎮東陽','米芾','宋','宋诗','song-poetry','','[]','照地干旄十丈長，大皇孫子守東陽。',64,'全唐诗/poet.song.60000.json','["照地干旄十丈長，大皇孫子守東陽。", "吳濤卷海銀爲幔，郢雪飛英錦作章。", "無事笙簫開客館，有情山水聚衙床。", "樓中惡語須磨鏟，盡把新題換沈郎。"]'),
('1d3dfed1-13d1-407d-869e-210f576d9db0','蘇東坡輓詩五首  其一','米芾','宋','宋诗','song-poetry','','[]','方瞳正碧貌如圭，六月相逢萬里歸。',64,'全唐诗/poet.song.60000.json','["方瞳正碧貌如圭，六月相逢萬里歸。", "口不談時經噩夢，心常懷蜀俟秋衣。", "可憐衆熱偏能捨，自是登真限莫違。", "書到鄉人望還舍，晉陵玄鶴已孤飛。"]'),
('856b95fe-52fd-41fd-95fe-cb4927d5db61','蘇東坡輓詩五首  其二','米芾','宋','宋诗','song-poetry','','[]','淋漓十幅草兼真，玉立如山老健身。',64,'全唐诗/poet.song.60000.json','["淋漓十幅草兼真，玉立如山老健身。", "夢裏赤猿真月紀，興前白鳳似年辰。", "將尋賀監船虛返，欲近要離烈可親。", "忍死來還天有意，免稱聖代殺文人。"]'),
('1e64a2d2-95d4-4ffa-9d17-e3a283507364','蘇東坡輓詩五首  其三','米芾','宋','宋诗','song-poetry','','[]','小冠白㲲步東園，原是青城欲度仙。',64,'全唐诗/poet.song.60000.json','["小冠白㲲步東園，原是青城欲度仙。", "六合著名猶似窄，八周禦魅訖能旋。", "道如韓子頻離世，文比歐公復並年。", "我不銜恩畏清議，束芻難致淚潸然。"]'),
('6327cf83-4d2e-4519-b2e0-af88c9c29797','蘇東坡輓詩五首  其四','米芾','宋','宋诗','song-poetry','','[]','平生出處不同塵，末路相知太息頻。',64,'全唐诗/poet.song.60000.json','["平生出處不同塵，末路相知太息頻。", "力疾來辭如永訣，古書跋贊許猶新。", "荆州既失三遺老，碧落新添幾侍晨。", "若誦子虛真異世，酒傭屍佞是何人。"]'),
('cc769dab-6ca1-40fe-97b3-c2d58d7404e1','蘇東坡輓詩五首  其五','米芾','宋','宋诗','song-poetry','','[]','招魂聽我楚人歌，人命由天天奈何。',64,'全唐诗/poet.song.60000.json','["招魂聽我楚人歌，人命由天天奈何。", "昔感松醪聊墮睫，今看麥飯發悲哦。", "長沙論直終何就，北海傷豪忤更多。", "曾藉南窗逃藴暑，西山松竹不堪過。"]'),
('328c10c4-4e4f-4231-a62a-9df5b8e244a0','奉陪洞霄內閣拉殊師利宿穹窿本公故寺絕類岳麓感之而作','米芾','宋','宋诗','song-poetry','','[]','湘西衣冷榻留雲，此夕還如入夢魂。',64,'全唐诗/poet.song.60000.json','["湘西衣冷榻留雲，此夕還如入夢魂。", "六月薜蘿嗟我欲，一生林壑與心論。", "吳王舊賞今何有，惠可餘光宛若存。", "對榻深堂清話歇，長風快雨洗松門。"]'),
('456b4fa1-d3dc-4f44-b26e-b61d78ac1758','浮玉亭','米芾','宋','宋诗','song-poetry','','[]','石赤表雄名，三辰出濁清。',72,'全唐诗/poet.song.60000.json','["石赤表雄名，三辰出濁清。", "江澄天上見，鰲負水中行。", "瑞像浮溟海，殊香下玉京。", "神靈禮金碧，梵力度幽明。", "揭榜訛浮玉，莊嚴是化城。", "壯哉夜潮落，入枕百川聲。"]'),
('51bb7de5-61c1-47d1-886c-532fd97f7273','紹聖二年八月十八日觀潮於浙江亭書','米芾','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','怒勢豪聲迸海門，州人傳是子胥魂。',64,'全唐诗/poet.song.60000.json','["怒勢豪聲迸海門，州人傳是子胥魂。", "天排雲陣千雷震，地捲銀山萬馬奔。", "高與月輪參朔望，信如壺漏報朝昏。", "吳爭越戰成何事，一曲漁歌過遠村。"]'),
('bba51a0d-7d6b-4f05-aeaf-4c08978929e4','山林堂','米芾','宋','宋诗','song-poetry','','[]','洗竹延清景，培松衛歲芳。',48,'全唐诗/poet.song.60000.json','["洗竹延清景，培松衛歲芳。", "好峰多漾翠，嘉卉襲人香。", "犀玉開書札，龍蛇起混茫。", "微風北窗卧，真可上羲皇。"]'),
('452bed9f-fa95-49f8-8e88-d03074e90a74','浄名二首  其一','米芾','宋','宋诗','song-poetry','','[]','山晚烟棲樹，漁收鷺宿沙。',48,'全唐诗/poet.song.60000.json','["山晚烟棲樹，漁收鷺宿沙。", "曲生初月魄，遠淡滿川霞。", "依靜家如寺，游頻寺是家。", "何須傳大士，芰製著袈裟。"]'),
('82a991e9-fb5d-47fa-978d-bd19796a31a1','浄名二首  其二','米芾','宋','宋诗','song-poetry','','[]','縱目天容曠，披襟海共開。',48,'全唐诗/poet.song.60000.json','["縱目天容曠，披襟海共開。", "山形當檻走，雲影度江來。", "世界慚雙足，生涯付一杯。", "橫風多景夢，壺領酌泉迴。"]'),
('9227b30d-d1c3-4820-9625-63caa8066ca7','除書學博士呈時宰','米芾','宋','宋诗','song-poetry','','[]','半生湖海看青山，慣佩笭箵攬轡艱。',64,'全唐诗/poet.song.60000.json','["半生湖海看青山，慣佩笭箵攬轡艱。", "曉起初馳朱雀路，霜華慚綴紫宸班。", "百寮卑處瞻丹陛，五色光中望玉顔。", "浪說書名落人世，非公那解徹天關。"]'),
('bbc817dd-b1ec-4b8b-9f73-3449b09eda2e','送沂州使君納政榮歸','米芾','宋','宋诗','song-poetry','','[]','神强體健頰猶朱，犀虎輕拋憶舊廬。',64,'全唐诗/poet.song.60000.json','["神强體健頰猶朱，犀虎輕拋憶舊廬。", "明月滿船常伴畫，素風傳世莫非書。", "湧金門外秋長老，有美堂前錦不如。", "預想容觀春色好，靈龜舞鶴引安車。"]'),
('14a1d8ec-3479-4eec-8f25-1625487e985a','送水丘先生入都','米芾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','垂虹秋色醉題詩，徑及銀濤濯酒巵。',64,'全唐诗/poet.song.60000.json','["垂虹秋色醉題詩，徑及銀濤濯酒巵。", "雅謔高談傾國士，英風俠氣嚇吳兒。", "五侯倒屣重前席，三歲專經却下帷。", "早作黄金買嵩少，西湖逸客有心期。"]'),
('4752a1ca-abfd-4a61-884b-3c8e2f91f242','送潘景純','米芾','宋','宋诗','song-poetry','','[]','五年相遇一行頻，笑佩笭箵望塞雲。',64,'全唐诗/poet.song.60000.json','["五年相遇一行頻，笑佩笭箵望塞雲。", "曼倩未應徒爲米，仲宣何事樂從軍。", "開尊共喜身强健，秣馬還驚歲杪分。", "此別固應尤作惡，天涯老去與誰羣。"]'),
('0c27052f-6050-4515-b6b2-07351df7d53a','登棲靈塔','米芾','宋','宋诗','song-poetry','','[]','清露濕衣裳，心遐拉大荒。',48,'全唐诗/poet.song.60000.json','["清露濕衣裳，心遐拉大荒。", "想雷雲上見，覺蟻蔀中藏。", "地獻山川秘，天開日月光。", "太阿常耿介，未敢暫徬徨。"]'),
('7662f325-41bc-428d-8011-081c2f757c05','將行戲呈彥楚彥昭彥舟','米芾','宋','宋诗','song-poetry','','[]','沉沉靜境在人寰，樓殿蒼巒指顧間。',64,'全唐诗/poet.song.60000.json','["沉沉靜境在人寰，樓殿蒼巒指顧間。", "棄汝又成朝北闕，杜門安得老西山。", "朱金有命趨時拙，窮達忘懷枉道難。", "主相聖賢公路啟，長裾重曳舊青氈。"]'),
('21c76c7a-f46d-4274-8ae5-45c834b27e3a','遊山光寺','米芾','宋','宋诗','song-poetry','','[]','竹圍杉徑晚風清，又入山光寺裏行。',64,'全唐诗/poet.song.60000.json','["竹圍杉徑晚風清，又入山光寺裏行。", "一一過僧談舊事，遲遲繞壁認題名。", "仙來石伴懷灰劫，鶴語池邊勸後生。", "三十年間成底事，坐叨閒祿是身榮。"]'),
('73513dc4-8c7f-4071-9440-1d85de0a9309','江皋晚望','米芾','宋','宋诗','song-poetry','','[]','柳外艤舟晚，醉餘雙眼醒。',48,'全唐诗/poet.song.60000.json','["柳外艤舟晚，醉餘雙眼醒。", "水光涵一氣，星彩動圓靈。", "炯炯月初上，翛翛風更泠。", "遠山橫秀碧，淡墨說吾經。"]'),
('a4beefc4-dd95-483c-84f1-f35f40dc922f','和王彥舟','米芾','宋','宋诗','song-poetry','','[]','混塵慵走俗，陟巘喜非期。',48,'全唐诗/poet.song.60000.json','["混塵慵走俗，陟巘喜非期。", "漠漠江雨歇，溶深春水時。", "陶潜那寄傲，惠遠更能詩。", "吏自成稀闊，言歸心尚遲。"]'),
('5d42805a-9525-40fe-9e2b-c7ff8469e255','揚州作','米芾','宋','宋诗','song-poetry','','[]','春風何索寞，带雪入揚州。',48,'全唐诗/poet.song.60000.json','["春風何索寞，带雪入揚州。", "尚想遺釵雀，曾觀上玉鈎。", "真同一夢覺，坐想十年遊。", "邂逅逢孫楚，酣歌慰滯留。"]'),
('6eb0e32d-9f8c-4aa3-8a20-c6c31538d873','湖守林子中同遊道場','米芾','宋','宋诗','song-poetry','','[]','寶剎觸南箕，林幽石磴危。',48,'全唐诗/poet.song.60000.json','["寶剎觸南箕，林幽石磴危。", "雲霞隨履舄，魍魎避旌旗。", "遐寓乘新興，深尋據古詩。", "漥尊勿置酒，沆瀣已盈巵。"]'),
('17f0157f-4273-4a69-b2db-aeca43675f9b','呈王彥舟','米芾','宋','宋诗','song-poetry','','[]','吏日雖云冗，逢休樂有餘。',48,'全唐诗/poet.song.60000.json','["吏日雖云冗，逢休樂有餘。", "山林三面勝，圖史一齋虛。", "煉藥驚衰早，逢人話索居。", "傾囊收剡楮，待著鹿門書。"]'),
('326dbe3d-429b-4f9e-b30a-e4b4e0134ca3','奉酬仲微見寄之作','米芾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','倦遊湖海老侵尋，去就何情適契心。',64,'全唐诗/poet.song.60000.json','["倦遊湖海老侵尋，去就何情適契心。", "一境山林資我懶，半年風月爲君吟。", "闢開暗室成三果，選出香巒敵萬金。", "千里寄聲懷惠好，西風正隔洞庭深。"]'),
('a3d949f7-f244-4e70-849e-ebd9510af934','雜咏三首  其一','米芾','宋','宋诗','song-poetry','','[]','俠少場中酒作讎，不勝杯勺鬢今秋。',32,'全唐诗/poet.song.60000.json','["俠少場中酒作讎，不勝杯勺鬢今秋。", "道言禪語須蔬食，作意丹陽十日留。"]'),
('bc41638a-ce05-40bb-a82a-4b1d59bae598','雜咏三首  其二','米芾','宋','宋诗','song-poetry','','[]','逶迤一水出苕叢，碧底無沙冷照容。',32,'全唐诗/poet.song.60000.json','["逶迤一水出苕叢，碧底無沙冷照容。", "獨倚溪橋看風月，西山紫翠暮千重。"]'),
('9c21fe3a-d1cb-49a8-b91a-6fd5b7607cbe','雜咏三首  其三','米芾','宋','宋诗','song-poetry','','[]','霜雪迷西極，雲濤隔閬風。',24,'全唐诗/poet.song.60000.json','["霜雪迷西極，雲濤隔閬風。", "平生會心趣，都在浄名中。"]'),
('420fdf98-5d8e-40da-930c-aa560ca3ea34','垂虹亭','米芾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','斷雲一片洞庭帆，玉破鱸魚金破柑。',32,'全唐诗/poet.song.60000.json','["斷雲一片洞庭帆，玉破鱸魚金破柑。", "好作新詩吟景物，垂虹秋色滿東南。"]'),
('833d48e3-2a12-4b48-8d88-d466737a6231','去漣水','米芾','宋','宋诗','song-poetry','','[]','長日開閒境，春風美鼻雷。',24,'全唐诗/poet.song.60000.json','["長日開閒境，春風美鼻雷。", "黄紬依舊暖，牙鼓莫相催。"]'),
('d9fbfb8a-bda3-43a2-bb1c-b2a79fb36118','頻于夢中作宮詞何也漫成一首','米芾','宋','宋诗','song-poetry','','[]','滿院紅芳減復添，清微風細入重簾。',32,'全唐诗/poet.song.60000.json','["滿院紅芳減復添，清微風細入重簾。", "穠香不使朝醒快，竟日蠻沉擁繡衫。"]'),
('ef970204-0e20-4b07-8f2f-7f38ae420ed5','別吳方回弟','米芾','宋','宋诗','song-poetry','','[]','客星熠熠滑稽雄，愛著青衫自作窮。',32,'全唐诗/poet.song.60000.json','["客星熠熠滑稽雄，愛著青衫自作窮。", "澤國三年哭不死，又拖長袖揖王公。"]'),
('fbb6306d-8cb5-4252-b43d-2341120ad367','題李成畫','米芾','宋','宋诗','song-poetry','','[]','畫號爲真理或然，悠悠覺夢本同筌。',32,'全唐诗/poet.song.60000.json','["畫號爲真理或然，悠悠覺夢本同筌。", "殷勤封向青山去，要識江東李謫仙。"]'),
('7846830d-a58b-4689-bbb0-730e47a158c3','賞心亭晚望','米芾','宋','宋诗','song-poetry','','[]','晴新山色黛，風縱蘆花白。',24,'全唐诗/poet.song.60000.json','["晴新山色黛，風縱蘆花白。", "盡日依欄干，寒宵低細月。"]'),
('1e889427-1fc4-4f39-965e-0bd89c58a911','蕭堂書壁','米芾','宋','宋诗','song-poetry','','[]','插雲臺榭壓西興，笑語風生溽暑清。',32,'全唐诗/poet.song.60000.json','["插雲臺榭壓西興，笑語風生溽暑清。", "誰爲决雲開皓月，練翻雪捲看潮生。"]'),
('5b59de79-10fb-47a3-b7d9-87fa6a519e19','題泗濱南山石壁曰第一山','米芾','宋','宋诗','song-poetry','','[]','京洛風沙千里還，船頭出汴翠屏間。',32,'全唐诗/poet.song.60000.json','["京洛風沙千里還，船頭出汴翠屏間。", "莫論衡霍衝星斗，且是東南第一山。"]'),
('4461e825-4884-4a4d-adda-539f86fe1525','書淮岸艤舟館秀野亭','米芾','宋','宋诗','song-poetry','','[]','青葱秀野挾銀淮，誰把丹楹此地開。',32,'全唐诗/poet.song.60000.json','["青葱秀野挾銀淮，誰把丹楹此地開。", "我欲臨風取清曠，寄聲魚鳥莫相猜。"]'),
('874284b6-a86e-4919-86d4-10f76ce2f6a1','寶應道中','米芾','宋','宋诗','song-poetry','','[]','蒸雲大澤鬭蛟龍，五日頑無一點風。',32,'全唐诗/poet.song.60000.json','["蒸雲大澤鬭蛟龍，五日頑無一點風。", "十幅快帆飛野水，此生亦是小時通。"]'),
('95f1f409-d023-46d4-8010-a8a0232f430d','高郵即事二首  其一','米芾','宋','宋诗','song-poetry','','[]','高沙風快走蒼雲，小艇供鱸摘紫蓴。',32,'全唐诗/poet.song.60000.json','["高沙風快走蒼雲，小艇供鱸摘紫蓴。", "野泊終朝愛清景，不辜閒祿太平身。"]'),
('9ed9b0c3-a99e-48f0-ae73-0439ee5d5502','高郵即事二首  其二','米芾','宋','宋诗','song-poetry','','[]','華胥臺上欲臨風，萬籟無聲霧鬰空。',32,'全唐诗/poet.song.60000.json','["華胥臺上欲臨風，萬籟無聲霧鬰空。", "南北二龍乘障起，威音爛色正爭雄。"]'),
('ead0f25a-a569-43c7-b95c-e8037447c9ce','過浯溪','米芾','宋','宋诗','song-poetry','','[]','胡羯自干紀，唐綱竟不維。',24,'全唐诗/poet.song.60000.json','["胡羯自干紀，唐綱竟不維。", "可憐德業淺，有愧此碑詞。"]'),
('56015502-294c-4bf6-befc-77ace2a13c79','雜詠  其一','米芾','宋','宋诗','song-poetry','','[]','得官塵土古揚州，好客常稀俗客稠。',32,'全唐诗/poet.song.60000.json','["得官塵土古揚州，好客常稀俗客稠。", "掩簿叱胥無慁我，冒風踏雪作清遊。"]'),
('8893b985-5056-4a55-b1b6-4bafc0e4ead6','雜詠  其二','米芾','宋','宋诗','song-poetry','','[]','竹西桑柘暮鴉盤，特地霜風滿倦顔。',32,'全唐诗/poet.song.60000.json','["竹西桑柘暮鴉盤，特地霜風滿倦顔。", "不用使君相料理，都緣塵土少青山。"]'),
('3d555f81-0873-42a6-bb31-de8c1a6b78a0','雜詠  其三','米芾','宋','宋诗','song-poetry','','[]','贈我白毫筆，報以木蘭酒。',24,'全唐诗/poet.song.60000.json','["贈我白毫筆，報以木蘭酒。", "我書將示誰，汝筆稱我手。"]'),
('14fa18e4-0b2f-4307-9158-486359f437fc','瓜州百川浦','米芾','宋','宋诗','song-poetry','','[]','西瞻山逾緬，東望水正茫。',24,'全唐诗/poet.song.60000.json','["西瞻山逾緬，東望水正茫。", "楚人投餌處，吾肯扣鳴桹。"]'),
('cd9b2129-7d62-4eb1-b3af-a3532ba87f61','致爽軒四首  其一','米芾','宋','宋诗','song-poetry','','[]','西北瞻雲異，東南走貢珍。',24,'全唐诗/poet.song.60000.json','["西北瞻雲異，東南走貢珍。", "川華開日月，林嶺暗松筠。"]'),
('9c6d2703-24e0-468a-9654-02d1b0dc82cd','致爽軒四首  其二','米芾','宋','宋诗','song-poetry','','[]','北固輕綃外，西山淡素中。',24,'全唐诗/poet.song.60000.json','["北固輕綃外，西山淡素中。", "一天烟雨好，未獨愛霜空。"]'),
('b25758ff-9dcc-486d-aa0b-a2f7a8ee9c71','致爽軒四首  其三','米芾','宋','宋诗','song-poetry','','[]','玉斧初騎御，通明暫住居。',24,'全唐诗/poet.song.60000.json','["玉斧初騎御，通明暫住居。", "翛翛輕吹度，灑落碧華珠。"]'),
('e7d5a46b-f162-432f-a27b-f5e7c49e0bb8','致爽軒四首  其四','米芾','宋','宋诗','song-poetry','','[]','阿氏金爲屋，姮家玉作臺。',24,'全唐诗/poet.song.60000.json','["阿氏金爲屋，姮家玉作臺。", "岱輿憑海立，兜率跨雲開。"]'),
('030147f9-a6b3-4b26-b8f4-a62d200d3f0e','浄名  其一','米芾','宋','宋诗','song-poetry','','[]','厭市衝烟入，忘懷對客遲。',24,'全唐诗/poet.song.60000.json','["厭市衝烟入，忘懷對客遲。", "吟看飛鳥沒，坐到夕陽時。"]'),
('b67b9d65-3d33-4600-8288-52817c5b826a','浄名  其二','米芾','宋','宋诗','song-poetry','','[]','舊對湘西雪，遲遲憶故關。',24,'全唐诗/poet.song.60000.json','["舊對湘西雪，遲遲憶故關。", "水雲資老景，吟引謝江山。"]'),
('0b6c7dae-e977-46cf-b94e-2792ed81bc23','又','米芾','宋','宋诗','song-poetry','','[]','晨入雲隨步，宵還月共輿。',48,'全唐诗/poet.song.60000.json','["晨入雲隨步，宵還月共輿。", "清傳供佛飯，寒燎隔江漁。", "市響昏鴉亂，林穿列曜疏。", "殷勤顧景物，爲爾老南徐。"]'),
('1452dabe-8db1-4223-bfb1-97dcbb8134bf','題嗣濮王蘆雁二首  其一','米芾','宋','宋诗','song-poetry','','[]','偃蹇汀眠雁，蕭梢風觸蘆。',24,'全唐诗/poet.song.60000.json','["偃蹇汀眠雁，蕭梢風觸蘆。", "京塵方滿眼，速爲喚花奴。"]'),
('d0fdfa64-4e5f-4e05-a24f-1aba428bbfb2','題嗣濮王蘆雁二首  其二','米芾','宋','宋诗','song-poetry','','[]','野趣分苕水，鳳光剪鑑湖。',24,'全唐诗/poet.song.60000.json','["野趣分苕水，鳳光剪鑑湖。", "塵中不作惡，爲有鄴公圖。"]'),
('62688109-4050-4897-ae2c-8d26caa7b70e','題所得蔣氏帖','米芾','宋','宋诗','song-poetry','','[]','棐几延毛子，明窗館墨卿。',24,'全唐诗/poet.song.60000.json','["棐几延毛子，明窗館墨卿。", "功名皆一戲，未覺負平生。"]'),
('faabbeb7-9d46-4a14-84e3-4ec5c6ede2fb','答薛紹彭寄書','米芾','宋','宋诗','song-poetry','','[]','世言米薛或薛米，猶言弟兄與兄弟。',32,'全唐诗/poet.song.60000.json','["世言米薛或薛米，猶言弟兄與兄弟。", "四海論年我不卑，品定多應定如是。"]'),
('597d3415-c2a8-4159-ba14-4cd56c13568f','答劉涇書','米芾','宋','宋诗','song-poetry','','[]','唐滿書奩晉不收，却緣自不信雙眸。',32,'全唐诗/poet.song.60000.json','["唐滿書奩晉不收，却緣自不信雙眸。", "發狂爲報豢龍子，不怕人稱米薛劉。"]'),
('f3b2c203-94ca-4892-9cff-18beab5ed24c','庖丁解牛刀','米芾','宋','宋诗','song-poetry','','[]','庖丁解牛刀，無厚入有間。',84,'全唐诗/poet.song.60000.json','["庖丁解牛刀，無厚入有間。", "以此交世故，了不見後患。", "奈何觸褊心，忿氣益滋蔓。", "是非錯相干，惡成那及諫。", "智者善持己，頗覺操修辨。", "此道固不遠，可約可以散。", "黄帝本齋心，斯民即晏粲。"]'),
('8f69fdea-79ae-4a37-bef8-f19a2703c7dd','明月歌二首  其一','米芾','宋','宋诗','song-poetry','','[]','高高凝碧夜色卷，八荒更無纖雲屯。',128,'全唐诗/poet.song.60000.json','["高高凝碧夜色卷，八荒更無纖雲屯。", "冰輪直壓巨鼇首，東海萬里齊崩奔。", "仰觀左右毛骨竦，徐掃澄烟攝羣動。", "寥泬初疑玉兔跳，銀潢更恐金波湧。", "兒童爭指桂枝好，遊人不厭嫦娥老。", "苦留清景拂疏星，要與羲和接昏曉。", "光到長門知不知，猶勝關山人未歸。", "清風著我生雙翼，來作蟾宮變化飛。"]'),
('240b0a7d-8581-41b9-8988-49f55f06a214','明月歌二首  其二','米芾','宋','宋诗','song-poetry','','[]','姮娥竊藥爲飛仙，夜食丹霞凌紫烟。',240,'全唐诗/poet.song.60000.json','["姮娥竊藥爲飛仙，夜食丹霞凌紫烟。", "瞥開銀碧排翠鈿，信手拂掠新妝妍。", "蛾眉點出爭嬋娟，皎然嬌額臨風前。", "佳人再拜心拳拳，多生端有好姻緣。", "掀雲直指烏號懸，下射萬頃楊花氈。", "南飛驚鵲殊可憐，北堂人冷空無眠。", "彩霞欲掣舞衣揎，水精梳插籠鬢蟬。", "方諸滴瀝生流泉，老蚌呼吸凝芳鮮。", "誰家破鏡飛上天，滿林玉玦相勾連。", "多情應照載花船，無窮解趁尋春鞭。", "蓂莢自與桂華偏，駒隙誰爭白兔先。", "斯須幾望摶清圓，白毫宛轉吞大千。", "纖埃不隔知無邊，蘂宮可掬疑深穿。", "瓊華隨步翻繡筵，琉璃倒海傾長川。", "買來曾不用一錢，笙歌醉賞須年年。"]'),
('c43f871e-6ddf-47c8-a842-dd0c135b181b','菱溪石','米芾','宋','宋诗','song-poetry','','[]','長虹潜貫幽巖窟，綠烟更染秋波骨。',160,'全唐诗/poet.song.60000.json','["長虹潜貫幽巖窟，綠烟更染秋波骨。", "不容俗眼覘神功，只向菱溪作靈物。", "少室仙人領一麾，至誠發遍山中奇。", "雄雌亭亭兩挺出，宛若碧玉含春漪。", "朱欄碧甃拱山麓，翠霧彤霞掩幽谷。", "能將膚寸起清泉，幾見峰前春雨足。", "邇來新飾紫微宮，奇詭搜索林泉空。", "五色磊磊可補缺，三品往往慚收功。", "紫衣使者御天敕，肯教閟此蒼苔色。", "菱溪脫迹飛上天，迴看幽谷空雲烟。"]'),
('f6943737-91f5-4ca4-9e07-1df69511b29a','僧舍假山','米芾','宋','宋诗','song-poetry','','[]','玉峰高愛攙天碧，過眼雲關無處覓。',195,'全唐诗/poet.song.60000.json','["玉峰高愛攙天碧，過眼雲關無處覓。", "纔將呀豁向疏窗，已見峰稜翻瘦脊。", "明月照出溪中水，清風掃遍巖邊石。", "懸崖絕磴疑可擥，白露蒼烟俱咫尺。", "天陰未徹山陰寒，雨聲欲絕泉聲乾。", "須知物理有真妄，豈識道眼無殊觀。", "萬象森嚴掌握內，大塊俯仰毫芒間。", "抽身更洗清浄足，探歷幽深非所難。", "山僧作山真有以，詩人吟詩從此始。", "意教妙手發天慳，戲取神功當衆美。", "君不見浣花野老深結廬，白鹽赤甲龍虎趨。", "清吟醉賞左右足，當時應笑秦鞭驅。"]'),
('6296e741-8894-454f-b140-6de71713bff8','智衲草書','米芾','宋','宋诗','song-poetry','','[]','人愛老張書已顛，我知醉素心通天。',128,'全唐诗/poet.song.60000.json','["人愛老張書已顛，我知醉素心通天。", "筆鋒卷起三峽水，墨色染徧萬壑泉。", "興來颯颯吼風雨，落紙往往翻雲烟。", "怒蛟狂虺忽驚走，滿手黑電爭回旋。", "人間一日醉夢覺，物外萬態涵無邊。", "使人壯觀不知已，脫身直恐凌飛仙。", "棄筆爲山儻無苦，洗墨成池何足數。", "其來精絕自凝神，不在公孫渾脫舞。"]'),
('37fc4fe5-7eaa-49cb-ac6e-dc339dc1d23e','吳侍禁綠野亭','米芾','宋','宋诗','song-poetry','','[]','楚江倒水天上來，吳山削玉青崔嵬。',160,'全唐诗/poet.song.60000.json','["楚江倒水天上來，吳山削玉青崔嵬。", "飛流欲截衆峰險，揮手可擘烟雲開。", "危亭據此揭佳麗，斲出榱桷超層臺。", "憑空直喜縱高舉，下瞰愈覺心悠哉。", "曠野萬頃正入眼，清風四坐無纖埃。", "淺黛低潑弱柳色，紅粉正抹秋蓮腮。", "好音終日自多興，美景變態誰能裁。", "主人與客窮新賞，羅榼更擲神仙盃。", "歌珠舞雪不知已，何妨邀月聊徘徊。", "時來孰肯趣真隠，寄語沮溺無嫌猜。"]'),
('516b6295-77eb-49e2-90a3-7f2209fdc7bb','溪蓮行','米芾','宋','宋诗','song-poetry','','[]','廣寒宮女貪游戲，瑩滑琉璃光照地。',192,'全唐诗/poet.song.60000.json','["廣寒宮女貪游戲，瑩滑琉璃光照地。", "嫩雲纔捧出纖腰，無數鮫綃擁嬌翠。", "仙葩姿逞天姿穠，只愛臨溪梳洗慵。", "太真艷色禁不得，含羞微笑迎秋風。", "秋風苦惱秋露泣，的皪珠璣時瀉入。", "紅凝朱粉綠參差，儘濺裙襦烟不濕。", "初驚王母來瑶池，酡顔更醉流霞巵。", "三千佳麗已羅列，爭先鸞鑑勻娥眉。", "俄見洛神歸洛浦，波卷靴紋翠蛟舞。", "羽車雲蓋空紛披，碧疊巫峰生暮雨。", "坐憐吟倚風靈香，多情先斷何人腸。", "不及鴛鴦與鸂鶒，恣穿薄影眠池塘。"]'),
('d375697f-f643-4db7-9121-7061a99ef172','答郭純老秘校贈笏','米芾','宋','宋诗','song-poetry','','[]','銀蟾倒掛搖清輝，當中桂子初低垂。',320,'全唐诗/poet.song.60000.json','["銀蟾倒掛搖清輝，當中桂子初低垂。", "飛空已歷萬古盡，下照不使秋毫欺。", "轉盼冰輪湧東海，長天一派成琉璃。", "栽培不畏雪霜苦，剪拂豈容刀斧爲。", "明河無聲駕飛葉，紫府有陌馳修枝。", "姮娥愛惜日已久，玉階亦貴秋風吹。", "寧論匠石可斲削，還恐風雷堪出治。", "列真洞府秘不得，紫微宮闕藏其私。", "金童來授玉女捧，投之寶篋那能窺。", "每當方士脫凡骨，賜予一根朝帝墀。", "入手既覺袨服羽，照人端不羞朝曦。", "乃知不是風塵物，握出風塵真所宜。", "邇來地不愛此寶，名喧東魯誇珍奇。", "千金欲易不可得，橫紋錯落青絲披。", "胡爲夫子遠寄我，意以華豪驚絳帷。", "低頭拜賜亦已厚，我欲效報君須知。", "三年大聘獵英俊，捫膺吐氣生虹蜺。", "揉藍綵服俯可取，携將直上青雲梯。", "翱翔歡呼起拜舞，仰瞻日彩生堯眉。", "雞人忽報洞天曉，看取飛升變化時。"]'),
('d0bffc60-78bb-49f4-8c83-4bec6646a407','攬秀亭','米芾','宋','宋诗','song-poetry','','[]','羣峰矯矯蛟龍顛，衝波鼓鬣方迴旋。',288,'全唐诗/poet.song.60000.json','["羣峰矯矯蛟龍顛，衝波鼓鬣方迴旋。", "排空刻削萬仞碧，秀色直上干雲天。", "地形天巧世莫測，插出怪變知何年。", "傍驚列翠不入手，擬將瘦脊束差肩。", "何人高致得入手，擇奇結構當其前。", "丹甍繡桷麗朝日，綺疏藻井搖非烟。", "葱蒼數里拂巾被，蓊鬰衆木臨書筵。", "開扉割得曉光瑩，繞榻飛來佳氣鮮。", "乘閒超忽不知已，徒覺四顧清無邊。", "毫眉主人曳芒履，策杖欲作商宮仙。", "犀尊蕩漾瀉醇醴，招賓集醉秋風蓮。", "蓮華菡萏翠的皪，皎月照耀爭嬋娟。", "金絲鏘戛亂兩耳，醉倒三百黄金船。", "風流不見謝太守，昭亭朗賦磨新鎸。", "放傲豈如王逸少，蘭亭草聖窺天全。", "才華墨妙古已遠，只今唯有空山川。", "孰若開編樂教子，坐使發策驚前賢。", "還當操筆俯欄楯，試與採掇供詩篇。"]'),
('8859e936-95da-498b-9874-997033963da0','漣漪瑞墨堂書','米芾','宋','宋诗','song-poetry','','[]','陟巘不自期，孤雲掛松頂。',44,'全唐诗/poet.song.60000.json','["陟巘不自期，孤雲掛松頂。", "一揖不相期，飛雲無留影。", "雲已去，泉更長。", "雲泉畢世友，相得每相忘。"]'),
('84f3a1c4-8d38-4221-b93d-f044b5789579','雜詠  其一','米芾','宋','宋诗','song-poetry','','[]','水月光華動不風，寒增綠柳露滋松。',32,'全唐诗/poet.song.60000.json','["水月光華動不風，寒增綠柳露滋松。", "西山夜色無人喚，直透疏簾翠一重。"]'),
('a0571096-7190-425a-8c35-e07266cb15cb','雜詠  其二','米芾','宋','宋诗','song-poetry','','[]','巨艦橫江穩不搖，順浮溟漲午時潮。',32,'全唐诗/poet.song.60000.json','["巨艦橫江穩不搖，順浮溟漲午時潮。", "江南晴色山無翳，乞與閒人取次描。"]'),
('6c2cd815-48e6-4dd2-b0d0-5360a07841d3','送大郎應舉','米芾','宋','宋诗','song-poetry','','[]','天下英才米大郎，朝來跨馬入文場。',32,'全唐诗/poet.song.60000.json','["天下英才米大郎，朝來跨馬入文場。", "緒餘驚世須魁選，歸带蟾宮桂子香。"]'),
('e983fac7-781c-43ec-993d-75386ce98f7c','奉呈彥昭使君陪壯觀之賞','米芾','宋','宋诗','song-poetry','','[]','邀賓壯觀不辭寒，玉立風神氣上干。',32,'全唐诗/poet.song.60000.json','["邀賓壯觀不辭寒，玉立風神氣上干。", "欲識謝公清興處，千山萬嶺雪漫漫。"]'),
('91ab30e7-8be4-4c41-beb4-e29fc2f94f99','寄吳詩客','米芾','宋','宋诗','song-poetry','','[]','江上遲留臈破春，好詩時見賈參軍。',32,'全唐诗/poet.song.60000.json','["江上遲留臈破春，好詩時見賈參軍。", "年來鑒遠多新句，難附江風與海雲。"]'),
('0c8322f6-81b3-4370-a807-0261f94e81e6','奉詔書御屏','米芾','宋','宋诗','song-poetry','','[]','目炫五光開，雲蒸步起雷。',24,'全唐诗/poet.song.60000.json','["目炫五光開，雲蒸步起雷。", "不知天近遠，親見玉皇來。"]'),
('ed21b57f-4fb5-482c-8936-82f68294cb36','詠梅二首  其一','米芾','宋','宋诗','song-poetry','','[]','姑射真人自少羣，要親高節許交君。',32,'全唐诗/poet.song.60000.json','["姑射真人自少羣，要親高節許交君。", "一臺二妙逢清賞，甘遜佳名得致榮。"]'),
('8028c961-84ea-471e-96f2-c65c5f318a62','詠梅二首  其二','米芾','宋','宋诗','song-poetry','','[]','江頭盡醉似泥何，管領仙姿酒醟多。',32,'全唐诗/poet.song.60000.json','["江頭盡醉似泥何，管領仙姿酒醟多。", "烟艇兩三橫岸處，惜花佇立想凌波。"]'),
('5af9b7c9-b01f-413d-8594-488f1892bdc6','宿紫極宮','米芾','宋','宋诗','song-poetry','','[]','重柯交蔭動塵容，蓬閬仙家住水宮。',64,'全唐诗/poet.song.60000.json','["重柯交蔭動塵容，蓬閬仙家住水宮。", "道士神升金闕下，天君光降玉虛中。", "朱鬃筆定超凡籙，碧簡書傳避世翁。", "三夕臨風醒病骨，鈞天冉冉夢魂通。"]'),
('bfc2d74f-7504-402d-bbb1-89555b361194','道林','米芾','宋','宋诗','song-poetry','','[]','樓閣明丹堊，杉松振老髯。',24,'全唐诗/poet.song.60000.json','["樓閣明丹堊，杉松振老髯。", "僧迎方擁帚，茶細旋探簷。"]'),
('a19b082a-65e0-470f-a48c-8b3fb3cb4c13','法華臺','米芾','宋','宋诗','song-poetry','','[]','坱圠有同色，雪深雲未開。',24,'全唐诗/poet.song.60000.json','["坱圠有同色，雪深雲未開。", "終南晴夜月，彷彿似登臺。"]'),
('3afe8ff3-96b5-44f7-9b93-5bb12552f8eb','筆','米芾','宋','宋诗','song-poetry','','[]','摹畫由來妙手知，彩箋落處直疑飛。',32,'全唐诗/poet.song.60000.json','["摹畫由來妙手知，彩箋落處直疑飛。", "寸心用盡終何補，贏得霜毫禿後歸。"]'),
('5076e8a0-3ee6-4c6a-9b0c-b021d4f36f19','墨','米芾','宋','宋诗','song-poetry','','[]','百鍊經來老更奇，暗中光價自然飛。',32,'全唐诗/poet.song.60000.json','["百鍊經來老更奇，暗中光價自然飛。", "錦囊手跡長顔色，曾是君王乞得歸。"]'),
('4d805fc1-0a04-4218-a296-6d51394eec7c','紙','米芾','宋','宋诗','song-poetry','','[]','陶泓毛穎陳玄輩，同日聲名四海飛。',32,'全唐诗/poet.song.60000.json','["陶泓毛穎陳玄輩，同日聲名四海飛。", "獨有先生索高價，誰人獻賦洛陽歸。"]'),
('a36bae79-bbe4-417e-aaa5-7c586a37202a','硯','米芾','宋','宋诗','song-poetry','','[]','金井寒生一水池，讀書窗紙照螢飛。',32,'全唐诗/poet.song.60000.json','["金井寒生一水池，讀書窗紙照螢飛。", "悲歡窮泰尋常共，擲破還須匣取歸。"]'),
('2349591d-b480-481d-a9e5-539362613d8b','今日獻祝壽紀慶生申詩輒錄呈某頓首再拜','米芾','宋','宋诗','song-poetry','','[]','祥雲藹藹擁華筵，玉府蓬山見上仙。',32,'全唐诗/poet.song.60000.json','["祥雲藹藹擁華筵，玉府蓬山見上仙。", "瓊杯瀲灧祈眉算，永薦生申壽八千。"]'),
('1280d484-3633-4e78-a4c5-bc3ddbeb841d','周氏園居','米芾','宋','宋诗','song-poetry','','[]','高花落落照軒明，沼水涓涓遶砌聲。',32,'全唐诗/poet.song.60000.json','["高花落落照軒明，沼水涓涓遶砌聲。", "靜裏聞香醒倦思，雨中無事見閒情。"]'),
('c8f08b25-58a9-4562-b3b4-bdd9ba67de53','登米老菴呈天啟學士','米芾','宋','宋诗','song-poetry','','[]','我居爲江山，亦不爲像法。',60,'全唐诗/poet.song.60000.json','["我居爲江山，亦不爲像法。", "劫火色相空，未覺眼界乏。", "屹然留西菴，使我老境愜。", "衛公精爽在，千古對岌嶪。", "公來不可作，登臨浩相接。"]'),
('2d67734d-fd24-4175-a7e7-c638bc7e35d9','同官送鱸二首  其一','米芾','宋','宋诗','song-poetry','','[]','斑鱗擰鬣玉爲肌，夢入松江自可疑。',32,'全唐诗/poet.song.60000.json','["斑鱗擰鬣玉爲肌，夢入松江自可疑。", "𨁝跳金盤催膾手，西風正是憶鱸時。"]'),
('8275cf9f-5691-45b7-a307-4caef0280a16','同官送鱸二首  其二','米芾','宋','宋诗','song-poetry','','[]','虀黄鯉赤太凡生，蓴紫棖青道不行。',32,'全唐诗/poet.song.60000.json','["虀黄鯉赤太凡生，蓴紫棖青道不行。", "暫喜滿盤堆玉臛，誤教陳粟傲香粳。"]'),
('4d5956ed-09fd-4fc7-b20d-dbdf0b0b4b1d','觀雪','米芾','宋','宋诗','song-poetry','','[]','月姊封銀界，龍君幻玉壺。',24,'全唐诗/poet.song.60000.json','["月姊封銀界，龍君幻玉壺。", "江南三尺雪，人道十年無。"]'),
('9b2a98b1-6b90-4d5a-b546-76733d672fd7','新沼未有水','米芾','宋','宋诗','song-poetry','','[]','排檻花爭媚，環林石鬭蒼。',24,'全唐诗/poet.song.60000.json','["排檻花爭媚，環林石鬭蒼。", "何時潴淥浄，吾欲借籐床。"]'),
('c0ce8b82-a08e-48d4-afe2-f543b407b055','浄名作','米芾','宋','宋诗','song-poetry','','[]','大球三尺美無臕，素業清風合立朝。',32,'全唐诗/poet.song.60000.json','["大球三尺美無臕，素業清風合立朝。", "此別何言贈君子，讜言忠論好裨堯。"]'),
('45102b86-7ac1-48c8-b20a-9b510b10400e','遊湖州','米芾','宋','宋诗','song-poetry','','[]','泛泛五湖霜氣清，漫漫不辨水天形。',32,'全唐诗/poet.song.60000.json','["泛泛五湖霜氣清，漫漫不辨水天形。", "雖無織女支機石，且對姮娥稱客星。"]'),
('2ea8cda8-65ab-4817-98fa-43178860ef49','新主簿沈機惠棋局','米芾','宋','宋诗','song-poetry','','[]','縱橫世路久無猜，布劫爭先豈繫懷。',32,'全唐诗/poet.song.60000.json','["縱橫世路久無猜，布劫爭先豈繫懷。", "與我一枰撩萬緒，操戈信是逐生來。"]'),
('049cfef5-bc5d-4089-8a3f-d3cdd5ba5508','求監廟作','米芾','宋','宋诗','song-poetry','','[]','竊祿江湖事不攖，微祠舊足代深耕。',32,'全唐诗/poet.song.60000.json','["竊祿江湖事不攖，微祠舊足代深耕。", "敢爲野史攄幽憤，待廣由庚頌太平。"]'),
('de963f10-a54b-443d-a669-b3892186c7c5','元祐己巳歲維揚後齋爲亳州使君蔣公寫二首  其一','米芾','宋','宋诗','song-poetry','','[]','水竹風清一夢甦，濤生月破紫甌須。',32,'全唐诗/poet.song.60000.json','["水竹風清一夢甦，濤生月破紫甌須。", "滿堂愛客談書畫，且展宣王扇暍圖。"]'),
('f7c037a4-e2a6-4c5f-83c0-b3a04cc781b4','元祐己巳歲維揚後齋爲亳州使君蔣公寫二首  其二','米芾','宋','宋诗','song-poetry','','[]','小疾翻令吏日閒，明窗盡展古書看。',32,'全唐诗/poet.song.60000.json','["小疾翻令吏日閒，明窗盡展古書看。", "何須新句能消暑，滿腹風雲六月寒。"]'),
('eedbf76d-9164-4596-8afa-2d5445f8c495','贈人','米芾','宋','宋诗','song-poetry','','[]','平時語我密須移，我是商丘內不欺。',32,'全唐诗/poet.song.60000.json','["平時語我密須移，我是商丘內不欺。", "時節因緣翻異論，助他笑我見阿彌。"]'),
('096e1909-97ee-4484-b0d6-ce1b5dd77e76','題砂步三首  其一','米芾','宋','宋诗','song-poetry','','[]','一株怪石數莖筠，明月清風不繫身。',32,'全唐诗/poet.song.60000.json','["一株怪石數莖筠，明月清風不繫身。", "石月無痕竹無韵，寓軒消息與君陳。"]'),
('48e5ecc6-7ee7-455c-aff0-60ec67eb95b3','題砂步三首  其二','米芾','宋','宋诗','song-poetry','','[]','砂步漫皆合，松門若抱桴。',24,'全唐诗/poet.song.60000.json','["砂步漫皆合，松門若抱桴。", "悠悠搖艇子，真似剡溪圖。"]'),
('b868d86d-b1e2-48df-9f8c-3550ce708cc9','題砂步三首  其三','米芾','宋','宋诗','song-poetry','','[]','已有扁舟興，曾看過剡圖。',24,'全唐诗/poet.song.60000.json','["已有扁舟興，曾看過剡圖。", "翻思名手盡，誰復費工夫。"]'),
('43c3f91a-9dae-4aae-8d5e-5447d3ceff1a','題壁間  其一','米芾','宋','宋诗','song-poetry','','[]','歸來湖上寺，頓覺清有餘。',24,'全唐诗/poet.song.60000.json','["歸來湖上寺，頓覺清有餘。", "月色何太白，照人心腑紓。"]'),
('bc285229-fb6b-4c05-a920-46c486f111b4','題壁間  其二','米芾','宋','宋诗','song-poetry','','[]','水月虛懷，烟霞浪迹。',20,'全唐诗/poet.song.60000.json','["水月虛懷，烟霞浪迹。", "但莫憎愛，洞然明白。"]'),
('bbcf34b1-0820-4281-9cd7-db52ce4cd92e','鄙詩上呈通判朝奉大夫  其一','米芾','宋','宋诗','song-poetry','','[]','不是通侯貴，還應貢禹彈。',24,'全唐诗/poet.song.60000.json','["不是通侯貴，還應貢禹彈。", "只應好形製，自己愧彫殘。"]'),
('ec425697-1b56-47c9-b8dc-983a559138bd','鄙詩上呈通判朝奉大夫  其二','米芾','宋','宋诗','song-poetry','','[]','簪玳尚誰繼，風雲那可看。',24,'全唐诗/poet.song.60000.json','["簪玳尚誰繼，風雲那可看。", "自曾許持送，談笑未嘗乾。"]'),
('c692e4af-d490-4ecb-bd75-8b9b1b4a85e4','文殊','米芾','宋','宋诗','song-poetry','','[]','見聞如翳幻，三界若空花。',24,'全唐诗/poet.song.60000.json','["見聞如翳幻，三界若空花。", "聞復翳根除，塵銷覺圓浄。"]'),
('3508f563-cb97-41d8-940b-9dfd1ae55844','致爽軒  其一','米芾','宋','宋诗','song-poetry','','[]','水口癡雲散，林梢愛景還。',24,'全唐诗/poet.song.60000.json','["水口癡雲散，林梢愛景還。", "朝寒無物禦，擁鼻對西山。"]'),
('70d2fee1-adab-441b-9192-9752ad88d3ad','致爽軒  其二','米芾','宋','宋诗','song-poetry','','[]','夕紫堆香豆，朝嵐映墨池。',24,'全唐诗/poet.song.60000.json','["夕紫堆香豆，朝嵐映墨池。", "客來不須報，正是學書時。"]'),
('ee34bdbd-513b-4dc7-8a0a-f4ddb21e40f3','長壽菴咏梅','米芾','宋','宋诗','song-poetry','','[]','沉檀應在骨，龍麝自薰心。',24,'全唐诗/poet.song.60000.json','["沉檀應在骨，龍麝自薰心。", "千載吟蘄竹，清雅少知音。"]'),
('055c42a7-1dcf-4194-9ed8-3647b280c43b','壯觀','米芾','宋','宋诗','song-poetry','','[]','臨南山猗陟北岵，撫壯勝猗遺萬古。',172,'全唐诗/poet.song.60000.json','["臨南山猗陟北岵，撫壯勝猗遺萬古。", "漫漫蒼蒼穹無所，奕奕嶪嶪蹤奇度。", "逶迤猗前征，盤礴猗後駐。", "奮迅猗奔駛，却約猗畔顧。", "環旋猗抱卷，引伸猗就旅。", "霧釋猗離掩，雲乘猗平舉。", "瞭瞭猗蟾輝，悒悒猗蒸雨。", "鬰鬰猗陽春，莽莽猗玉露。", "爚爚猗午停，翳翳猗酉去。", "領吾儕猗並輿步，却飛仙猗不遐慕，癯其形猗久何苦。", "便莫便猗遵坦路，適莫適猗破心阻。", "樂莫樂猗頻會遇，莫莞藤猗擷芳藇。"]'),
('1d2e318a-9cd0-4c26-9a84-6972ae4e9025','王略帖贊','米芾','宋','宋诗','song-poetry','','[]','昭回於天垂英光，跨頡歷籀化大荒。',64,'全唐诗/poet.song.60000.json','["昭回於天垂英光，跨頡歷籀化大荒。", "烟華淡濃動彷徉，一噫萬古稱天章。", "鸞夸虬引鵠序翔，洞天九九通遼陽。", "茫茫十二小劫長，璽完神訶命黻藏。"]'),
('72fc8d5c-d3fb-49c5-a3a1-0cb01aa2944a','王獻之蘇氏寶帖贊','米芾','宋','宋诗','song-poetry','','[]','猗太宰，秀當代。',64,'全唐诗/poet.song.60000.json','["猗太宰，秀當代。", "靈襟疏，沖韵邁。", "一筆落，兩行带。", "雲龍廷，走百怪。", "驚電掣，斷兕快。", "盤偃蹇，意無在。", "藐百川，會百海。", "人那知，冠千載。"]'),
('8ceb0aea-8d40-4d4b-ab0e-18d836f0a2a2','王右軍穉恭帖贊','米芾','宋','宋诗','song-poetry','','[]','混沌破，龍蛇出。',56,'全唐诗/poet.song.60000.json','["混沌破，龍蛇出。", "大荒子，鼓神物。", "縱變怪，造怳忽。", "起洪水，稽天骨。", "大道驚，戮狂勃。", "時蟄引，無憚率。", "神禹符，鎮罅窟。"]'),
('7812cc4d-4024-449a-b732-0b31fbb36d8b','書法贊','米芾','宋','宋诗','song-poetry','','[]','去顔肉，增褚骨。',24,'全唐诗/poet.song.60000.json','["去顔肉，增褚骨。", "發天秀，助神物。", "敢竊議，增骨突。"]'),
('4f675cbc-73b8-4f51-a87f-a1ddf7c88ac4','十八羅漢贊','米芾','宋','宋诗','song-poetry','','[]','巍巍釋能儒，十八大果士。',60,'全唐诗/poet.song.60000.json','["巍巍釋能儒，十八大果士。", "每於垢濁世，見此無相身。", "追貌自楚工，磷玉妙吳匠。", "種種出道韵，二幻與佛同。", "在處爲道場，五濁化浄土。"]'),
('25236e99-2a03-434f-98bb-3d99503c82b7','晦堂心如來真贊','米芾','宋','宋诗','song-poetry','','[]','此是晦堂，更無佛祖。',50,'全唐诗/poet.song.60000.json','["此是晦堂，更無佛祖。", "百尺竿頭，誰敢進步。", "無限衆生，爲此老誤。", "誤不誤，陝府鐵牛跳出土，兩脚搥胸叫冤苦。"]'),
('7433d27d-2991-4a6e-ab0c-c8b894f38383','臨化偈','米芾','宋','宋诗','song-poetry','','[]','衆香國中來，衆香國中去。',36,'全唐诗/poet.song.60000.json','["衆香國中來，衆香國中去。", "人欲識去來，去來事如許。", "天下老和尚，錯入輪迴路。"]'),
('e9136b48-ad39-42d3-a142-142749fc5c3e','焦山普濟禪院碑贊','米芾','宋','宋诗','song-poetry','','[]','古佛留法度大心，種種威攝現勝相。',128,'全唐诗/poet.song.60000.json','["古佛留法度大心，種種威攝現勝相。", "大心衆生攝威德，求度傾身及衆寶。", "冥陽咸會精誠通，正法是歸大緣集。", "我今稽首佛陀僧，永奠海山作津筏。", "我今稽首明應公，永護寶車炳威德。", "悉化大心依浄住，一世咸如今佛日。", "三光不愆四序調，主聖臣忠載萬億。", "五穀蕃生土地肥，萬靈常躋仁壽域。"]'),
('539c1cf3-b84f-437c-a17d-88a125557e17','露筋之碑贊','米芾','宋','宋诗','song-poetry','','[]','王化煥猗盛江漢，叔運煽猗人倫亂。',48,'全唐诗/poet.song.60000.json','["王化煥猗盛江漢，叔運煽猗人倫亂。", "一德彥猗昭世典，情莫轉猗天質善。", "楚澤湎猗雲木偃，煒斯囝猗日星建。"]'),
('4aa07514-e27a-433e-add3-793a93793c58','天衣懷禪師碑贊','米芾','宋','宋诗','song-poetry','','[]','稽首歸依無上尊，清浄圓滿千億化。',96,'全唐诗/poet.song.60000.json','["稽首歸依無上尊，清浄圓滿千億化。", "三身俱現立法祖，一法不立即如來。", "示現有漸緣慈悲，慈悲本不爲佛祖。", "佛祖不立無歸依，所以三身開後覺。", "寥寥千古古佛遠，堂堂此身即古佛。", "衆生不昧本來心，此是古佛行住處。"]'),
('06856c7f-f9af-42b4-b804-ce6a97cf0b4d','甘露作呈夷曠','米芾','宋','宋诗','song-poetry','','[]','欲雨氣不透，庭梧有栖烟。',72,'全唐诗/poet.song.60000.json','["欲雨氣不透，庭梧有栖烟。", "迴首望北固，雲藏浄名天。", "呼童速具輿，憑高覽山川。", "隠見豈不好，開霽景固全。", "須臾剛風流，湛湛清露圓。", "歸途知有伴，華月上丹淵。"]'),
('8374d055-528c-4708-a904-0ac45af2fb0e','夜登鑑遠觀江南野燒作','米芾','宋','宋诗','song-poetry','','[]','君不見紅旗一卷無奔北，龍驤將軍初下蜀。',134,'全唐诗/poet.song.60000.json','["君不見紅旗一卷無奔北，龍驤將軍初下蜀。", "又不見天兵十萬領藩曹，百丈靈旗照江國。", "高樓夜登有鑒賞，江南野燒深山谷。", "烈勢已覺逼南辰，龍蛇膏血如爆竹。", "故應玉石俱被焚，老樵拾炭投斧斤。", "長松巨梓中大厦，一隨烈焰同塵埃。", "人言木自爲風戛，木中生火自焚爇。", "欲知利害日相磨，此火害人尤慘熱。"]'),
('782610c9-042f-4fbe-b145-145bb9e8a254','不應武康清溪之檄端居即事呈淮陽建昌二太守辰溪監郡三公','米芾','宋','宋诗','song-poetry','','[]','秘篋大開千古到，雪圖小掛滿堂寒。',96,'全唐诗/poet.song.60000.json','["秘篋大開千古到，雪圖小掛滿堂寒。", "墨濃員嶠峰孤起，枕冷燕山玉一團。", "圓扇古人蟬雀意，清風四海弟兄歡。", "閉關不謝勤來客，畏暑非緣懶作官。", "鳬脛欲長寧可益，蜩枝求足已能胖。", "有時驚覺神瀵夢，北里新聲舞翠鸞。"]'),
('cdf18671-710b-4979-a62a-6fa97da51e65','獄空行上獻府公朝奉麾下漣水令米芾皇恐','米芾','宋','宋诗','song-poetry','','[]','楚州五邑口百萬，擾靜盡繫太守公。',248,'全唐诗/poet.song.60000.json','["楚州五邑口百萬，擾靜盡繫太守公。", "政由吏人民乃擾，政由太守民氣通。", "安土樂生善民欲，惡民惟欲與吏同。", "太守無能不戢吏，精力不給吏乃庸。", "兩獄百間塞有罪，有耳未聞一日空。", "晉昌唐公名世後，清風素節爲時宗。", "五更三點運精思，衆人安寢吏計窮。", "百姓小妄赦不罪，庶幾小屈能自致。", "五邑來者初亦彙，久而官悚吏皆畏，雖欲呼之亦不至。", "乃知獄空空有理，百萬無冤無枉吏。", "來者迎刃無留滯，赦來兩獄久無事。", "太守政聲既如此，廉車旁午目所備。", "胡不剡章上天子，追風早來促公起。", "去入省闈或使指，吏皆欲去民欲留。", "我祝公去豈同吏，長坂大車程萬里。"]'),
('a706acb4-3102-4779-8d69-9d0460572131','壯觀二首  其一','米芾','宋','宋诗','song-poetry','','[]','無涯小智壯營營，昔昔浮生夢數驚。',32,'全唐诗/poet.song.60000.json','["無涯小智壯營營，昔昔浮生夢數驚。", "重到白沙登壯觀，江湖醉眼暫揩明。"]'),
('b62dcf3c-0c23-4ff1-a996-e8ee413839ef','壯觀二首  其二','米芾','宋','宋诗','song-poetry','','[]','夢寐中間得鹿時，孔軒如在定能知。',32,'全唐诗/poet.song.60000.json','["夢寐中間得鹿時，孔軒如在定能知。", "江山勝處頻傾酒，我是當年謝客兒。"]'),
('3f3135f6-b35d-466c-b7f5-3ffde6ac65f8','壯觀後詩同二公遊壯觀上呈府公工部','米芾','宋','宋诗','song-poetry','','[]','壯觀不到俄四期，叮嚀老思模雄奇。',64,'全唐诗/poet.song.60000.json','["壯觀不到俄四期，叮嚀老思模雄奇。", "羣山勢活各奔走，大川氣斂合衆離。", "蒼嶔留雪玉刻巧，碧落靜滑紅輪馳。", "寒潮不生九澤凍，行膠與子約再來。"]'),
('5009f0a8-5a3f-44a6-a12e-f8fc8a6fd2d3','龍真行爲天章待制林公跋書云秘府右軍書一卷有一龍形真字印故作','米芾','宋','宋诗','song-poetry','','[]','龍形真字芸香裏，伏日道山聊一啟。',144,'全唐诗/poet.song.60000.json','["龍形真字芸香裏，伏日道山聊一啟。", "媼來鵝去已千年，莫像癡兒收蠟紙。", "蕭衍老翁食無肉，錦質綉章能獨侈。", "不知劫火付冤家，却誤頑仙求令史。", "文皇有金無鑒目，頼取穹官齊押尾。", "徐生小黠辨茅簷，不道天真難力致。", "晚薄功名歸一戲，一奩尤勝三公貴。", "牡丹不語人能醉，墨光覺勝朱鉛媚。", "與身俱生無術治，又染膏肓劉巨濟。"]'),
('bd74ccd8-fec2-4b65-9684-ba9625bd920c','催租','米芾','宋','宋诗','song-poetry','','[]','一司日日下賑濟，一司旦旦催租稅。',64,'全唐诗/poet.song.60000.json','["一司日日下賑濟，一司旦旦催租稅。", "單狀請出且抄納，百姓眼中聊一視。", "白頭縣令受薄祿，不敢鞭笞怒上帝。", "救民無術告朝廷，監廟東歸早相乞。"]'),
('7cf9afb9-3019-4f95-b768-284fae2ca443','海岳菴雜詩','米芾','宋','宋诗','song-poetry','','[]','仲若呼不聞，孝然叫不應。',60,'全唐诗/poet.song.60000.json','["仲若呼不聞，孝然叫不應。", "東海滾底浪，南山入雲徑。", "西南嵯峨者，起復巧相競。", "火輪激剛風，倒化紫金境。", "枕石不知冷，鼓腹歌更迥。"]'),
('2d68b344-107b-4c80-b2e3-c3c87f99728c','書壽陽樓柱','米芾','宋','宋诗','song-poetry','','[]','披豁雄風至，欹眠一夢遲。',48,'全唐诗/poet.song.60000.json','["披豁雄風至，欹眠一夢遲。", "豪騎八公馬，醉擷五香芝。", "廉老心徒勇，梅生語不卑。", "青岡何處是，猶壯謝家兒。"]'),
('7ff1bffd-7aa4-4481-8af6-ea229a794647','太常二絕  其一','米芾','宋','宋诗','song-poetry','','[]','塵埃徹腦老侵尋，悞入清流聽八音。',32,'全唐诗/poet.song.60000.json','["塵埃徹腦老侵尋，悞入清流聽八音。", "魚鳥難馴湖海志，岸沙汀竹憶山林。"]'),
('65b89e3b-7009-441f-9119-03a09273db08','太常二絕  其二','米芾','宋','宋诗','song-poetry','','[]','竹前竹後太常齋，風度簫韶識舜諧。',32,'全唐诗/poet.song.60000.json','["竹前竹後太常齋，風度簫韶識舜諧。", "博士擁書方徹卷，相公上馬報當階。"]'),
('461a89e9-a21c-4809-98e3-42620ec64dd4','青山','米芾','宋','宋诗','song-poetry','','[]','一園松竹冷陰森，猶得桓公歎可臨。',32,'全唐诗/poet.song.60000.json','["一園松竹冷陰森，猶得桓公歎可臨。", "却叵劉琨看左傳，玉壺徒缺誤雄心。"]'),
('07de35b1-2bb7-4da6-a1da-bebf8fa105eb','過當塗','米芾','宋','宋诗','song-poetry','','[]','鷗鷺依寒水，蒹葭靜晚風。',24,'全唐诗/poet.song.60000.json','["鷗鷺依寒水，蒹葭靜晚風。", "烟光秋雨細，樹色碧山重。"]'),
('9d15c724-9b9d-44a0-ba8f-0583d1c5941d','鑑遠樓','米芾','宋','宋诗','song-poetry','','[]','賞心亭上羣山雪，三夕丹淵借月華。',32,'全唐诗/poet.song.60000.json','["賞心亭上羣山雪，三夕丹淵借月華。", "吟盡江南清絕趣，亟行歸覲紫皇家。"]'),
('fb1ccb93-a04a-4e82-963f-e7be81671b3c','拜書學博士作','米芾','宋','宋诗','song-poetry','','[]','昔夢浮生定是非，家山且喜隔年歸。',32,'全唐诗/poet.song.60000.json','["昔夢浮生定是非，家山且喜隔年歸。", "扁舟又出欄潮閘，出處初心老更違。"]'),
('d33fe64c-036b-4c1b-9c29-d97d1346c193','研山詩','米芾','宋','宋诗','song-poetry','','[]','山研雲初抱，奩書客不傳。',24,'全唐诗/poet.song.60000.json','["山研雲初抱，奩書客不傳。", "北窗多異氣，正對浄名天。"]'),
('7691fa82-21cf-4065-96cd-b997be15de9b','寶月觀','米芾','宋','宋诗','song-poetry','','[]','濁盡塵難掩，光分逐露圓。',24,'全唐诗/poet.song.60000.json','["濁盡塵難掩，光分逐露圓。", "香清得桂子，珠瑩墜花鈿。"]'),
('07c5213c-a9d4-4147-a79f-8bba24ccf5f5','槐竹','米芾','宋','宋诗','song-poetry','','[]','槐前竹後午陰繁，壺嶺華胥屢往還。',32,'全唐诗/poet.song.60000.json','["槐前竹後午陰繁，壺嶺華胥屢往還。", "雅興欲爲十客具，人和端使一身閒。"]'),
('9d551bab-fb2d-431e-bb96-a3171fe91e3d','萬籟','米芾','宋','宋诗','song-poetry','','[]','萬籟寒空響，羣山隠映開。',24,'全唐诗/poet.song.60000.json','["萬籟寒空響，羣山隠映開。", "遲遲暮鐘裏，且喚竹輿來。"]'),
('83ef5527-427d-4a5f-add2-231ae26592ab','杉徑','米芾','宋','宋诗','song-poetry','','[]','萬槊森然老更成，要將餘韵鬭僧清。',32,'全唐诗/poet.song.60000.json','["萬槊森然老更成，要將餘韵鬭僧清。", "道傍誰識凌雲操，只有詩人著眼明。"]'),
('e4dfb34b-03c5-4ee6-b308-9e926fcc1808','早來堂','米芾','宋','宋诗','song-poetry','','[]','山聚詩增思，洋寬墨有池。',48,'全唐诗/poet.song.60000.json','["山聚詩增思，洋寬墨有池。", "紫金化夕境，嵐翠發朝曦。", "兜率當銅檻，蓬壺對蕙帷。", "平生會心趣，歸計豈應遲。"]'),
('d862da8c-0753-4dbd-bd8f-d6558286a28c','黄龍真贊','米芾','宋','宋诗','song-poetry','','[]','的的曹溪一點開，從茲馿足踏塵埃。',32,'全唐诗/poet.song.60000.json','["的的曹溪一點開，從茲馿足踏塵埃。", "黄龍若不三玄接，爭得東林八轉來。"]'),
('c9757264-9836-4bc4-83be-93c704eb9449','擬古  其一','米芾','宋','宋诗','song-poetry','','[]','青松勁挺姿，凌霄恥屈盤。',72,'全唐诗/poet.song.60000.json','["青松勁挺姿，凌霄恥屈盤。", "種種出枝葉，牽連上松端。", "秋花起絳烟，旖旎雲錦殷。", "不羞不自立，舒光射丸丸。", "柏見吐子效，鶴疑縮頸還。", "青松本無華，安得保歲寒。"]'),
('44cd8446-ca3e-4309-88f0-310783f15ffa','擬古  其二','米芾','宋','宋诗','song-poetry','','[]','龜鶴年壽齊，羽介所託殊。',60,'全唐诗/poet.song.60000.json','["龜鶴年壽齊，羽介所託殊。", "種種是靈物，相得忘形軀。", "鶴有沖霄心，龜厭曳尾居。", "以竹兩附口，相將上雲衢。", "報汝慎勿語，一語墮泥塗。"]'),
('452778fd-f018-43c7-b4ee-8cd1f6314303','入境寄集賢林舍人','米芾','宋','宋诗','song-poetry','','[]','揚帆載月遠相過，佳氣蔥蔥聽誦歌。',64,'全唐诗/poet.song.60000.json','["揚帆載月遠相過，佳氣蔥蔥聽誦歌。", "路不拾遺知政肅，野多滯穗是時和。", "天分秋暑資吟興，晴獻溪山入醉哦。", "便捉蟾蜍共研墨，綵牋書盡翦江波。"]'),
('e4d6a482-9587-41d6-be94-b11aa160d70a','重九會郡樓','米芾','宋','宋诗','song-poetry','','[]','山清氣爽九秋天，黄菊紅茱滿泛船。',64,'全唐诗/poet.song.60000.json','["山清氣爽九秋天，黄菊紅茱滿泛船。", "千里結言寧有後，羣賢畢至猥居前。", "杜郎閑客今焉是，謝守風流古所傳。", "獨把秋英緣底事，老來情味向詩偏。"]'),
('83e714b2-08cb-43e9-bcb9-78349f8daebb','和林公峴山之作','米芾','宋','宋诗','song-poetry','','[]','皎皎中天月，團團徑千里。',168,'全唐诗/poet.song.60000.json','["皎皎中天月，團團徑千里。", "震澤乃一水，所占已過二。", "娑羅即峴山，謬云形大地。", "地惟東吳偏，山水古佳麗。", "中有皎皎人，瓊衣玉爲餌。", "位維列仙長，學與千年對。", "幽操人獨處，迢迢願招類。", "金颸带秋威，欻逐雲檣至。", "朝隮輿馭飆，暮返光浮袂。", "雲盲有風驅，蟾餮有刀利。", "亭亭太陰宮，無乃瞻星氣。", "興深夷險一，理洞軒裳僞。", "紛紛夸俗勞，坦坦忘懷易。", "浩浩將我行，蠢蠢須公起。"]'),
('a6bc0ff4-b8a4-4443-bcdf-a091356b316d','送王渙之彥舟','米芾','宋','宋诗','song-poetry','','[]','集英春殿鳴鞘歇，神武天臨光下澈。',208,'全唐诗/poet.song.60000.json','["集英春殿鳴鞘歇，神武天臨光下澈。", "鴻臚初唱第一聲，白面王郎年十八。", "神武樂育天下造，不使敲抨使傳道。", "衣錦東南第一州，棘璧湖山兩清照。", "襄陽野老漁竿客，不愛紛華愛泉石。", "相逢不約約無逆，輿握古書同岸幘。", "淫朋嬖黨初相慕，濯髮灑心求易慮。", "翩翩遼鶴雲中侶，土苴尪鴟那一顧。", "邇來器業何深至，湛湛具區無底沚。", "可憐一點終不易，枉駕殷勤尋漫仕。", "漫仕平生四方走，多與英才並肩肘。", "少有俳辭能駡鬼，老學鴟夷漫存口。", "一官聊具三徑資，取捨殊塗莫迴首。"]'),
('7ee1f8eb-f27f-4044-abe2-7e168b182bce','爲政','米芾','宋','宋诗','song-poetry','','[]','美人爲政本忘機，服藥求仙事不違。',64,'全唐诗/poet.song.60000.json','["美人爲政本忘機，服藥求仙事不違。", "葉縣已泥丹竈畢，瀛洲當伴赤松歸。", "先師有訣神將助，大聖無心火自飛。", "九轉但能生羽翼，雙鳬忽去定何依。"]'),
('ba305592-6413-4778-b873-af520b82f35d','戲成呈司諫台坐','米芾','宋','宋诗','song-poetry','','[]','我思岳麓抱黄閣，飛泉元在天半落。',98,'全唐诗/poet.song.60000.json','["我思岳麓抱黄閣，飛泉元在天半落。", "石鯨吐出湔一里，赤日霧起陰紛薄。", "我曾坐石浸足眠，肘項抵水洗背肩。", "客時效我病欲死，一夜轉筋著艾燃。", "如今病渴擁爐坐，安得縮却三十年。", "嗚呼安得縮却三十年，重往坐石浸足眠。"]'),
('cfd6ac95-5c23-45d0-9f4a-790a037d1521','將之苕溪戲作呈諸友  其一','米芾','宋','宋诗','song-poetry','','[]','松竹留因夏，溪山去爲秋。',48,'全唐诗/poet.song.60000.json','["松竹留因夏，溪山去爲秋。", "久賡白雪詠，更度采菱謳。", "縷玉鱸堆案，團金橘滿洲。", "水宮無限景，載與謝公遊。"]'),
('955f0eea-8ceb-4bd3-9a28-cc54a69daa2f','將之苕溪戲作呈諸友  其二','米芾','宋','宋诗','song-poetry','','[]','半歲依脩竹，三時看好花。',48,'全唐诗/poet.song.60000.json','["半歲依脩竹，三時看好花。", "懶傾惠泉酒，點盡壑源茶。", "主席多同好，羣峰伴不譁。", "朝來還蠹簡，便起故巢嗟。"]'),
('75fa5ace-7abe-42b0-97a9-2eca21d022bf','將之苕溪戲作呈諸友  其三','米芾','宋','宋诗','song-poetry','','[]','好懶難辭友，知窮豈念通。',48,'全唐诗/poet.song.60000.json','["好懶難辭友，知窮豈念通。", "貧非理生拙，病覺養心功。", "小圃能留客，青冥不厭鴻。", "秋帆尋賀老，載酒過江東。"]'),
('7af6b8d6-34cc-46ec-a540-5400f95bcf1c','將之苕溪戲作呈諸友  其四','米芾','宋','宋诗','song-poetry','','[]','仕倦成流落，遊頻慣轉蓬。',48,'全唐诗/poet.song.60000.json','["仕倦成流落，遊頻慣轉蓬。", "熱來隨意住，凉至逐緣東。", "入境親疏集，他鄉彼此同。", "暖衣兼飽食，但覺愧梁鴻。"]'),
('a0c08237-1116-4dc2-bb58-6735ce2aaef4','將之苕溪戲作呈諸友  其五','米芾','宋','宋诗','song-poetry','','[]','旅食緣交住，浮家爲興來。',48,'全唐诗/poet.song.60000.json','["旅食緣交住，浮家爲興來。", "句留荆水話，襟抱卞峰開。", "過剡如尋戴，遊梁定賦枚。", "漁歌堪畫處，又有魯公陪。"]'),
('796d6841-d10a-4cdb-a209-173e6bb6ac0e','將之苕溪戲作呈諸友  其六','米芾','宋','宋诗','song-poetry','','[]','密友從春拆，紅薇過夏榮。',48,'全唐诗/poet.song.60000.json','["密友從春拆，紅薇過夏榮。", "團枝殊自得，顧我若含情。", "漫有蘭隨色，寧無石對聲。", "却憐皎皎月，依舊滿船行。"]'),
('e84aaeb8-a526-476a-8884-09766e402dc1','拜中岳命作  其一','米芾','宋','宋诗','song-poetry','','[]','雲水心常結，風塵面久盧。',48,'全唐诗/poet.song.60000.json','["雲水心常結，風塵面久盧。", "重尋釣鼇客，初入選仙圖。", "鼠雀真官耗，龍蛇與衆俱。", "却懷閑祿厚，不敢著潜夫。"]'),
('da02fa6c-4419-41cf-917c-8e9bc0a69f44','拜中岳命作  其二','米芾','宋','宋诗','song-poetry','','[]','常貧須漫仕，閑祿是身榮。',48,'全唐诗/poet.song.60000.json','["常貧須漫仕，閑祿是身榮。", "不託先生第，終成俗吏名。", "重緘議法口，靜洗看山睛。", "夷惠中何有，圖書老此生。"]'),
('20ded7ed-b489-4861-a38d-62fc78578ab0','謹以鄙詩送提舉通直使江西','米芾','宋','宋诗','song-poetry','','[]','三吳有丈夫，氣欲吞海水。',60,'全唐诗/poet.song.60000.json','["三吳有丈夫，氣欲吞海水。", "開口論世事，借箸對天子。", "瑞節高如松，一歲幾繁使。", "秋水浮湘月，罇酒屢覯止。", "言別不可攀，寥虛看雲駛。"]'),
('db426839-7d78-4588-960d-6f8235dcee99','秋山','米芾','宋','宋诗','song-poetry','','[]','淡墨秋林畫遠天，暮霞還照紫添烟。',32,'全唐诗/poet.song.60000.json','["淡墨秋林畫遠天，暮霞還照紫添烟。", "故人好在重携手，不到平山漫五年。"]'),
('c52c27a2-8785-47e8-94eb-51381a34b13f','穰侯出關','米芾','宋','宋诗','song-poetry','','[]','穰侯去國緩驅車，蔡澤還來取范睢。',32,'全唐诗/poet.song.60000.json','["穰侯去國緩驅車，蔡澤還來取范睢。", "惡客只應真可厭，怪他漢相館邱虛。"]'),
('22ea8013-e4cc-4579-b5ed-caac084929e2','中秋登海岱樓作','米芾','宋','宋诗','song-poetry','','["\u4e2d\u79cb\u8282", "\u5199\u666f", "\u4e2d\u79cb"]','目窮淮海兩如銀，萬道虹光育蚌珍。',32,'全唐诗/poet.song.60000.json','["目窮淮海兩如銀，萬道虹光育蚌珍。", "天上若無修月戶，桂枝撐損向西輪。"]'),
('820545f0-0ee0-49bd-aae1-c2adff29d122','壯觀','米芾','宋','宋诗','song-poetry','','[]','君謨登壯觀，要我賦新詩。',48,'全唐诗/poet.song.60000.json','["君謨登壯觀，要我賦新詩。", "鬢逐年光老，詞緣大作奇。", "江山一世斷，風雅六朝卑。", "對酒勸不飲，操懷誰與知。"]'),
('5e5c6dfc-df38-4721-96f4-8784e51031c9','次韵魏見寄','米芾','宋','宋诗','song-poetry','','[]','山椒卜築瞰江波，千里常懷楚製荷。',64,'全唐诗/poet.song.60000.json','["山椒卜築瞰江波，千里常懷楚製荷。", "舊憐俊氣閒羈馬，老厭奴書不玩鵝。", "真逸豈因明主棄，聖時長和野民歌。", "一自扣舷驚夏統，洛川雲物至今多。"]'),
('589eab91-d6a4-449a-bdda-d74f586c1aa4','和陳建州覺民  其一','米芾','宋','宋诗','song-poetry','','[]','七年烏帽抗黄塵，晝錦歸來世又新。',32,'全唐诗/poet.song.60000.json','["七年烏帽抗黄塵，晝錦歸來世又新。", "若過武夷山下看，人間不太敝精神。"]'),
('64544be7-f625-4029-b9bd-d6f4c758ca0c','和陳建州覺民  其二','米芾','宋','宋诗','song-poetry','','[]','白頭何慕久京華，靜洗黄塵眼界花。',32,'全唐诗/poet.song.60000.json','["白頭何慕久京華，靜洗黄塵眼界花。", "萬寶精神在風月，好詩追取不須賒。"]'),
('1846a955-36ac-4bdf-8d12-000c0eb06567','收張僧繇天王上有薛稷題閻二物樂老處元直取得又收景渙問禮圖亦六朝畫珊瑚一枝','米芾','宋','宋诗','song-poetry','','[]','三枝朱草出金沙，來自天支節相家。',32,'全唐诗/poet.song.60000.json','["三枝朱草出金沙，來自天支節相家。", "當日蒙恩預名表，愧無五色筆頭花。"]'),
('aaf6f30b-9b1b-4190-bace-83a148f73716','一生','米芾','宋','宋诗','song-poetry','','[]','一生吏案發人狂，重入承明馬齒長。',32,'全唐诗/poet.song.60000.json','["一生吏案發人狂，重入承明馬齒長。", "書畫不賢倉庾氏，便於賃舍植秋芳。"]'),
('37bde736-7bb7-425c-8b19-c1810eabc528','張長史今歲仍得見於越上長史遂出此展之可愛成佳物也主者寶之','米芾','宋','宋诗','song-poetry','','[]','吳人善砧理，惡楮化爲美。',24,'全唐诗/poet.song.60000.json','["吳人善砧理，惡楮化爲美。", "其他亦倣此，第未知之耳。"]'),
('7845871d-de4e-44b9-bbe1-638651b6d639','奉酬山甫','米芾','宋','宋诗','song-poetry','','[]','每登鑑遠樓，下視皇天蕩。',72,'全唐诗/poet.song.60000.json','["每登鑑遠樓，下視皇天蕩。", "思挹落落人，凭欄攬萬象。", "忽逢西浦士，談彩何蕭曠。", "養成谷口名，行見青藜杖。", "山色且淡濃，漚鷺翩下上。", "漁舟何者子，佇目看烟浪。"]'),
('ff20fd9c-a30d-4b3d-8eb3-7a390ae1138b','過姑孰作','米芾','宋','宋诗','song-poetry','','[]','下輿照澗數星星，一世還如隔世經。',32,'全唐诗/poet.song.60000.json','["下輿照澗數星星，一世還如隔世經。", "不見山東李十二，青山山色只青青。"]'),
('6dd09c9d-ba98-46fe-bf9d-d5680fbbbb68','皇太后挽辭  其一','米芾','宋','宋诗','song-poetry','','[]','餘慶源真相，求賢佐裕陵。',48,'全唐诗/poet.song.60000.json','["餘慶源真相，求賢佐裕陵。", "知幾捲箔早，戡變叱龍升。", "靜德羣邪震，清心後世矜。", "大恩知欲報，聖孝已踰曾。"]'),
('3f37aaa1-4720-442f-b21e-de1ff708b610','皇太后挽辭  其二','米芾','宋','宋诗','song-poetry','','[]','溫厚同光獻，剛廉法寶慈。',48,'全唐诗/poet.song.60000.json','["溫厚同光獻，剛廉法寶慈。", "擁扶樂推聖，照徹托公欺。", "南紀歸忠魄，東朝足素規。", "仁明存舊幄，常似補天時。"]'),
('549e4293-6aad-4f60-9d6d-05a88ee5be18','都梁十景詩 龜山寺晚鐘','米芾','宋','宋诗','song-poetry','','[]','龜峰高聳接雲樓，撞月鐘聲吼鐵牛。',32,'全唐诗/poet.song.60000.json','["龜峰高聳接雲樓，撞月鐘聲吼鐵牛。", "一百八聲俱聽徹，夜行猶自不知休。"]'),
('e030121f-e9c8-4cc9-bb3b-fc5cd4f893c7','都梁十景詩 五塔寺歸雲','米芾','宋','宋诗','song-poetry','','[]','塔邊雲影任高低，閒逐清風自在飛。',32,'全唐诗/poet.song.60000.json','["塔邊雲影任高低，閒逐清風自在飛。", "四海望遥人久渴，不成霖雨又空歸。"]'),
('2370ecf9-a81b-4af6-a9b2-669a1373349f','都梁十景詩 瑞巖庵清眺','米芾','宋','宋诗','song-poetry','','[]','西山月落楚天低，不放紅塵點翠微。',32,'全唐诗/poet.song.60000.json','["西山月落楚天低，不放紅塵點翠微。", "鶴唳一聲松露滴，水晶寒溼道人衣。"]'),
('73472cbc-2243-43f6-919f-52044e1ef438','都梁十景詩 清風山聞笛','米芾','宋','宋诗','song-poetry','','[]','鐵笛誰吹一曲哀，清風約我上層臺。',32,'全唐诗/poet.song.60000.json','["鐵笛誰吹一曲哀，清風約我上層臺。", "悠揚正到堪聽處，怕惹閒愁却下來。"]'),
('3114c2fe-b87f-4bf6-9887-b8258d68e3bd','都梁十景詩 八仙臺招隠','米芾','宋','宋诗','song-poetry','','[]','山徑重重鎖綠苔，松花曾見幾番開。',32,'全唐诗/poet.song.60000.json','["山徑重重鎖綠苔，松花曾見幾番開。", "羣仙費盡招呼力，那得休官一箇來。"]'),
('c1608816-8257-42b0-9f97-38c91c148879','都梁十景詩 杏花園春晝','米芾','宋','宋诗','song-poetry','','[]','風輕雲淡午天春，花外遊人載酒樽。',32,'全唐诗/poet.song.60000.json','["風輕雲淡午天春，花外遊人載酒樽。", "不是山屏遮隔斷，牧童錯指是孤村。"]'),
('d32cb41e-016a-4694-907d-6e9c973db97b','都梁十景詩 玻瓈泉浸月','米芾','宋','宋诗','song-poetry','','[]','半山亭下老苔錢，鑿破玻瓈引碧泉。',32,'全唐诗/poet.song.60000.json','["半山亭下老苔錢，鑿破玻瓈引碧泉。", "一片玉蟾留不住，夜深飛入鏡中天。"]'),
('f1196417-fc6d-4169-8248-113196de3dea','都梁十景詩 會景亭陳迹','米芾','宋','宋诗','song-poetry','','[]','自是韶光不耐秋，水光山色一時休。',32,'全唐诗/poet.song.60000.json','["自是韶光不耐秋，水光山色一時休。", "細將瓦礫分明看，片片飛來落葉愁。"]'),
('23aa15e3-e42e-4bd6-bbb7-d491f8cc84de','都梁十景詩 寶接山落照','米芾','宋','宋诗','song-poetry','','[]','怪石纍纍玉作堆，登臨晚景更徘徊。',32,'全唐诗/poet.song.60000.json','["怪石纍纍玉作堆，登臨晚景更徘徊。", "夕陽無限堪停好，莫到奇山空自迴。"]'),
('7994cb6e-a1aa-415c-81db-f091905948c1','望海樓','米芾','宋','宋诗','song-poetry','','["\u548f\u7269\u8bd7", "\u548f\u7269", "\u5199\u666f"]','雲間鐵甕近青天，縹緲飛樓百尺連。',64,'全唐诗/poet.song.60000.json','["雲間鐵甕近青天，縹緲飛樓百尺連。", "三峽江聲流筆底，六朝帆影落尊前。", "幾番畫角催紅日，無事滄洲起白烟。", "忽憶賞心何處是，春風秋月兩茫然。"]'),
('c707beff-b8eb-406a-84ea-c810f6120669','甘露寺','米芾','宋','宋诗','song-poetry','','[]','六代蕭蕭木葉稀，樓高北固落殘暉。',64,'全唐诗/poet.song.60000.json','["六代蕭蕭木葉稀，樓高北固落殘暉。", "兩州城郭青烟起，千里江山白鷺飛。", "海近雲濤驚夜夢，天低月露溼秋衣。", "使君肯負時平樂，長倒金鍾盡醉歸。"]'),
('cf69cf17-ad73-470f-abb6-28bb0177f6ef','雜詠','米芾','宋','宋诗','song-poetry','','[]','揚清歌，發皓齒，北方佳人東鄰子。',96,'全唐诗/poet.song.60000.json','["揚清歌，發皓齒，北方佳人東鄰子。", "且吟白紵停綠水，長袖拂面爲君起。", "寒雲夜卷霜海空，胡風吹天飄塞鴻。", "玉顔滿堂樂未終，館娃日落歌吹濃。", "弦歌興罷拂衣還，棄米何嘗有俸錢。", "恩自大鈞能逐物，只應訪藥是優賢。"]'),
('27c9ff87-26dc-4224-8780-c6da68af44d1','閶門舟中戲作呈伯原志東  其一','米芾','宋','宋诗','song-poetry','','[]','蘋風忽起吹舟悍，雨打圖書藏裹亂。',64,'全唐诗/poet.song.60000.json','["蘋風忽起吹舟悍，雨打圖書藏裹亂。", "閶門咫尺不安流，何况盟津與江漢。", "非無輕檝并長槹，逆風流水適相遭。", "須臾風迴水流順，星宿浮槎問月高。"]'),
('8bc3d55f-9c37-4161-9865-65402ec07d74','閶門舟中戲作呈伯原志東  其二','米芾','宋','宋诗','song-poetry','','[]','吳王故苑古長洲，潮汐池邊一佇留。',32,'全唐诗/poet.song.60000.json','["吳王故苑古長洲，潮汐池邊一佇留。", "秀蕙芳蘭無處所，荒莞叢葦滿清流。"]'),
('00f78025-7b64-4488-a438-0e44b6cb0b04','觀音巖','米芾','宋','宋诗','song-poetry','','[]','秦驅禹鑿已寥寥，却爲高人得姓焦。',64,'全唐诗/poet.song.60000.json','["秦驅禹鑿已寥寥，却爲高人得姓焦。", "鮑餌有時邀楚釣，海雲常覺護山樵。", "巖多陰霧龍藏角，虹絓蒼林玉露臕。", "濁氣不侵靈貺下，方壇曾駐紫清飆。"]'),
('e725023c-c166-4805-9b77-c180aa2ac0e0','貞娘墓歌','米芾','宋','宋诗','song-poetry','','[]','何不學仙冢纍纍，白楊西郭陰風悲。',128,'全唐诗/poet.song.60000.json','["何不學仙冢纍纍，白楊西郭陰風悲。", "虎邱一叩貞娘墓，薜荔援牆委蘭露。", "千歲蒙茸幾樹花，夜飄鬼火曉啼鴉。", "向憐挾瑟彈清月，猶憶吹簫乘彩霞。", "吳閶少年往來道，黛蛾釵燕誰能好。", "酒滴春雲夢不消，泉聲幽咽鐘聲老。", "陌上行遊緩緩歸，昨日紅顔今日非。", "東望闔閭穿葬處，玉鳬將化湛盧飛。"]'),
('48f50edf-83e3-4ce8-8baa-d226e374612a','不集南山','米芾','宋','宋诗','song-poetry','','[]','山翁茗艼葛彊隨，庭下青春鸞雀飛。',32,'全唐诗/poet.song.60000.json','["山翁茗艼葛彊隨，庭下青春鸞雀飛。", "幕府慣爲方外客，風前嬾易道家衣。"]'),
('d049db43-c5a8-472c-8c62-a8d067273cab','弈棋圖歌','米芾','宋','宋诗','song-poetry','','[]','神仙縹緲何年別，忽此逢迎山石裂。',96,'全唐诗/poet.song.60000.json','["神仙縹緲何年別，忽此逢迎山石裂。", "前溪練瀑派玉簾，更後雲林霧痕缺。", "聚頭磕額方外人，擔肩抱蟾骨法新。", "棋枰對弈環座看，誰信樵斧忘青春。", "我今髮雪三千丈，尚要崑崙撐頂上。", "爐心且養九轉丹，拂却銖衣記無恙。"]'),
('5c43340b-a943-401f-8536-eac5b9f2adc4','龍團歌','米芾','宋','宋诗','song-poetry','','[]','瀛帥謝公之所惠，大如車輪輕如紙。',107,'全唐诗/poet.song.60000.json','["瀛帥謝公之所惠，大如車輪輕如紙。", "磨而試之墨過漆，元非本約重違意，寒雀比之立憔悴。", "道寧萬一歸於彼，不督芙蓉乃恕耳。", "三木模研理固異，耿墨比此天與地。", "開匣付介驚欲墜，惜之不得幾下淚。", "君匣{犭噩}州便可碎，只留承晏使執侍。"]'),
('712094b8-1b5f-49e7-b00e-8e70c955bea3','瀑布詩','米芾','宋','宋诗','song-poetry','','[]','吾有瀑布詩，古今賽不得。',24,'全唐诗/poet.song.60000.json','["吾有瀑布詩，古今賽不得。", "最好是一條，界破青山色。"]'),
('3788465c-d9db-4e25-bb37-8dcd96aac904','堯山','米芾','宋','宋诗','song-poetry','','[]','信美此山高，穹窿遠朝市。',24,'全唐诗/poet.song.60000.json','["信美此山高，穹窿遠朝市。", "暑水結蒼陰，飛泉落晴翠。"]'),
('4bb0c6f4-584a-4364-aa82-b6f224bad427','和嚴道培書院韵  其一','米芾','宋','宋诗','song-poetry','','[]','城頭山脚舊圖開，華構凌雲亦壯哉。',64,'全唐诗/poet.song.60000.json','["城頭山脚舊圖開，華構凌雲亦壯哉。", "談席昔人文獻地，升堂此日豫章材。", "弦歌化裏清風動，麟鳳天南紫氣來。", "獨奈巖阿叢桂冷，幽棲不是偉長才。"]'),
('922396cf-9325-4af0-bc81-704199610f77','和嚴道培書院韵  其二','米芾','宋','宋诗','song-poetry','','[]','高館搴帷萬象開，西山翠入氣佳哉。',64,'全唐诗/poet.song.60000.json','["高館搴帷萬象開，西山翠入氣佳哉。", "六經重振南方學，千里還徵上駕材。", "鸞鶴遶庭翔更集，雲霞拂棟去還來。", "古今同被弦歌化，林卧其如老不才。"]'),
('023e2510-b91a-4aa4-b85a-df0b53ccbd3b','題寶珠閣','米芾','宋','宋诗','song-poetry','','[]','對檻青山露，羣仙捧寶珠。',24,'全唐诗/poet.song.60000.json','["對檻青山露，羣仙捧寶珠。", "求遺如起定，象罔是文殊。"]'),
('fe143c26-56a3-4382-bbaa-5fc5d07a51b9','虹縣舊題二首  其一','米芾','宋','宋诗','song-poetry','','[]','快霽一天清洲氣，健帆千里碧榆風。',32,'全唐诗/poet.song.60000.json','["快霽一天清洲氣，健帆千里碧榆風。", "滿船書畫同明月，十日隨風窈窕中。"]'),
('b19879f9-2434-4711-a70c-4baf3de2ccf9','虹縣舊題二首  其二','米芾','宋','宋诗','song-poetry','','[]','碧榆綠柳舊遊中，華髮蒼顔未退翁。',64,'全唐诗/poet.song.60000.json','["碧榆綠柳舊遊中，華髮蒼顔未退翁。", "天使殘年司筆硯，聖知小學是家風。", "長安又到人徒老，吾道何時定復東。", "題柱扁舟真老矣，竟無事業奏膚公。"]'),
('b1b1ebce-1937-4c11-95e0-15784945efaa','秋暑憩多景樓','米芾','宋','宋诗','song-poetry','','[]','縱目天容曠，披襟海共開。',48,'全唐诗/poet.song.60000.json','["縱目天容曠，披襟海共開。", "山光隨眥到，雲景渡江來。", "世界慚雙足，生涯付一杯。", "橫風多景夢，應似穆王臺。"]'),
('eb201f78-e202-44ad-8fa7-c836ca994d45','題董北苑畫','米芾','宋','宋诗','song-poetry','','[]','千峰突兀插空立，萬木蕭疏擁澗陰。',32,'全唐诗/poet.song.60000.json','["千峰突兀插空立，萬木蕭疏擁澗陰。", "日暮草堂猶未掩，從知塵土遠山林。"]'),
('499f133d-8fb6-4625-958f-743f1a313737','琴詩','米芾','宋','宋诗','song-poetry','','[]','澹乎無味中，指下清音發。',24,'全唐诗/poet.song.60000.json','["澹乎無味中，指下清音發。", "□□□□□，空山墮凉月。"]'),
('d4c49cef-c9f2-4b1f-9b24-5b905b41f110','開先寺觀瀑布','米芾','宋','宋诗','song-poetry','','[]','度挾捫青玉，臨深坐綠苔。',48,'全唐诗/poet.song.60000.json','["度挾捫青玉，臨深坐綠苔。", "水從雙劍下，山挾兩龍來。", "春暖花驚雪，林空石迸雷。", "塵纓聊此濯，欲去首重回。"]'),
('4cd5b81d-c183-4960-9f17-bbc99c156484','詩二首  其一','米芾','宋','宋诗','song-poetry','','[]','水勢臨階轉，峰形對路開。',48,'全唐诗/poet.song.60000.json','["水勢臨階轉，峰形對路開。", "槎從天上得，石是海邊來。", "瑞草分叢種，祥花間竹栽。", "舊傳辭賦客，唯見有鄒枚。"]'),
('3e774489-6109-446c-b8da-0196a573f2b0','詩二首  其二','米芾','宋','宋诗','song-poetry','','[]','携琴遶碧沙，搖葦弄青霞。',48,'全唐诗/poet.song.60000.json','["携琴遶碧沙，搖葦弄青霞。", "杜若幽庭草，芙蓉曲沼花。", "宴遊來野客，形勝得山家。", "往往留仙步，登攀日易斜。"]'),
('073451f5-e8bc-4fa4-a1ee-37b786df649a','詩三首  其一','米芾','宋','宋诗','song-poetry','','[]','三閭宰國議，相如造承明。',24,'全唐诗/poet.song.60000.json','["三閭宰國議，相如造承明。", "莫教朝廷上，不及爲郡名。"]'),
('e70198c5-41ae-4801-b52d-46f8ed6ccba3','詩三首  其二','米芾','宋','宋诗','song-poetry','','[]','幾時越五湖，行行遂所適。',24,'全唐诗/poet.song.60000.json','["幾時越五湖，行行遂所適。", "之子方樂天，衆累焉能迫。"]'),
('d616777e-4178-43a3-93e3-744a98c5f371','詩三首  其三','米芾','宋','宋诗','song-poetry','','[]','閒中無所事，得意思同論。',24,'全唐诗/poet.song.60000.json','["閒中無所事，得意思同論。", "約月升崇觀，校射出平原。"]'),
('d2631436-1870-46ee-aaa1-4563bf96529c','大臣薦對詩','米芾','宋','宋诗','song-poetry','','[]','笏引上天梯，鞘鳴奮地雷。',24,'全唐诗/poet.song.60000.json','["笏引上天梯，鞘鳴奮地雷。", "誰云天尺五，親見玉皇來。"]'),
('9920a179-6e66-4bb4-a7bb-2f29bbd80f57','驅蝗蟲詩','米芾','宋','宋诗','song-poetry','','[]','蝗蟲本是天災，不由人力擠排。',28,'全唐诗/poet.song.60000.json','["蝗蟲本是天災，不由人力擠排。", "若是敝邑遣去，却煩貴縣發來。"]'),
('26decfc1-37ef-420f-820f-ed38d803a722','謝吳安中留宿','米芾','宋','宋诗','song-poetry','','[]','肉眼通神四十年，侯門拖袖氣如烟。',32,'全唐诗/poet.song.60000.json','["肉眼通神四十年，侯門拖袖氣如烟。", "符離經過無行李，西入皇都索相錢。"]'),
('8759f2a1-2517-40cc-b600-f1c5da8fde4c','寄題開福院白蓮堂  其一','米芾','宋','宋诗','song-poetry','','[]','二林消息已千年，戲向池中種白蓮。',32,'全唐诗/poet.song.60000.json','["二林消息已千年，戲向池中種白蓮。", "昨夜秋香逐霜雪，又看蓮子藕如船。"]'),
('5758111e-20d7-422c-bfed-4b2f3644dba0','寄題開福院白蓮堂  其二','米芾','宋','宋诗','song-poetry','','[]','舊多社客談因果，新向禪林問祖風。',32,'全唐诗/poet.song.60000.json','["舊多社客談因果，新向禪林問祖風。", "歸去萬緣無不了，這回洗鉢聽齋鐘。"]'),
('d00c882d-eb35-4c93-9597-bed1d304f61e','干越亭','米芾','宋','宋诗','song-poetry','','[]','長卿骨已朽，延陵得茲亭。',72,'全唐诗/poet.song.60000.json','["長卿骨已朽，延陵得茲亭。", "延平廖明略，大句題軒楹。", "遂令干越俗，擅此今古名。", "高詠劉廖句，白雲穿石屏。", "琵琶洲無弦，我彈君能聽。", "彈罷共一笑，白雲歸玉京。"]'),
('84e42688-71e8-45b4-9fec-69227fe063a3','題李伯時山陰圖許元度王逸少謝安石支道林四像二首  其一','米芾','宋','宋诗','song-poetry','','[]','一幅輕綃三尺闊，百歲丹青半鹿脫。',32,'全唐诗/poet.song.60000.json','["一幅輕綃三尺闊，百歲丹青半鹿脫。", "誰將光景寫吳綾，神采森然動毫末。"]'),
('649428b4-9b8d-49f3-98e1-36ca91b6d778','題李伯時山陰圖許元度王逸少謝安石支道林四像二首  其二','米芾','宋','宋诗','song-poetry','','[]','臨卷嘆張芝，筆格入妙思。',36,'全唐诗/poet.song.60000.json','["臨卷嘆張芝，筆格入妙思。", "疏眉映朗目，白玉無泥滓。", "堂堂偉且長，想見坦腹姿。"]'),
('383dde27-698c-4501-8280-2d66fae3dad3','龍井延恩衍慶院','米芾','宋','宋诗','song-poetry','','[]','竹徑隨泉上，山雲觸石生。',24,'全唐诗/poet.song.60000.json','["竹徑隨泉上，山雲觸石生。", "寶棲彈指處，的的是分明。"]'),
('c17394ad-0834-4f71-9f4b-998fd49eef54','懷南唐研山','米芾','宋','宋诗','song-poetry','','[]','研山不復見，哦詩徒嘆息。',24,'全唐诗/poet.song.60000.json','["研山不復見，哦詩徒嘆息。", "唯有玉蟾蜍，向余頻唳滴。"]'),
('487d1bc5-604d-4eef-a5b4-0ad8e118430e','題越人王脩竹所藏雪竇禪師真跡','米芾','宋','宋诗','song-poetry','','[]','一幅昏昏半已空，何人重出自爲工。',32,'全唐诗/poet.song.60000.json','["一幅昏昏半已空，何人重出自爲工。", "從茲萬偈並千頌，擾亂春風卒未窮。"]'),
('e63b96e8-0dda-4106-9543-f10e7871ca9b','鷄黍','米芾','宋','宋诗','song-poetry','','[]','鷄黍招要意已真，後堂許到轉相親。',64,'全唐诗/poet.song.60000.json','["鷄黍招要意已真，後堂許到轉相親。", "巧裁花竹豈多地，浄掃軒窗無一塵。", "傾倒不知情話密，衰隤深畏酒行頻。", "落花一夜成疏迹，風雨還增客恨新。"]'),
('7649c70d-88a1-4a3c-8c80-0d24cda7bec3','題馬遠作四皓弈棋圖橫卷','米芾','宋','宋诗','song-poetry','','[]','落落四皓翁，山林養其靜。',72,'全唐诗/poet.song.60000.json','["落落四皓翁，山林養其靜。", "羞爲漢家臣，若辟秦苛政。", "商顔高峨峨，坐待天下定。", "欻起佐儲皇，上前啟名姓。", "堪憐羽翼成，難將口舌爭。", "無語及扶蘇，空歌紫芝咏。"]'),
('8c59b478-b5a4-4e57-b428-be88d607b08b','題定武蘭亭古本','米芾','宋','宋诗','song-poetry','','[]','翰墨風流冠古今，鵝池誰不賞山陰。',32,'全唐诗/poet.song.60000.json','["翰墨風流冠古今，鵝池誰不賞山陰。", "此書雖向昭陵朽，刻石猶能易黄金。"]'),
('455b6d0e-a85f-4082-8517-0b039f72c293','題禪堂壁間','米芾','宋','宋诗','song-poetry','','[]','水石相搏，風竹相吞。',20,'全唐诗/poet.song.60000.json','["水石相搏，風竹相吞。", "爐烟方裊，草木自欣。"]'),
('7d2c849e-2808-41ea-95db-c87443d149e1','壯觀亭','米芾','宋','宋诗','song-poetry','','[]','扶筇上瑶臺，一笑領清絕。',24,'全唐诗/poet.song.60000.json','["扶筇上瑶臺，一笑領清絕。", "如何夜來風，獨下前村雪。"]'),
('d6dbc263-1393-4504-a1b9-2fa02103f287','題仙掌石','米芾','宋','宋诗','song-poetry','','[]','碧海出蜃閣，青空起夏雲。',24,'全唐诗/poet.song.60000.json','["碧海出蜃閣，青空起夏雲。", "瑰奇□怪石，錯落動乾文。"]'),
('9e7ee80e-8b4c-4e14-a9a7-0790b8c3b860','送端臣桂林先生兼簡信叔老兄帥坐','米芾','宋','宋诗','song-poetry','','[]','驂鸞碧玉林，琢句白瓊瑶。',72,'全唐诗/poet.song.60000.json','["驂鸞碧玉林，琢句白瓊瑶。", "人間埃𡏖盡，青羅數分毫。", "程老列仙長，磊落粹露臕。", "玉瀝發太和，得君同逍遥。", "刻巖棲烏鴉，陟巘透紫霄。", "南風勿賦鵩，即是登雲軺。"]'),
('949f7f31-b6f4-48f1-9f34-cfe3dde8b262','太白江油尉廳詩','米芾','宋','宋诗','song-poetry','','[]','嵐光深院裏，傍砌水泠泠。',48,'全唐诗/poet.song.60000.json','["嵐光深院裏，傍砌水泠泠。", "野燕巢官舍，溪雲入古廳。", "日斜孤吏過，簾捲亂峰青。", "五色神仙尉，焚香讀道經。"]'),
('09aaf8ca-786b-40ce-b47c-b74cb5dbda33','題多景樓','米芾','宋','宋诗','song-poetry','','[]','華胥兜率夢曾游，天下江山第一樓。',96,'全唐诗/poet.song.60000.json','["華胥兜率夢曾游，天下江山第一樓。", "冉冉明廷萬靈入，迢迢溟海六鰲愁。", "指分坱圠方輿露，頂矗昭回列緯浮。", "衲子來時多泛鉢，漢星歸未覺經牛。", "雲移怒翼搏千里，氣霽剛風御九秋。", "康樂平生追壯觀，未知席上極滄洲。"]'),
('31a8afc7-40a7-42de-9a31-16322a139649','吳江舟中作','米芾','宋','宋诗','song-poetry','','[]','昨風起西北，萬艘皆乘便。',132,'全唐诗/poet.song.60000.json','["昨風起西北，萬艘皆乘便。", "今風轉而東，我舟十五縴。", "力乏更雇夫，百金尚嫌賤。", "船工怒鬭語，夫坐視而怨。", "添槔亦復車，黄膠生口嚥。", "河泥若祐夫，粘底更不轉。", "添金工不怒，意滿怨亦散。", "一曳如風車，叫啖如臨戰。", "傍觀鶑竇湖，渺渺無涯岸。", "一滴不可汲，況彼西江遠。", "萬事須乘時，汝來一何晚。"]'),
('1daa77e0-0482-4537-93be-8d4f916d1f43','題蘇東坡木石圖','米芾','宋','宋诗','song-poetry','','[]','四十誰云是，三年不製衣。',48,'全唐诗/poet.song.60000.json','["四十誰云是，三年不製衣。", "貧知世路險，老覺道心微。", "已是致身晚，何妨知我□。", "欣逢風雅伴，歲晏未言歸。"]'),
('b64c7a17-d478-40ed-b5e5-95635055c938','從天竺歸隠溪之南岡詩','米芾','宋','宋诗','song-poetry','','[]','昔年訪月寒溪頭，霜高酒劣稜生裘。',64,'全唐诗/poet.song.60000.json','["昔年訪月寒溪頭，霜高酒劣稜生裘。", "溪僧輟寢從吾幽，共移不繫漁人舟。", "斷崖老木紛金亂，又如蘋藻𣶬清流。", "鶴骨浸煩風露憂，妙語滿地無人收。"]'),
('298a131a-182e-4c51-97e0-df6396aae680','句  其一','米芾','宋','宋诗','song-poetry','','[]','清明去郡則得郡，安用作業解洗業。',16,'全唐诗/poet.song.60000.json','["清明去郡則得郡，安用作業解洗業。"]'),
('e946f4a9-29b4-4879-8936-ce919e82e359','句  其二','米芾','宋','宋诗','song-poetry','','[]','中間有一蕭閒伯，學道登仙初應格。',32,'全唐诗/poet.song.60000.json','["中間有一蕭閒伯，學道登仙初應格。", "朝元明日拜五光，玉皇應怪鬚眉白。"]'),
('22dabf60-ed80-4a77-8bde-3e0acea89bde','句  其三','米芾','宋','宋诗','song-poetry','','[]','金山醉歸江月出，瓜洲洶湧寒潮入。',16,'全唐诗/poet.song.60000.json','["金山醉歸江月出，瓜洲洶湧寒潮入。"]'),
('0d62b73f-a4ab-437c-89c5-072f307324b8','句  其四','米芾','宋','宋诗','song-poetry','','[]','飯白雲留子，茶甘露有兄。',12,'全唐诗/poet.song.60000.json','["飯白雲留子，茶甘露有兄。"]'),
('91d7d82b-a064-4e72-8f75-78fc37e195b6','句  其五','米芾','宋','宋诗','song-poetry','','[]','人是西方無量佛，壽如南極老人星。',16,'全唐诗/poet.song.60000.json','["人是西方無量佛，壽如南極老人星。"]'),
('a976e7d6-a808-44a9-a46c-4faaee7181bf','句  其六','米芾','宋','宋诗','song-poetry','','[]','手摩一丈石，讀盡上元碑。',12,'全唐诗/poet.song.60000.json','["手摩一丈石，讀盡上元碑。"]'),
('c5de3bbe-3b04-4219-b71e-ac28b02a1c54','句  其七','米芾','宋','宋诗','song-poetry','','[]','甘泉如惠泉。',6,'全唐诗/poet.song.60000.json','["甘泉如惠泉。"]'),
('09176927-e764-45fb-bd02-d1b77b12fb51','句  其八','米芾','宋','宋诗','song-poetry','','[]','孤嶼水中圓，遥空海邊闊。',12,'全唐诗/poet.song.60000.json','["孤嶼水中圓，遥空海邊闊。"]'),
('d81c259a-6991-490c-9a62-72c8c8f8bedc','句  其九','米芾','宋','宋诗','song-poetry','','[]','如來髓，釋迦骨。',16,'全唐诗/poet.song.60000.json','["如來髓，釋迦骨。", "人不識，彌勒佛。"]'),
('6504b6ef-3b36-4a9c-ab33-7eab0fa74f4b','神功盛德詩  其一','華鎮','宋','宋诗','song-poetry','','[]','茫茫神州，有疆有理。',36,'全唐诗/poet.song.60000.json','["茫茫神州，有疆有理。", "殲殄豺虎，翦夷荆杞。", "人可以羣，神獲其祀，惟宣祖是畀。"]'),
('a6311024-eb24-45f6-aea3-02edae558ebe','神功盛德詩  其二','華鎮','宋','宋诗','song-poetry','','[]','道有倫極，克建克敘。',41,'全唐诗/poet.song.60000.json','["道有倫極，克建克敘。", "不喪厥猷，物有其紀。", "既汙者隆，何千萬年。", "施于孫子，惟宣祖所畀。"]'),
('c805cdae-f35e-4f96-9cad-f0b01fe30ea0','神功盛德詩  其三','華鎮','宋','宋诗','song-poetry','','[]','其畀惟何，篤生真人。',40,'全唐诗/poet.song.60000.json','["其畀惟何，篤生真人。", "作之孔武，敏則有神。", "乃聖嗣德，益之以文。", "慶既令矣，克成厥勳。"]'),
('28ccda5d-d677-4352-bc25-99f11fdc0ae5','神功盛德詩  其四','華鎮','宋','宋诗','song-poetry','','[]','於皇武王，帝錫其猷。',50,'全唐诗/poet.song.60000.json','["於皇武王，帝錫其猷。", "克奮神武，應天之求。", "維睠乃顧，申命用休。", "獄訟謳歌，旁來不謀。", "高視虞夏，嗣于有周。"]'),
('f2eb502d-0064-421f-9b47-840afbf0508e','神功盛德詩  其五','華鎮','宋','宋诗','song-poetry','','[]','蠢爾小腆，昧天之靈。',55,'全唐诗/poet.song.60000.json','["蠢爾小腆，昧天之靈。", "弗念厥顯，首干我經。", "龍旂東指，淮海惟清。", "西狩三城，澤潞以平。", "皇皇天聲，如雷如霆，罔不震驚。"]'),
('ddb1ad02-d05d-4d4e-a506-39c8529666da','神功盛德詩  其六','華鎮','宋','宋诗','song-poetry','','[]','偏師四指，露檄旁招。',40,'全唐诗/poet.song.60000.json','["偏師四指，露檄旁招。", "負固銜璧，知幾造朝。", "凌江絕嶺，曾不崇朝。", "蜀道失險，關烽聿銷。"]'),
('154e4377-a681-48a5-8f06-37b7beac08e9','神功盛德詩  其七','華鎮','宋','宋诗','song-poetry','','[]','恢恢皇綱，周漢之後。',40,'全唐诗/poet.song.60000.json','["恢恢皇綱，周漢之後。", "唐嗣不武，實弛其紐。", "自我維之，律此羣醜。", "式相上帝，以奠九有。"]'),
('10d05f9b-962c-489b-962c-82a7c0ebf115','神功盛德詩  其八','華鎮','宋','宋诗','song-poetry','','[]','瞻彼亨龍，應時而作。',41,'全唐诗/poet.song.60000.json','["瞻彼亨龍，應時而作。", "維雲維雷，以引以翼。", "大人有徽音，物被其澤。", "德馨孔昭，休命爰錫。"]'),
('897197d1-da2f-4e7a-995c-083ae731cb56','神功盛德詩  其九','華鎮','宋','宋诗','song-poetry','','[]','蕞爾汾晉，穢我王路。',40,'全唐诗/poet.song.60000.json','["蕞爾汾晉，穢我王路。", "天誅久稽，爰赫斯怒。", "大明繼昭，晞彼朝露。", "文軌攸同，平平天步。"]'),
('0ec0c2df-1008-4c3a-885b-6c6ad569df77','神功盛德詩  其一○','華鎮','宋','宋诗','song-poetry','','[]','朱干琱戈，包以虎皮。',40,'全唐诗/poet.song.60000.json','["朱干琱戈，包以虎皮。", "脫劍解胄，敦說書詩。", "鍾鼓喤喤，俎豆儀儀。", "相我斯成，以永丕基。"]'),
('3fb77dc5-1916-4e08-9fab-469a80412529','神功盛德詩  其一一','華鎮','宋','宋诗','song-poetry','','[]','猗歟道真，厥心希微。',67,'全唐诗/poet.song.60000.json','["猗歟道真，厥心希微。", "我則道之，萬物紛錯，我攝之以無爲。", "股肱良矣，心膂則奇。", "蕩蕩妙用，民莫之知。", "既綏寰中，亦靜四夷。", "承休垂裕，維君維師。"]'),
('0888a4c5-5c00-412c-9e76-ddf623072fd9','神功盛德詩  其一二','華鎮','宋','宋诗','song-poetry','','[]','雍雍和聲，召彼協氣。',36,'全唐诗/poet.song.60000.json','["雍雍和聲，召彼協氣。", "散爲豐年，凝爲嘉瑞。", "三脊之茅，四海之美，惟帝王是致。"]'),
('824aa760-c18c-4ce3-a485-d4c7ca261edd','神功盛德詩  其一三','華鎮','宋','宋诗','song-poetry','','[]','巖巖太山，升於天中。',40,'全唐诗/poet.song.60000.json','["巖巖太山，升於天中。", "鸞輿戾止，玉檢金封。", "汾脽千里，親飛六龍。", "上下昭報，神明以通。"]'),
('5edfb7b8-7b63-476e-9eb0-050e32d122e0','神功盛德詩  其一四','華鎮','宋','宋诗','song-poetry','','[]','在昔圖書，出於河洛。',40,'全唐诗/poet.song.60000.json','["在昔圖書，出於河洛。", "有龍有龜，前聖之作。", "惟天無親，德侔斯格。", "我躬受之，寶符神筴。"]'),
('b2d186f8-5078-491a-87b5-dbf275e00bb0','神功盛德詩  其一五','華鎮','宋','宋诗','song-poetry','','[]','上天之載，引之惟逸。',40,'全唐诗/poet.song.60000.json','["上天之載，引之惟逸。", "原民之生，天子之職。", "我安其止，弗擾弗刻。", "厥德罔愆，宜符帝則。"]'),
('8cebc084-85d4-405b-9ce8-1ca32fce2aa2','神功盛德詩  其一六','華鎮','宋','宋诗','song-poetry','','[]','我征既寬，我役不煩。',40,'全唐诗/poet.song.60000.json','["我征既寬，我役不煩。", "息我干矛，審爾刑冤。", "井飲田食，日舒以閑。", "鴻化何爲，淳風載還。"]'),
('4854dfdb-338d-4451-84d8-1e644ffc554f','神功盛德詩  其一七','華鎮','宋','宋诗','song-poetry','','[]','俾爾息而庶，俾爾厚而富。',32,'全唐诗/poet.song.60000.json','["俾爾息而庶，俾爾厚而富。", "黄髮稚齒，既仁且壽。", "帝歆其馨，介我純祐。"]'),
('d27d5bbc-5f7b-48a5-8b80-87e39aaacf13','神功盛德詩  其一八','華鎮','宋','宋诗','song-poetry','','[]','其祐維何，如商之戊。',61,'全唐诗/poet.song.60000.json','["其祐維何，如商之戊。", "天地其行，既長且久。", "寵綏下民，克念厥後。", "取我元良，錫之九有。", "不失其傳，益羨三后。", "惟堯舜爲難，惟我則不。"]'),
('76403d65-1d35-4ddd-b461-15ecefb44919','神功盛德詩  其一九','華鎮','宋','宋诗','song-poetry','','[]','世德之淵，慶流瀰瀰。',50,'全唐诗/poet.song.60000.json','["世德之淵，慶流瀰瀰。", "篤生哲后，在宗之子。", "其積彌新，有聞不已。", "文考受之，以肖以似。", "人之攸歸，天命爰止。"]'),
('b6a7135b-4ae3-45ad-af76-5e6c2acbc5f7','神功盛德詩  其二○','華鎮','宋','宋诗','song-poetry','','[]','天命靡常，惟德惟功。',40,'全唐诗/poet.song.60000.json','["天命靡常，惟德惟功。", "神聖有作，曆數在躬。", "正位東朝，遂成大宗。", "協和萬邦，萬邦以雍。"]'),
('4d2d35d3-3c8f-4dc6-9365-304be0484fcb','神功盛德詩  其二一','華鎮','宋','宋诗','song-poetry','','[]','沈沈神機，其動其時。',40,'全唐诗/poet.song.60000.json','["沈沈神機，其動其時。", "和柔以剛，克愛以威。", "肅之振之，俾無或隳。", "功則未既，思有宏規。"]'),
('d21288dc-b53a-45a5-9de0-75e33d4bb26e','神功盛德詩  其二二','華鎮','宋','宋诗','song-poetry','','[]','皇有大猷，其成落落。',40,'全唐诗/poet.song.60000.json','["皇有大猷，其成落落。", "文武不世，千載無作。", "聖人勃興，積厚施博。", "作之新之，以底遠略。"]'),
('f496667c-fb7d-48e5-bfa2-defb8c6b816a','神功盛德詩  其二三','華鎮','宋','宋诗','song-poetry','','[]','既發我明，既達我聰。',50,'全唐诗/poet.song.60000.json','["既發我明，既達我聰。", "合變體經，神化無窮。", "長毓儒雅，蓄礪兵戎。", "無思不服，物有其容。", "夙夜不怠，濟我豐功。"]'),
('aabf7726-8459-4881-aaea-382b8059be3b','神功盛德詩  其二四','華鎮','宋','宋诗','song-poetry','','[]','濟濟朝廷，有名有實。',40,'全唐诗/poet.song.60000.json','["濟濟朝廷，有名有實。", "多士在服，百工勵翼。", "禮樂興矣，刑政既達。", "郁乎有文，紹周之則。"]'),
('f585df62-d5d2-4225-a170-47e029f70dfd','神功盛德詩  其二五','華鎮','宋','宋诗','song-poetry','','[]','綿綿句麗，莽莽河湟。',46,'全唐诗/poet.song.60000.json','["綿綿句麗，莽莽河湟。", "絕彼東海，逸于西疆。", "或翦或懷，德威孔揚。", "列我郡縣，襲我衣裳，於前人有光。"]'),
('951a3de4-8e7d-40da-bf87-bbd5d179a77b','詠古十六首  其一','華鎮','宋','宋诗','song-poetry','','[]','衮衣自美好，無能被猿猱。',180,'全唐诗/poet.song.60000.json','["衮衣自美好，無能被猿猱。", "鶢鶋巢魯門，惻愴臨九牢。", "此物乃異類，珍華宜見逃。", "潁陽本無人，嗜好非羽毛。", "執心一何苦，用形一何勞。", "采薇代芻豢，芻豢氣膻臊。", "飲水寧手掬，飄風聲怒號。", "不慕黄屋尊，遺之如秋毫。", "道真固所重，無乃太囂囂。", "達士各有心，非志斯鬰陶。", "飲河已盈腹，河流自滔滔。", "一枝儻可棲，雲構如蓬蒿。", "適外皆長物，逐物非吾曹。", "如何市朝人，捐生競錐刀。", "頹川無回波，始覺素風高。"]'),
('83f85d6a-4da2-4ded-84bd-c5954d0073f7','詠古十六首  其二','華鎮','宋','宋诗','song-poetry','','[]','穆王有天下，王綱正齊肅。',156,'全唐诗/poet.song.60000.json','["穆王有天下，王綱正齊肅。", "玉帛來萬邦，明堂覆重屋。", "珠金嚴器皿，龍章粲華服。", "玉戚副朱干，英莖薦清曲。", "窈窕備嬪御，芳顔美如玉。", "文章窮制作，采色已繁縟。", "晚與化人遊，清都暫經目。", "夢回顧人世，愴恨情不足。", "九重深且嚴，視若窘羈束。", "腐朽視玉石，膻惡生膏沐。", "倏起駕八駿，凌飛厲黄鵠。", "遠尋西王母，高宴崑山麓。", "歸來九廟荒，日暮歌黄竹。"]'),
('09b52d5d-15b8-4c3f-b670-df600f6ba9b4','詠古十六首  其三','華鎮','宋','宋诗','song-poetry','','[]','黄河天上來，一曲一千里。',108,'全唐诗/poet.song.60000.json','["黄河天上來，一曲一千里。", "馮夷值海若，反顧忘秋水。", "通川不足多，支流寧復紀。", "大樸久已喪，羣言亂如麻。", "儒墨及刑名，交流自名家。", "曲士殉所察，紛紛摘其華。", "伯陽究宗本，爲言天地初。", "蟪蛄驚春秋，格言落玄虛。", "華顛困章句，强識家人書。"]'),
('d38e3f01-b18b-4927-8176-9af21d0a912b','詠古十六首  其四','華鎮','宋','宋诗','song-poetry','','[]','長劍寄寶匣，往往夜鳴吼。',192,'全唐诗/poet.song.60000.json','["長劍寄寶匣，往往夜鳴吼。", "芒針補弊履，雖賤不爲醜。", "藏器貴有施，斯人自吾偶。", "汲汲出疆贄，皇皇喪家狗。", "無愧三宿行，未多沮溺耦。", "營丘執羔客，乃是射鈎手。", "解縛履文陛，低顔亦含垢。", "魯堂品藻中，茂實帝王後。", "君子當際會，所學問行否。", "南陽三顧日，不羨商巖叟。", "相期等釣璜，茲爲兆熊后。", "宿將輕少年，前席亦何有。", "恢恢王景略，落落秦關右。", "周旋二十年，初心了無負。", "何必逐桓溫，聯翩東南走。", "松栢儻莫依，嵩岱皆培塿。"]'),
('60186d2a-4b6e-4a6e-8b2a-406d1141e73f','詠古十六首  其五','華鎮','宋','宋诗','song-poetry','','[]','昔在戰國時，吳生固多奇。',144,'全唐诗/poet.song.60000.json','["昔在戰國時，吳生固多奇。", "弱魯偶以將，彊齊不能支。", "聿來守西河，縱橫各有施。", "黔首樂無貳，財用日以滋。", "士卒思致命，官事咸允釐。", "韓趙既來賓，秦人怯東窺。", "魏郊昔多壘，中外安且熙。", "當時計其功，誰復相等夷。", "盛德乃不器，中智各有宜。", "由來秉國鈞，不類提軍綏。", "論列謾紛錯，至當難重違。", "桓桓蓋世氣，低徊下卑辭。"]'),
('9cd1a97e-364b-4507-a0bc-6b987f8fbdc3','詠古十六首  其六','華鎮','宋','宋诗','song-poetry','','[]','風雲起幽朔，霜雪彫松桂。',180,'全唐诗/poet.song.60000.json','["風雲起幽朔，霜雪彫松桂。", "修竹實不華，猗梧慘憔悴。", "江漢凝以沍，醴泉更蒙蔽。", "鸞鳳何所歸，增擊真良計。", "岐山盡禾黍，九成困惉懘。", "鳴矣後佳期，來儀爽幽契。", "烏鳶競腐鼠，仰視驚高逝。", "衆羽亦可懷，雲飛屢回睨。", "猗嗟魯先生，生後唐虞際。", "高華雖韡韡，碩果終幽翳。", "幅紙下聊城，片言挫秦銳。", "銛鋩釋紛難，未足論明哲。", "况復歷下談，微端本柔脆。", "時無豪傑士，橫議喧鶗鴂。", "春冰薄輕綃，可耐秋陽熭。"]'),
('708ed481-439a-42c0-816b-aede73f0a488','詠古十六首  其七','華鎮','宋','宋诗','song-poetry','','[]','黍稷無惡種，方苞藉良農。',168,'全唐诗/poet.song.60000.json','["黍稷無惡種，方苞藉良農。", "淳化混無外，殊疆藹同風。", "海濱昔未洽，盜弄潢池中。", "勝殘無善政，矧日勞兵戎。", "龔叟達事變，嘉言契清衷。", "鈇鑕何所施，鉤鉏日成功。", "鷄豚被封域，桑麻翳垣墉。", "天子念循良，召對明光宮。", "醉客雅輕事，臨歧願追從。", "厚意難重違，歸軒相與同。", "終藉哲人語，清風傃淵沖。", "小人徇其末，所得竟無庸。", "君子喻其大，道義在所攻。", "聯裾治水衡，遲暮何從容。"]'),
('9bdac81f-8a51-48c4-a1e1-53914a826717','詠古十六首  其八','華鎮','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','鮒魚在涸轍，所志斗升水。',120,'全唐诗/poet.song.60000.json','["鮒魚在涸轍，所志斗升水。", "斗升不可得，安望長江鯉。", "朝登禹門浪，回首風雷起。", "高才忽細行，脫略外譏毀。", "鄉閭不見容，縣令邈難邇。", "悠然挹斗酒，西遊咸陽市。", "一言悟時主，傾注超園綺。", "獻納無間言，經綸有餘美。", "平步躡雲漢，瞬息致千里。", "賈生終如遺，資用豈不偉。"]'),
('89acf9c7-15eb-4598-b95c-9b72197473f0','詠古十六首  其九','華鎮','宋','宋诗','song-poetry','','[]','三聖贊拔茅，拔茅有連茹。',168,'全唐诗/poet.song.60000.json','["三聖贊拔茅，拔茅有連茹。", "四始詠鳴鹿，鳴鹿嘯其類。", "性理儻可賞，微物在所貴。", "矧伊人倫秀，德輶自勤致。", "昔在世宗時，炎劉正昌熾。", "蒲輪聘枚叟，異人始麕至。", "鄭生何慷慨，稱薦天下士。", "嘉言美且閑，咀之有餘味。", "當朝尚趨和，浮沈在承意。", "囊括未足多，似忝司農位。", "獨以推轂賢，千秋仰高義。", "周公親吐握，事與田竇異。", "如何大將軍，碌碌無所譽。", "功業雖可名，風流固多愧。"]'),
('b188f601-b13c-4bf6-89bf-020e520c9e24','詠古十六首  其一○','華鎮','宋','宋诗','song-poetry','','[]','吾愛袁東陽，才華自天性。',96,'全唐诗/poet.song.60000.json','["吾愛袁東陽，才華自天性。", "注射溢飛泉，玲瓏韵鳴磬。", "微吟傍牛渚，傾寫江州聽。", "珠聯麟野韵，響答臨歧贈。", "倉卒宣城辭，顛沛長沙詠。", "辭林騁高步，聲華既明盛。", "不爲桓公屈，高風更嚴勁。", "榮路何足論，清衷自如瑩。"]'),
('336f09d8-abbe-467d-956d-30b5890d0001','詠古十六首  其一一','華鎮','宋','宋诗','song-poetry','','[]','興平昔喪亂，射狼恣吞攫。',144,'全唐诗/poet.song.60000.json','["興平昔喪亂，射狼恣吞攫。", "雄才卧南陽，盤桓寄雲壑。", "良玉沽善價，高情無適莫。", "風雲時會合，約束非纆索。", "蕭公鎮關中，守固惟筦鑰。", "韓彭冒鳴鏑，閫內非所度。", "成都偪仄地，草昧事參錯。", "顧盼乾坤靜，談笑風霆作。", "東連紫髯公，北設渭濱略。", "靈源挹愈盈，英風際寥廓。", "明知不自假，高談貴無怍。", "宿昔何所侔，夷吾暨燕樂。"]'),
('1df05a82-fb25-42a1-af28-1cb10a361fd3','詠古十六首  其一二','華鎮','宋','宋诗','song-poetry','','[]','窫窳當九門，西山寶騶虞。',120,'全唐诗/poet.song.60000.json','["窫窳當九門，西山寶騶虞。", "鴟鴞集上林，丹穴巢鵷雛。", "姦雄始基搆，哲人晦良圖。", "步兵偶叔末，整轡登蓬壺。", "身世委杯酒，不以禮法拘。", "長嘯引鳴鳳，新詩綴驪珠。", "慷慨臨廣武，感激慟窮途。", "所志豈方外，林下薄踟躕。", "恢恢大雅人，矯矯真龍駒。", "寧愧蘇門士，臨刑據槁梧。"]'),
('9a0ef46d-06d2-46ae-b3bd-ce7675b6e7bd','詠古十六首  其一三','華鎮','宋','宋诗','song-poetry','','[]','秋陽鑠金石，康莊晝如焚。',108,'全唐诗/poet.song.60000.json','["秋陽鑠金石，康莊晝如焚。", "乘軒及負荷，累足朝市門。", "揮汗散凌雨，騰埃播長雲。", "隋珠彈黄雀，貴賤誰復論。", "安知北窗下，乃有羲皇人。", "高卧挹清風，翛然遠世紛。", "綠琴寂繁奏，白醅漉綸巾。", "井水患甘旨，膏蘭困明芬。", "何用結廬地，喧填走車輪。"]'),
('b6c8a18d-426d-44f1-bf4f-c40a799942e6','詠古十六首  其一四','華鎮','宋','宋诗','song-poetry','','[]','唐昔先天後，天步復清平。',168,'全唐诗/poet.song.60000.json','["唐昔先天後，天步復清平。", "君王圖治定，槐棘來羣英。", "渭水亦投竿，莘原猶棄耕。", "丈夫敦志尚，不爲軒冕輕。", "矯矯同州守，素風獨崢嶸。", "慷慨論十事，激切觀王明。", "獻納無迕言，始來歆大烹。", "富貴豈不念，直道思有行。", "馭者信所學，不爲嬖奚更。", "况當秉國鈞，見利難自傾。", "行己或可枉，乘軒何所榮。", "風虎既相從，雲雷底光亨。", "開元及貞觀，當日乃懸衡。", "至今夸毗人，聞風心骨驚。"]'),
('fb8c0993-117f-4541-8ae6-6b9f5ca6b222','詠古十六首  其一五','華鎮','宋','宋诗','song-poetry','','[]','高柳何葱蒨，嫋嫋章臺端。',168,'全唐诗/poet.song.60000.json','["高柳何葱蒨，嫋嫋章臺端。", "眉葉蔭紫極，條絲拂朱欄。", "何以謝松竹，撓弱慚歲寒。", "既乏貞固姿，枝葉何足觀。", "小人殉利慾，俛仰如轉丸。", "苟非社稷臣，禍患寧肯干。", "蒲山已歸覲，黎陽尚盤桓。", "當時方寸地，明明赤如丹。", "飆舉冠凌烟，騰芳臭如蘭。", "一言失其所，功名兩彫殘。", "高帝論平陽，劉氏終以安。", "英公負文皇，武氏爲世患。", "無忌問趙相，侯嬴起長歎。", "白首不可保，知人良獨難。"]'),
('caceaa82-856e-4dfb-bf67-fbfd520c5f76','詠古十六首  其一六','華鎮','宋','宋诗','song-poetry','','[]','蘭芷生幽薄，浥露搴華姿。',168,'全唐诗/poet.song.60000.json','["蘭芷生幽薄，浥露搴華姿。", "芙容隔秋江，扁舟滿江湄。", "丈夫抱材用，但願君王知。", "甯生擊牛角，載歌南山詞。", "詞終脫裋褐，纓佩暮萎蕤。", "人事非有定，斯言或難持。", "翩翩李將軍，鳴弦壓由基。", "餘威震戎虜，談笑靜邊陲。", "桃李曾無言，嘉聲滿黄扉。", "心知堪萬戶，乃謂生匪時。", "烽火照甘泉，未能包虎皮。", "目視漢飛將，棄棄輕如遺。", "頗牧已黄土，忉忉勤緬思。", "如何中林士，坐視青雲期。"]'),
('1025460b-94ae-41c9-b62a-9a46c8a30494','古風','華鎮','宋','宋诗','song-poetry','','[]','瞻彼南山下，溝塍蔚相續。',96,'全唐诗/poet.song.60000.json','["瞻彼南山下，溝塍蔚相續。", "泉流既清美，土壤膏且沃。", "巖壑雲氣多，時雨常霑足。", "苦乏知人術，所寄非良淑。", "樹藝本未工，營私一何速。", "銚鎒不及時，終然廢穜稑。", "嘗恐歲云暮，蟋蟀鳴我屋。", "良苗不可見，何以望嘉穀。"]'),
('2c89f085-1ddf-4fe6-8fed-2d9772b2a7a5','讀孟東野懊惱詩','華鎮','宋','宋诗','song-poetry','','[]','東野不解事，强爲懊惱詞。',120,'全唐诗/poet.song.60000.json','["東野不解事，强爲懊惱詞。", "惡詩皆得官，舉世不及嗤。", "好詩空抱山，寂寞無人知。", "詩自有好惡，得官不在詩。", "白面無伎能，青雲多路歧。", "君無一囊錢，姻婭復爲誰。", "且保珪玉質，無使傷磷緇。", "文章古所貴，恐非涉世資。", "羽翼聖道術，收拾古佚遺。", "此外不可倚，倚文諒多奇。"]'),
('fd60aa29-2812-4d05-8e79-89932c82c5c6','小院','華鎮','宋','宋诗','song-poetry','','[]','小院無經過，虛庭窈深幽。',60,'全唐诗/poet.song.60000.json','["小院無經過，虛庭窈深幽。", "高堂晝晴永，朱箔上銀鈎。", "文砌桐花落，碧瓦烟光流。", "交疏靜丹綺，飛梁架青虬。", "流鶑自睍睆，好音暫遲留。"]'),
('36842889-a404-49fa-bc89-411d3f080a2b','早發蕪湖風便舟中有感','華鎮','宋','宋诗','song-poetry','','[]','長波西南騖，高風激江流。',180,'全唐诗/poet.song.60000.json','["長波西南騖，高風激江流。", "掛席向浦溆，凌虛駕輕舟。", "洲渚亂揮霍，蒹葭颯颼飀。", "重山捷飛過，疊浪紛悠悠。", "鳬鶩不及辨，頻咤越飛鷗。", "舟人擊鼓吹，謔浪相賡酬。", "調笑西來人，掩淚寒沙頭。", "人聞此語樂，我聞此言憂。", "爾速非爾巧，彼淹豈其尤。", "淹速偶所值，矜笑徒自偷。", "况余涉世途，泰稀否常稠。", "此日雖偶駛，來日恐或不。", "馭也儻可矜，留滯還增羞。", "天道雅無常，非分非所求。", "但願日日行，行路無阻修。"]'),
('e2b2ce45-0918-485e-a280-d7738f13b6c1','汎舟','華鎮','宋','宋诗','song-poetry','','[]','汎舟涉長川，舟巨川且廣。',108,'全唐诗/poet.song.60000.json','["汎舟涉長川，舟巨川且廣。", "操榜無良師，東西逐波蕩。", "左之蕉葦多，右之洲渚枉。", "中有安流道，可以詣所往。", "不習昧其從，終日勞蕩槳。", "蕩槳勞尚可，所憂波濤長。", "黑雲蔽白日，驚飈摧五兩。", "沈浮何足道，形生在反掌。", "豈無觴深人，疏絕不得賞。"]'),
('6a82f225-d50b-4b74-aa73-9f291db6d936','題竹軒詩','華鎮','宋','宋诗','song-poetry','','[]','歲寒青松青，落落惟修竹。',120,'全唐诗/poet.song.60000.json','["歲寒青松青，落落惟修竹。", "烟葉舒青翠，風莖戛蒼玉。", "高標契嘉士，暫挹情已足。", "况復清陰中，耽耽有華屋。", "屋下富經史，塤篪韵方睦。", "啄食日已肥，文綵更繁縟。", "側聆簫韶奏，聯翩赴清曲。", "秋色正蕭疏，庭宇清以肅。", "且復遶修林，采采黄金菊。", "莫學山陽客，顛倒困醽醁。"]'),
('2d97f0dd-e500-4ace-b1bf-835d988667bb','贈別新渭府機宜蔡二同年','華鎮','宋','宋诗','song-poetry','','[]','賈生流落處，寒日照山郭。',240,'全唐诗/poet.song.60000.json','["賈生流落處，寒日照山郭。", "江湖行欲盡，客意正寂寞。", "轂擊逢蔡侯，舊交宛不若。", "立談露底裏，貞意銷垠堮。", "握手笑登舟，杯盤已紛錯。", "初言敘交契，次問何漂泊。", "苦道行路長，舂陵亦墝埆。", "仲冬纔薄寒，秋水雖已落。", "湘山尚重疊，湘水亦浩漠。", "水深莫暮止，路遠宜晨作。", "委曲話津途，纖悉指棲托。", "前修共科名，分義曾不薄。", "此道久淪替，後生多落寞。", "頌君古人風，不爲一杯酌。", "我舟尚南邁，君馬方西躍。", "各指天一涯，何以慰離索。", "平凉古名鎮，扼控開戎幕。", "綠髮照青衫，從容預經略。", "從軍古所貴，清世尤多樂。", "已見六翮修，行看上遼廓。"]'),
('9e573a99-226d-4f98-a9a5-734853015131','宿道林寺詩','華鎮','宋','宋诗','song-poetry','','[]','鉦鼓遠轟填，旌旗近凌亂。',240,'全唐诗/poet.song.60000.json','["鉦鼓遠轟填，旌旗近凌亂。", "蘭棹截波艤，肩輿傍山轉。", "白羽映塵舉，烏紗倚風岸。", "揆才非阿都，託乘陪中散。", "暝投蕭寺迥，路入修林蒨。", "清談曾未既，長夜已踰半。", "周旋仰陂量，眄睞慚溝斷。", "欲倚青雲披，輕歌白石爛。", "高風生夜壑，長松響幽澗。", "秉燭訪陳跡，辭墨疊壯觀。", "纓蕤雖未濯，心目欣已浣。", "文奇楚招些，跡異元郎漫。", "初驚冰玉違，已見珠璣璨。", "臨池名草聖，天台得才冠。", "兼資古所稀，荐遇世尤願。", "琳琅鼓餘韵，蛟虯走芳翰。", "詣絕雅無倫，神變敏如幻。", "規爲到古始，氣槩起消懦。", "須知趙璧貴，祗借秦人玩。", "吟想情有餘，言終屢增歎。"]'),
('5cf01bf8-e1d5-4654-a61c-119275afaf10','汲水詩','華鎮','宋','宋诗','song-poetry','','[]','汲水苦綆短，低回就清淺。',108,'全唐诗/poet.song.60000.json','["汲水苦綆短，低回就清淺。", "綆短儻有續，重淵良不遠。", "清淺本無源，其涸易見睍。", "重淵酌愈出，流波被溝畎。", "膏肓苟願治，會須好俞扁。", "所之在萬里，庸可策駑蹇。", "白茅滿原隰，刈之何不勉。", "緝索綆乃長，單極恣舒卷。", "寄聲汲引者，功微利亦鮮。"]'),
('c25a2eaa-ee8e-4aa7-bf4d-7ba838cb2dd0','虛室','華鎮','宋','宋诗','song-poetry','','[]','軒前列羣山，軒後得虛室。',48,'全唐诗/poet.song.60000.json','["軒前列羣山，軒後得虛室。", "宛若成都居，枵然惟四壁。", "清明照窗牖，不待秋月色。", "萬籟悄無聲，終年飽岑寂。"]'),
('7e8f6c84-249d-4bde-96a7-6703527d9ead','頤軒詩','華鎮','宋','宋诗','song-poetry','','[]','土木謝琱華，結構趣閑敞。',48,'全唐诗/poet.song.60000.json','["土木謝琱華，結構趣閑敞。", "四座來風月，中庭容几杖。", "庭喧海潮至，窗暝山雲上。", "蕭散寄官曹，欣茲會清賞。"]'),
('e9c68db3-7d82-4b02-8685-7fe3d9a20f68','寶墨堂','華鎮','宋','宋诗','song-poetry','','[]','堂有顔公石，辭墨真世寶。',48,'全唐诗/poet.song.60000.json','["堂有顔公石，辭墨真世寶。", "圓潤屈銀鈎，淳華掞春藻。", "忠義昔所服，文藝久彌好。", "至今有識人，撫卷惜元老。"]'),
('f24eaaa8-49b1-42bd-a67a-dcb35bff34ef','廣述二首  其一','華鎮','宋','宋诗','song-poetry','','[]','茫茫太行道，日側嘯彫虎。',144,'全唐诗/poet.song.60000.json','["茫茫太行道，日側嘯彫虎。", "天明落檻穽，迥失山林阻。", "搖尾仰視人，意態已如鼠。", "烏鵲竟何爲，俛咮噪而聚。", "高明人共畏，鰥寡世所侮。", "丈夫氣如霜，所貴摧强禦。", "埋輪斥豺狼，不待梁冀死。", "長孺戒李息，張湯方遇主。", "古人恥低徊，吐茹兩不武。", "真節一朝奮，千載羞莽鹵。", "茲人不可見，茲事乃近古。", "三復清風詩，永懷仲山甫。"]'),
('ccec7fac-b347-48a7-97b1-87b41f034cb5','廣述二首  其二','華鎮','宋','宋诗','song-poetry','','[]','飄風入閶闔，九陌起黄埃。',120,'全唐诗/poet.song.60000.json','["飄風入閶闔，九陌起黄埃。", "馺遝振鳴珂，馳驅東西來。", "側足湊高明，珠箔爲褰開。", "附會崇岳友，沮譽牛李儕。", "傾側競姿媚，談笑足詼諧。", "朝爲道旁客，暮爲廊廟才。", "如何首陽人，悵望黄金臺。", "所得竟斗筲，回首良可哀。", "安見鄭子真，谷口日徘徊。", "嘉聲滿朝野，何用苦自媒。"]'),
('48f48674-aa9f-41bd-92b1-aa01e9c86dce','春日雜興十五首  其一','華鎮','宋','宋诗','song-poetry','','[]','季冬歲云暮，玄冥肅寒威。',72,'全唐诗/poet.song.60000.json','["季冬歲云暮，玄冥肅寒威。", "濃雲蔽白日，朔風戾天飛。", "霜華晝不消，木冰粲瓊枝。", "河漢凝以沍，松竹慘萎蕤。", "豺虎有饑色，况乃狐兔微。", "朝陽汎春光，黄雀鳴華榱。"]'),
('6053ff1a-d0fa-47a5-b1d7-8c4c49ed479d','春日雜興十五首  其二','華鎮','宋','宋诗','song-poetry','','[]','鳴禽斷殘夢，寒衾有餘溫。',72,'全唐诗/poet.song.60000.json','["鳴禽斷殘夢，寒衾有餘溫。", "褰帷覽東窗，朝陽汎晴暾。", "晨興不知倦，攝衣步南軒。", "碧瓦無寒霜，芳露浥蘭蓀。", "東風苦未競，愁見陰雲屯。", "登高遠四望，極目際郊原。"]'),
('25f7a464-f232-43d2-8100-5794a0416bb9','春日雜興十五首  其三','華鎮','宋','宋诗','song-poetry','','[]','三眠愁夜久，夙興坐高堂。',84,'全唐诗/poet.song.60000.json','["三眠愁夜久，夙興坐高堂。", "是時大火中，啟明在東方。", "曉月俯前楹，列星掩微芒。", "和風從東來，草木有流芳。", "欄花浥零露，密影森低昂。", "咸池浴朝日，照耀上扶桑。", "輕烟靄簾櫳，盈盈斂餘光。"]'),
('dc6e93ff-b9ad-45ca-aa7e-2375a7ee4ffe','春日雜興十五首  其四','華鎮','宋','宋诗','song-poetry','','[]','韶光入南園，芳樹囀珍禽。',108,'全唐诗/poet.song.60000.json','["韶光入南園，芳樹囀珍禽。", "弄月曉烟際，吟風夕陽林。", "間關調巧言，玲瓏韵鳴琴。", "密傳青帝意，說盡陽和心。", "採之芳林幽，置之華堂深。", "願言几席間，時聽林中音。", "朝餐屑崑玉，彫籠飾南金。", "引盼結綺疏，弄影高梧陰。", "三旬春欲暮，寫此如簧吟。"]'),
('e8c3eaec-6570-4311-aa74-ecf2202079d0','春日雜興十五首  其五','華鎮','宋','宋诗','song-poetry','','[]','緩步出東門，徘徊高城隅。',132,'全唐诗/poet.song.60000.json','["緩步出東門，徘徊高城隅。", "芳郊曉烟霽，極目眺平湖。", "遲日暖潜魚，東風汎菰蒲。", "陽和著萬物，動植皆昭蘇。", "行樂貴及時，流光易云徂。", "五陵少年客，燕趙傾城姝。", "憧憧滿金隄，盈盈雜簪裾。", "華龍儼上駟，冰雪瑩膚腴。", "帷花啟芳筵，藉草羅樽壺。", "搴條密相遺，巧笑情有餘。", "溱洧宛未妍，桑中良不如。"]'),
('8166738c-0029-430d-9379-e31b87ec4932','春日雜興十五首  其六','華鎮','宋','宋诗','song-poetry','','[]','東風入九門，細草有餘綠。',72,'全唐诗/poet.song.60000.json','["東風入九門，細草有餘綠。", "長楊散金縷，繚亂青樓曲。", "緗桃美於錦，素馨純如玉。", "名園搜未盡，春華已盈目。", "蘭蕙有天香，乃在山之麓。", "不與東風發，誰知顧中谷。"]'),
('f466e70c-f193-4c3f-916b-e53cf5aeff79','春日雜興十五首  其七','華鎮','宋','宋诗','song-poetry','','[]','姜庸曉相携，採桑高城東。',72,'全唐诗/poet.song.60000.json','["姜庸曉相携，採桑高城東。", "新妝競姚冶，危鬟較櫳鬆。", "袿襦無舊製，組繡有餘工。", "穿林逐流鶑，遵渚學驚鴻。", "密葉朝露晞，遠揚戾東風。", "日昃蠶已饑，采采不盈籠。"]'),
('c48d5832-7263-46ca-a011-c00bd12193c5','春日雜興十五首  其八','華鎮','宋','宋诗','song-poetry','','[]','虛懷湛秋水，拳石枕寒沙。',180,'全唐诗/poet.song.60000.json','["虛懷湛秋水，拳石枕寒沙。", "上栽九節蒲，依倚復欹斜。", "寄懷曲几穩，發秀終年嘉。", "細根散蒼髯，巨柢蟠青蛇。", "玉篦瑩故葉，劍鋩長新芽。", "融怡謝陽光，滋澤非露華。", "潔貞宛相適，吹噓曾不賒。", "乃知元氣游，脗合大道涯。", "生生無間斷，在在均邇遐。", "陰騭有異稟，朗應無爾差。", "故茲靈藥材，見重長年家。", "寧如溱洧贈，復異洛陽花。", "臭腐薦高腴，夭冶揚芬葩。", "栽培劇彫楮，徂謝迅飛霞。", "韶光瞬息移，不得延豪奢。"]'),
('163e8af3-88f2-4824-b429-ae3f8f4a8b5e','春日雜興十五首  其九','華鎮','宋','宋诗','song-poetry','','[]','東郊接南陌，芳樹繚脩隄。',120,'全唐诗/poet.song.60000.json','["東郊接南陌，芳樹繚脩隄。", "疏雨斂輕埃，十里平如坻。", "雲日弄晴陰，烟花淡低迷。", "往來多騕褭，躑躅赴東西。", "紫騮連錢花，青驄碧玉蹄。", "軒頭剝秋兔，闊臆竦鳴雞。", "金鑣響玲瓏，玉校光高低。", "促韁合組繡，脩策琢玻瓈。", "顧影斂逸足，迎風鬰長嘶。", "不逢王武子，與解錦障泥。"]'),
('4d49b9bc-08b6-4435-8b87-18726fa5703e','春日雜興十五首  其一○','華鎮','宋','宋诗','song-poetry','','[]','晴春厭密處，駕言出林坰。',108,'全唐诗/poet.song.60000.json','["晴春厭密處，駕言出林坰。", "捨車步蘅皋，緩带遵蘭汀。", "長林合葱蒨，綠陰透虛明。", "上有遷谷鶑，下聞求友聲。", "風和簧舌穩，薄暮耳猶傾。", "歸輈俯俄景，脩路尚安行。", "華鋪閉深院，嘉樹列前庭。", "高梧蔭綺窗，媚柳拂朱甍。", "安得谷中侶，晨昏此飛鳴。"]'),
('e8228eea-0d99-4e95-be1d-0102254c3a7b','春日雜興十五首  其一一','華鎮','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','迢遞長江表，崎嶇青障間。',120,'全唐诗/poet.song.60000.json','["迢遞長江表，崎嶇青障間。", "瑞草雜野卉，吐秀莫窮看。", "馥鬰誰與奇，細碎如等閒。", "荆榛共榮悴，樵牧幾摧殘。", "殊鄉採嘉聲，千里輳名園。", "輕舟走彫檻，文砌薦朱欄。", "芳華未盈枝，傾都已酡顔。", "疏叢乏葱蒨，薄采媿朱殷。", "珍賞占芳時，野客更舊觀。", "試問蜂和蝶，何如蕙與蘭。"]'),
('04203c49-94f1-445d-ab22-83a4f97be976','春日雜興十五首  其一二','華鎮','宋','宋诗','song-poetry','','[]','江梅燦瑶琨，緒風未成和。',144,'全唐诗/poet.song.60000.json','["江梅燦瑶琨，緒風未成和。", "紅藥簇雲錦，韶光已蹉跎。", "臘寒苦難任，秋陽暴如何。", "寧知桃李樹，乘春蔚婆娑。", "二月艷陽天，兩京佳麗多。", "五陵浮瑞氣，三州翻綠波。", "宮槐出華闕，御柳夾銀河。", "玄鳥雜飛舞，黄鸝競鳴歌。", "芳蹊展平練，繁艷簇香羅。", "浥露笑金谷，迎風媚銅駝。", "落英縱紛紛，珍實已峨峨。", "莫訝潘河陽，盈城意靡他。"]'),
('70b5fd73-82a6-49af-8c47-ca0825934467','春日雜興十五首  其一三','華鎮','宋','宋诗','song-poetry','','[]','纖纖蘭蕙甲，青青楊柳絲。',180,'全唐诗/poet.song.60000.json','["纖纖蘭蕙甲，青青楊柳絲。", "草木有春華，園林競芳時。", "妝點貴銓次，高下有推移。", "連畛已端修，茅蹊盡平治。", "雕欄被丹雘，文甃合瑠璃。", "穿薄啟縈迂，拍隄汎漣漪。", "安排紅藥樹，映带牡丹枝。", "蔓草既誅鋤，秋榮亦芟夷。", "碧蘆斷修幹，丹蓼剪芳蕤。", "苞杞散不收，叢菊棄如遺。", "蘆蓼尚云可，杞菊或未宜。", "神功著西河，嘉聲藹東籬。", "朱實照金鼎，黄華登玉巵。", "暄凉雖異序，榮秀各有期。", "商飆掠春叢，摧折誰能支。"]'),
('8fd770f7-4dac-47c8-afe8-4fcc3f83d090','春日雜興十五首  其一四','華鎮','宋','宋诗','song-poetry','','[]','春華雜丹素，芳心馥椒蘭。',84,'全唐诗/poet.song.60000.json','["春華雜丹素，芳心馥椒蘭。", "蝴蝶採其榮，交飛密爲團。", "輕鬚卷絲緒，弱翅剪冰紈。", "栩栩婉有容，飛飛閑可觀。", "深叢密依倚，曲徑恣盤桓。", "日昃芳氣消，露晞黄粉乾。", "繁華未零落，幽意已闌珊。"]'),
('c3e7731b-1430-49a2-b1e8-883dafe04894','春日雜興十五首  其一五','華鎮','宋','宋诗','song-poetry','','[]','中和嘉會日，名都肆廣筵。',108,'全唐诗/poet.song.60000.json','["中和嘉會日，名都肆廣筵。", "華榱蔭簪裙，樽俎森盈前。", "主賓興方諧，威儀曾未愆。", "鳳簫密銀簧，瑶琴掩朱弦。", "衆優湊廣庭，跰𨇤颯回旋。", "被服偭古製，咿嗚操方言。", "鉦鼙雜鳴擊，促數競喧填。", "歌舞養心耳，心耳今煩悁。", "恐非君子音，不足延永年。"]'),
('5007ecb6-6a69-418f-877d-938fb15d20d3','和孫秀才醉中二首  其一','華鎮','宋','宋诗','song-poetry','','[]','封人祝多子，患寡不患小。',72,'全唐诗/poet.song.60000.json','["封人祝多子，患寡不患小。", "林慮行且歌，自喜身已老。", "五月日可畏，不踐門前道。", "北窗足虛閑，清風颯然到。", "况有樽中物，玉山恣傾倒。", "黄河或可斷，世事未云了。"]'),
('384b99df-76b2-4359-816d-90f6af838b2c','和孫秀才醉中二首  其二','華鎮','宋','宋诗','song-poetry','','[]','吾鄰有達士，時得問話言。',48,'全唐诗/poet.song.60000.json','["吾鄰有達士，時得問話言。", "寄身杯酒間，萬事不復論。", "大嚼青精飯，高岸白綸巾。", "愧非伯倫伴，辜此羲軒民。"]'),
('5a21cedd-775f-4da7-bbb8-1f270850b72d','瀑布','華鎮','宋','宋诗','song-poetry','','[]','蒼崖入青冥，飛泉下巖頂。',48,'全唐诗/poet.song.60000.json','["蒼崖入青冥，飛泉下巖頂。", "薄風春雷怒，照月秋練迥。", "清潤冷書幌，輕柔媚茶鼎。", "揮弄自忘歸，賞心意誰並。"]'),
('1c3e2766-fdcb-45a7-afae-2992469ce3c5','橫山','華鎮','宋','宋诗','song-poetry','','[]','戶外片山橫，長蛇勢繚繞。',48,'全唐诗/poet.song.60000.json','["戶外片山橫，長蛇勢繚繞。", "林疏無鷙獸，海近多鷗鳥。", "雲氣弄晴陰，烟光媚昏曉。", "坐中見樵采，隠隠下林杪。"]'),
('c38ea3e4-25b2-4487-87cb-2fc266abfcd1','懷嵩亭','華鎮','宋','宋诗','song-poetry','','[]','嵩高維神嶽，峻極上霄漢。',48,'全唐诗/poet.song.60000.json','["嵩高維神嶽，峻極上霄漢。", "臨登信舍地，庶入朝夕觀。", "垂簷碧雲低，带戶前山亂。", "何日見愚公，神棲夢輕斷。"]'),
('aa0743e8-3c10-4d4d-9250-3ccc724ad185','適南亭','華鎮','宋','宋诗','song-poetry','','[]','子真埋照地，千載委榛莽。',48,'全唐诗/poet.song.60000.json','["子真埋照地，千載委榛莽。", "知音久未會，遺蹤寂誰賞。", "華堂始基搆，皂蓋日來往。", "高風邈已遠，茲焉競長想。"]'),
('f123701f-83ef-4fa8-8c3f-be48aeb0d59b','湖南運使柯少卿用廣西提刑曹司勳遊嶽麓寺韵送廣西行俾令同賦','華鎮','宋','宋诗','song-poetry','','[]','昔聞湘西寺，夢想投雙脚。',240,'全唐诗/poet.song.60000.json','["昔聞湘西寺，夢想投雙脚。", "身境隔楚越，攘臂無由攫。", "此日陪勝集，當年意彌廓。", "山環秀色遠，地勝真興託。", "赤日朗泥金，彤霞煥塗雘。", "追隨得後乘，登頓閑芒屩。", "窮幽際高深，歷險遵厓堮。", "北斗近在手，南溟消一酌。", "天風韵球琳，世味羶醴酪。", "躡屐想王謝，登舟成李郭。", "欣戚起參差，去住同紛錯。", "常時惜聚散，靈襟費恢拓。", "契理在相忘，言志亦盍各。", "無然結惆悵，聊用聆談噱。", "况當擁斧繡，不類居榛壑。", "金石雖欲流，風雲正相薄。", "蕣華夕則隕，蠟味淡可嚼。", "照坐蘭玉明，揮翰珠璣落。", "青嶂繚雲構，紅紗羅蠟爝。", "景勝語難工，柔毫幾頻閣。"]'),
('bda55db0-fb8d-4808-b5c1-b0101205f488','早發京口舟中','華鎮','宋','宋诗','song-poetry','','[]','解維去北固，掛席指西湘。',216,'全唐诗/poet.song.60000.json','["解維去北固，掛席指西湘。", "秋江迥以朗，物色見毫芒。", "篷窗列遠岫，天際插連檣。", "鷗鷺簇寒沙，蒹葭肅初霜。", "千里伊此始，扁舟前路長。", "路長念行遲，家遠情難忘。", "回首東南引，朝陽汎滄凉。", "稽山不可見，况復梓與桑。", "日月無停晷，星漢迭回光。", "人生天宇間，安得戀故鄉。", "徒勞非所願，薄言奉高堂。", "念昔楚與越，相望若參商。", "山川有分守，出入多譏防。", "道泰共家國，路夷闢關梁。", "勉從四方事，及此筋力强。", "羈宦真飛蓬，飄颻隨風翔。", "遠近不自我，東西竟何常。", "君子貴知命，世路各有方。"]'),
('b3d8a9a1-644d-48d8-9bbc-528a5833dc93','巫山神女詩','華鎮','宋','宋诗','song-poetry','','[]','巫娥美無度，綽約姑射倫。',96,'全唐诗/poet.song.60000.json','["巫娥美無度，綽約姑射倫。", "冰雪照肌骨，被服丹霞裙。", "蘭膏皆臭腐，天香有清芬。", "手提瑶華枝，乘鸞弄氤氳。", "緬邈相光彩，杳然喪塵紛。", "楚王夢見之，三歲情如醺。", "伊人竟何許，宛在陽臺下。", "宋生未見稱，朝暮自雲雨。"]'),
('4c114645-c0c8-4d41-a76b-31a33a81cb29','襄陽道中望鹿門山','華鎮','宋','宋诗','song-poetry','','[]','龐公昔避世，全家入翠微。',48,'全唐诗/poet.song.60000.json','["龐公昔避世，全家入翠微。", "空遣山下路，不知今是非。", "高風久寂寥，世路誰與歸。", "山頭日欲落，搔首重依依。"]'),
('0589ad83-5534-44f9-b87f-b7841871d1c2','采石','華鎮','宋','宋诗','song-poetry','','[]','夜暗梟狐響，天明蛟蜃伏。',228,'全唐诗/poet.song.60000.json','["夜暗梟狐響，天明蛟蜃伏。", "君子貴知幾，乘時介多福。", "中原昔不競，淮海波濤蹙。", "高視孫仲謀，雄心冀前躅。", "大明將昇騰，氛祲先驅逐。", "周師東南指，淮澨歸亭毒。", "遺燼倚江流，熒熒怯風燭。", "真人方遠略，墜緒勞君續。", "後至祇取羞，先迷庶能復。", "時雨動民望，遠猷走辰告。", "密算結浮梁，長驅踐平陸。", "敵氣沮飛渡，軍勢乘破竹。", "鱗羽不及張，巢窟駭傾覆。", "百年厓石稜，鎸刻猶在目。", "風濤杳不作，水落秋山足。", "留與釣魚舟，穿維宛相屬。", "由來一带水，未勝長城曲。", "道梗叛或易，時清去還速。", "何必鑿秦淮，佳氣自消縮。"]'),
('172874dd-3f6d-4f65-b502-50745b35428d','銅陵阻風','華鎮','宋','宋诗','song-poetry','','[]','常言秋冬交，泝江便風多。',168,'全唐诗/poet.song.60000.json','["常言秋冬交，泝江便風多。", "我行已旬餘，有風不生波。", "直道不敢往，曲港傷逶迤。", "昨日始張帆，騰凌越盤渦。", "脩途驛未歷，寒日景已俄。", "夜半轉巨橐，驚濤擁蛟鼉。", "天明更雄厲，尋尺不得過。", "密雨喜初霽，整衣起婆娑。", "倚檣玩輕鷗，遵渚踏寒莎。", "羨望東行舟，飛帆峭嵯峨。", "回數挽引日，多少唯與阿。", "行止風在天，天爲謂之何。", "欲歎翻自笑，聊爲阻風歌。", "來日如未已，且用資吟哦。"]'),
('baf4f349-91ea-44f5-924b-3abbedb1ad6a','書李西臺詩帖','華鎮','宋','宋诗','song-poetry','','[]','古來論書如論馬，不看皮毛看筋骨。',224,'全唐诗/poet.song.60000.json','["古來論書如論馬，不看皮毛看筋骨。", "赤驥雖瘦神彩駿，骨筋强奇氣突兀。", "點畫筋骨生筆端，昔人小伎不自忽。", "用筆臨紙如用兵，敵陣深攻橫馳突。", "水墨淋漓無顧藉，鋒毫來往輕陵捽。", "皂鵰蒼隼搏秋天，老蜃長蛟結幽窟。", "李唐末年天下亂，劍戟縱橫文藝缺。", "鍾王遺法散不傳，二百年來更蕪沒。", "卧豪側管不到紙，狐渡春冰輕窸窣。", "尋蹤貌影見形似，坐擬前人已超越。", "禿盡南山千兔毫，妙絕曾無一毛髮。", "西臺老李得古意，揮灑工夫通怳惚。", "昔聞已覺心思啟，今見頓使蒙蔽發。", "縹襮欲卷更復開，明發臨風到華月。"]'),
('be971fca-b1b6-49b4-9e8a-482484f5d96c','次韵和湖南運判司勳曹公衡山行','華鎮','宋','宋诗','song-poetry','','["\u8861\u5c71"]','大山隠隠橫如衡，北與常嶽當天經。',384,'全唐诗/poet.song.60000.json','["大山隠隠橫如衡，北與常嶽當天經。", "發奇吐怪無時停，旦暮生氣凝紫青。", "隆隆翠光照南溟，是爲朱陵赤帝庭。", "奇峰八九羅明星，真仙宴集通層城。", "飛樓疊閣到絕頂，環回照映真雲屏。", "流泉夜逐銀河傾，危石上與搘機撐。", "輕輿飛蓋不知峻，來往常見林梢盈。", "炳靈彌世動宸扆，儀物嚴奉侔朝廷。", "天章國寶萃神異，金華墨彩光崢嶸。", "提封奄有神仙宅，星軺部按經雲扃。", "傳經俯可拾青紫，摛華早合登蓬瀛。", "肯跨蘇耽嶺頭鶴，輕逐浮丘吹玉笙。", "暫將勝具擬玄度，行與大帝調六英。", "漢庭已當思汲黯，紫坦歸次光晶熒。", "尋源况曾到雞足，根塵洗盡丹臺靈。", "宰官應世通有誠，飛雲何意超鴻冥。", "玄珠不獨罔象得，白雪一點洪鑪生。", "詩豪墨妙天許并，雲崖蘇壁增新銘。", "紫虛羽蓋飄竛竮，湘源寶瑟鳴蘭汀。", "蛾眉旋顧若自失，霜威一肅春華零。", "琴高睥睨不敢請，遺鯉失步奔長鯨。", "平反犴獄成虛囹，姦豪斂衽無辜寧。", "隨車靄靄留餘馨，千里卷盡重雲暝。", "威形不習西門豹，襟風遠析湘人酲。"]'),
('e2bf92d5-c1b1-410e-bf73-08373e3b7bb2','雲溪行','華鎮','宋','宋诗','song-poetry','','[]','雲溪發源自雲門，千古流注越山根。',256,'全唐诗/poet.song.60000.json','["雲溪發源自雲門，千古流注越山根。", "城金河玉雖已遠，南來波浪長崩奔。", "蒼崖峭壁三十里，翠烟紫霧籠寒水。", "往來鷗鷺逐波頭，出沒魚龍穿石齒。", "清時有客寄扁舟，長嘯日來溪上遊。", "緩教霜翮追清曲，漫引輕絲下碧流。", "有時醉卧閒雙槳，不知船逐樵風上。", "挹盡千巖曉氣清，聽我萬壑寒泉響。", "無端側耳鳳凰鳴，却跨青鸞上玉京。", "流連丹桂三秋色，辜負寒松半夜聲。", "十年南北何擾擾，咫尺溪頭不成到。", "幾回魂夢似當時，夢覺尚疑雲滿抱。", "今日羈縻江海曲，折腰翻爲斗升粟。", "山頭日落見雲歸，自怪此身何局促。", "皂雕萬里在一飛，蛟龍未必藉溝池。", "風月好時心似水，嘯歌聊可解人頤。"]'),
('9543fb97-e16c-4f06-a6f4-3e14cbb4cd97','梅花','華鎮','宋','宋诗','song-poetry','','[]','當年杜老對梅花，曾憶何郎淮海作。',64,'全唐诗/poet.song.60000.json','["當年杜老對梅花，曾憶何郎淮海作。", "今日江城歲云暮，還思杜老歌東閣。", "春風冬雪三百年，中間梅花歲歲妍。", "清才一往不可見，惟有凌寒曉妝面。"]'),
('3d3ac727-0389-49bc-8c20-d45a0cac02e4','燈','華鎮','宋','宋诗','song-poetry','','[]','細風吹雨霑疏幕，夜久燈青寒盡落。',128,'全唐诗/poet.song.60000.json','["細風吹雨霑疏幕，夜久燈青寒盡落。", "未言金椀沃龍膏，且免鄰牆旋彫鑿。", "淄川老翁牙齒疏，四十始欲披儒衣。", "况是雙鬢青絲好，不應便作衡門老。", "他年清切許雄飛，人間萬事隨動頤。", "不獨千枝照羅幕，廐溷蠟淚當成堆。", "吾鄉先達少陵後，功名爭光臯與伊。", "虛齋一盞半明滅，賓主清談到明發。"]'),
('bf7f48d4-4460-41c6-9ad8-6ab97dc47435','叢玉山','華鎮','宋','宋诗','song-poetry','','[]','石城深沈有神櫝，蒼璧青圭森矗矗。',384,'全唐诗/poet.song.60000.json','["石城深沈有神櫝，蒼璧青圭森矗矗。", "榛蕪未薙見圓石，沆瀣初披得叢玉。", "寒流噴薄洗煩慮，翠光斂舒瑩人目。", "兩巖神化瑣烟霞，一逕天成徧厓谷。", "朝陽杲杲亙東嶺，夕陽亭亭載西陸。", "拄天峻極天爲低，交雲拔起雲常簇。", "風箕雨畢列華藻，木客雲娥儼儀服。", "應真示相契空門，洪厓脫身度塵躅。", "露天池寒星斗簇，合巖石暖莓苔綠。", "石臺登眺多舂容，金柜緘封富奇蓄。", "幽竇懸泉歲清淺，碧嵐如雲日紛鬰。", "蓮花風度夏香深，芙蓉露裛秋華肅。", "靈龜戲游物自壽，師子雄騰誰與逐。", "金魚熻嚇待時雨，石鼇贔屭依蒼麓。", "滿川雲起老龍吟，虛谷風清雕虎伏。", "主人天與經綸器，才名早在神仙籙。", "清時北闕方我須，雅興東山難自速。", "脩途未許頓長轡，勝地何妨揭華屋。", "雙巖挹秀左右逢，快覽凭高心眼足。", "夜邀秋月得丹桂，曉迓冬曦看若木。", "飛梁續徑壓蒼磯，投隙團茅繚脩竹。", "雲軒芝蓋俯可揖，水色天光濃溢掬。", "綠野篇章惜未多，輞川圖畫今能續。", "披圖已覺思超越，過眼應忘身跼束。"]'),
('8292798c-9c1c-41d7-aca6-0fe8d3fb5c8d','徐元立出示李父龍角水壁詩邀予繼作因成長篇','華鎮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','龍德神變通盈虛，孕育乃與鰷鱨俱。',384,'全唐诗/poet.song.60000.json','["龍德神變通盈虛，孕育乃與鰷鱨俱。", "被鱗戴角形非無，飛潜食息皆時須。", "太上道德體未刳，神物咸萃天王都。", "坰林苑囿馴騶虞，宮中高閣鳴鵷雛。", "玄龜負卦洛水隅，戴因之獸游廣途。", "此時應龍如鷗鳬，翔泳宮沼何舒于。", "庖犧正位膺乾符，是出德水呈神圖。", "彝倫九敘時紛敷，蒼白紀官各有呼。", "皇風綿邈雖已徂，下至虞舜成帝謨。", "豢御世守職未渝，節時飲食如哺烏。", "玄冥失職水正蕪，物乃坻伏潜天區。", "耳目接識非朝晡，疑無驚有無智愚。", "葉公好尚俄有孚，真物來止還驚吁。", "遺鱗脫角時可俘，世俗往往疑見誣。", "淮上乃有桑門徒，曾見得之青草湖。", "紺鱗兩葉角一跗，坳漥猶見藏泥塗。", "堅質溫潤如荆瑜，冷光凌亂侵琨珸。", "我疑仙客催盤盂，乘興擊破鴛鴦壺。", "又似石尉矜豪麤，醉中敲折青珊瑚。", "此物殊觀惟可娛，得名非似齊人竽。", "但恨不見真形軀，冥飛杳渺何能拘。", "昔人市骨求駿駒，毋在文駟交馳驅。", "靈德况與魑魅殊，沈潜非爲禹鼎模。", "喬岑十疊窮崎嶇，鯨波萬里不可逾。"]'),
('4aefabfc-d2d4-4521-bfc2-60d1e036bf25','次韵劉三秀才瑞香二首  其一','華鎮','宋','宋诗','song-poetry','','[]','南枝碎玉飄溟濛，春光次第海天東。',96,'全唐诗/poet.song.60000.json','["南枝碎玉飄溟濛，春光次第海天東。", "紫囊夜發香中瑞，芳蹊不用夭桃紅。", "開謝忍從風日下，形容聊寄牋毫中。", "珠玉交輝色璀璨，塤篪迭奏聲和同。", "園林光價遠莫擬，造化機權疑未公。", "會須折向玉峰去，追隨鳴珮搖天風。"]'),
('dbaeb674-3805-4e96-9f98-ce79151c81eb','次韵劉三秀才瑞香二首  其二','華鎮','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','玄機冥運依鴻濛，執規歲歲來司東。',96,'全唐诗/poet.song.60000.json','["玄機冥運依鴻濛，執規歲歲來司東。", "乘時剪裁馭大巧，梢頭幾度鋪青紅。", "匡廬幽香誰見賞，直須爲瑞芳華中。", "餘寒未盡已爛縵，似領千花修會同。", "貴名舊尊木芍藥，第品應許居上公。", "願分靈根徧四海，充塞天地皆香風。"]'),
('51a6b12c-dfb4-48d0-a904-bbd77160a211','道守董公重成寇公樓集宴僚屬因賦長句','華鎮','宋','宋诗','song-poetry','','[]','九峰翠滴天光曉，日射三川波浩溔。',384,'全唐诗/poet.song.60000.json','["九峰翠滴天光曉，日射三川波浩溔。", "朱門畫戟古城西，岑樓新駕長林杪。", "飛欒疊楶橫紛錯，重覆交疏深䆗窱。", "幕開碧落四垂低，屏列好山千疊遶。", "卧聽羲馭轉轣轆，坐看星車回縹緲。", "嘯歌微動薄寥虛，樽俎平鋪俯蘿蔦。", "耳前燕語得其所，目外鵬圖莫之夭。", "簾翻江日酒霞鮮，窗度天風香穗裊。", "平昔萊公此棲止，目窮佳麗真明瞭。", "雲歸自惜故鄉非，日低誰念長安杳。", "帝居閶闔深難叫，世路風波古瀰渺。", "饑烏得食嚇鵷雛，嫫母在宮憎窈窕。", "干將莫耶不惜折，威鳳麒麟恥羈擾。", "北瞻曾冠拱辰星，南飛却過隨陽烏。", "彭殤滔滔不足問，榮悴冥冥未宜了。", "沐猴纓弁竟非真，明玉在塵終自皦。", "百年同氣姤賢守，抉隠搜遺思遠紹。", "網羅勝賞得偏多，懷想高風情不少。", "鯢蟠陳迹久寂寞，虹揭畫梁重夭矯。", "已知青竹播馨香，更看華牓延光皎。", "自憐值遇分濩落，重此登臨思悽悄。", "舉目頻驚五嶺明，回頭却顧長沙藐。", "局促可能參庾亮，清平豈是依劉表。", "楚天不斷故關迷，危欄倚徧前山小。"]'),
('57360751-4a39-4225-ab58-fbf8b57b2d63','新開河','華鎮','宋','宋诗','song-poetry','','[]','淮山畎澮奔東海，注作陂池地形改。',64,'全唐诗/poet.song.60000.json','["淮山畎澮奔東海，注作陂池地形改。", "濁水曾無五尺深，驚濤便欲千尋駭。", "人魚漏網逞胸臆，老蚌乘陰弄光彩。", "東風吹斷西來流，見爾枯虛當可待。"]'),
('e9a4ca43-8fb8-4749-850d-0a8ebdf7fec7','如意院井詩二首  其一','華鎮','宋','宋诗','song-poetry','','[]','太平興國古佛剎，小院得名如意輪。',160,'全唐诗/poet.song.60000.json','["太平興國古佛剎，小院得名如意輪。", "何人默識原地脈，鑿井正會甘泉津。", "闊容三尺白銀罋，深可二丈青絲緡。", "夏凉未覺冰雪冷，味美不啻醍醐珍。", "寺僧知愛不忍惜，汲引無間都城人。", "鳴鐘聲歇更漏促，天雞初報扶桑晨。", "側肩接足負擔者，排闥爭湊蒼苔唇。", "絲瓶上下掉孔急，語笑嘈雜春雷振。", "永日迢迢既云暮，健夫噏噏皆嚬呻。", "萬人已喜用周給，一泓依舊清奫淪。"]'),
('390e5831-e854-41db-9ed1-a5e1333799ea','如意院井詩二首  其二','華鎮','宋','宋诗','song-poetry','','[]','井德本來無得喪，居遷乃見井有仁。',144,'全唐诗/poet.song.60000.json','["井德本來無得喪，居遷乃見井有仁。", "深穿闊甃世不少，聞名索實多非真。", "潢汙方集已登幹，驕陽未久先飛塵。", "盈虛既與陰晴變，安用華屋床雕銀。", "崇寧元年五六月，僦居偶在寺井濱。", "曾經畏日曝累朔，亦見霖雨傾彌旬。", "碧痕澄澄古甃上，消長不改蒼龍鱗。", "莫嫌營置近闤闠，莫厭資取多紛綸。", "深院無人轆轤靜，焉知此井常清新。"]'),
('aa8dfbe9-5b46-4a5a-9b2d-c04e291f1ffa','李光道見過贈詩','華鎮','宋','宋诗','song-poetry','','[]','高槐上拂青天面，枝疏不得驚禽戀。',160,'全唐诗/poet.song.60000.json','["高槐上拂青天面，枝疏不得驚禽戀。", "槐下官曹何冷落，去馬來牛色多倦。", "春風綠楊暗虛室，秋雨蒼苔鎖深院。", "三見牆頭梅子花，一字不畫塵侵硯。", "宛如太古兩相忘，况復飛蓋追遊宴。", "有時獨詠西園詩，想像清風情眷眷。", "門前忽報華軒過，邂逅開懷如昔見。", "目擊便嗟相得晚，更僕清談盡黄卷。", "顧我迂疏何所取，似君秀穎迺可羨。", "少壯應須努力時，人間歲月如流電。"]'),
('b5a41765-85be-4015-b877-97685d0a201f','寄贈永嘉鄭先生','華鎮','宋','宋诗','song-poetry','','[]','滎陽人物世仍有，文雅風流傳巳久。',288,'全唐诗/poet.song.60000.json','["滎陽人物世仍有，文雅風流傳巳久。", "廣文獨步天寶年，才名曾在諸公右。", "新詩高陪屈宋遊，神翰遠與鍾王偶。", "更覺丹青到微妙，獨將造化爭妍醜。", "一封入奏蓬萊宮，三絕題自君王手。", "當時盛事雖云遠，今日高風曾未朽。", "親逢夫子滄海頭，重起清芬百年後。", "倦遊不肯依梁苑，尚德自甘耕谷口。", "方外聰明已木雞，人間事變皆芻狗。", "子雲寂寞守儋石，靖節軒昂遺五斗。", "不試惟令曲藝工，久幽更覺機神厚。", "詩情渺與江湘迥，畫筆能教鬼神走。", "論工子建已知親，較勝長康未應負。", "所嗟藻鑒闊楚越，猶使佳名在林藪。", "邂逅雖知近巖壑，栖遲尚苦拘塵垢。", "明明冰玉長在懷，望望烟霞屢驤首。", "何日傾心聽誦詩，他時洗眼看揮帚。", "狂歌且寄草堂客，佳句終慚杜陵叟。"]'),
('ecc327cd-a0d1-4a13-9de8-a9a0b7957504','陪和守宴城樓罷留望江山懷古','華鎮','宋','宋诗','song-poetry','','[]','歷陽城樓多好風，南來和雨飛溟濛。',288,'全唐诗/poet.song.60000.json','["歷陽城樓多好風，南來和雨飛溟濛。", "齊紈四座寂不動，六月酒面魚鱗紅。", "鈴齋無訟日多暇，時引大旆摩晴空。", "賓來不問禮數隔，披襟倚檻欣迎逢。", "平蕪不斷楚天闊，無數好山來望中。", "伊昔重瞳顧寰宇，八千西渡皆貔虎。", "叱咤風雲五六年，蓋世拔山寧不武。", "力盡江頭已蕭瑟，秋風未央亦禾黍。", "亂世英雄氣頗麤，當時還羨紫髯夫。", "箭重舟偏徐轉柁，舟中賓主亦歡呼。", "龍驤露橈下三峽，春草不合臨平湖。", "衣带縈迂寧足倚，桃葉渡之勝一葦。", "三閣香消春夢殘，空傳玉樹江南女。", "人間萬事無妍醜，過眼紛紛盡芻狗。", "祗有江山似舊時，從來却落漁樵手。", "懷春悲秋徒自苦，浮雲去來我何有。", "鳴絲案竹閒清唱，當軒更有盈樽酒。", "清時勝日臨高明，未愧黄金垂六鈕。"]'),
('fc9a095f-1296-486d-8537-ad507c9be81c','永嘉巡檢張侍禁廨舍闢洞名黄石','華鎮','宋','宋诗','song-poetry','','[]','下邳逋客赤松侶，興薄雲天寄廛市。',288,'全唐诗/poet.song.60000.json','["下邳逋客赤松侶，興薄雲天寄廛市。", "五世鳴鐘不自矜，肯向人前進遺履。", "素靈將傾赤精奮，羽翼當資天下士。", "夜半殷勤授素書，歷歷商郊阪泉旨。", "西過陳留得沛公，雲蒸龍躍相因倚。", "剪嬴傾項成帝業，廟謀勝算皆予起。", "漢家明堂窮壯觀，楹棟能收真杞梓。", "清塵獨步千載上，名實誰可繼其美。", "君家緒系出南陽，世服戎衣登祿仕。", "鳳毛益使家聲振，新以七書見天子。", "君居無事若山居，退食小齋日經始。", "茨茅塗土完且潔，栽花接果盈階戺。", "風月江山散不收，標題黄石寧虛爾。", "應懷祖武日自礪，功名將使旂常紀。", "今日中原久太平，頌聲交作干戈止。", "南過銅標束带方，玉帛梯航餘萬里。", "惟有祁連及賀蘭，朝廷未欲知疆理。", "儻推漢幄從衡術，定遠將軍何可擬。"]'),
('58b00ca2-7310-4ac2-909b-244374012ad1','南嶽僧仲仁墨畫梅花','華鎮','宋','宋诗','song-poetry','','["\u8861\u5c71"]','世人畫梅賦丹粉，山僧畫梅勻水墨。',176,'全唐诗/poet.song.60000.json','["世人畫梅賦丹粉，山僧畫梅勻水墨。", "淺籠深染起高低，烟膠翻在瑶華色。", "寒枝鱗皴節目老，似戰高風聲淅瀝。", "三苞兩朵筆不煩，全開半函如向日。", "疏點粉黄危欲動，縱掃香須輕有力。", "不待孤根暖氣回，分明寫出春消息。", "大空聲色本無有，宮徵青黄隨世識。", "達人玄覽徹根源，耳觀目聽縱橫得。", "禪家會見此中意，戲弄柔毫移白黑。", "佳句殷勤致兩番，深情邂逅高雙璧。", "不愁開謝逐東風，全勝當年隴頭驛。"]'),
('20496965-9880-409a-8467-5b3b3d3ff732','咏西施','華鎮','宋','宋诗','song-poetry','','[]','浣紗溪上浣紗女，野服山花照寒水。',163,'全唐诗/poet.song.60000.json','["浣紗溪上浣紗女，野服山花照寒水。", "含嚬慘淡不勝愁，猶使東鄰駭西里。", "山鳥淵魚無定識，俯見潜逃仰驚起。", "矜花睠月春復秋，長恐朱顔成暮齒。", "君王掄選入吳宮，吳宮寂寞無桃李。", "芙容一笑君意傾，宰嚭言行子胥死。", "姑蘇臺榭游麋鹿，闔閭城闕生荆杞。", "蛾眉倩盼應自成，築宮教習胡能美。", "當時掩抑無人顧，今日爲君除國恥。", "君莫怪騄驥鹽車弭耳時，誰人不作駑駘比。"]'),
('f4028ece-2c2b-4ca3-9cc6-bf2b8aa60f0e','次韵和劉五秀才重陽不見菊詩','華鎮','宋','宋诗','song-poetry','','[]','黄花長汎重陽酒，今日重陽花未有。',96,'全唐诗/poet.song.60000.json','["黄花長汎重陽酒，今日重陽花未有。", "莫傷節物此時非，少陵已歎移栽後。", "江梅滿枝春未來，紅藥開時春却歸。", "春前春後各自得，化工無私人莫測。", "明日籬邊金蘂黄，未應埋沒隨風霜。", "高堂滿汎黄金盞，相陪何用茱萸囊。"]'),
('4a6031f7-012b-47a3-99db-b158170281f4','贈別越帥蔡侍郎五十韵','華鎮','宋','宋诗','song-poetry','','[]','飛廉鼓橐開氛雺，玉龍盤礴堆蒼岫。',384,'全唐诗/poet.song.60000.json','["飛廉鼓橐開氛雺，玉龍盤礴堆蒼岫。", "雲崖左壁出高墉，環回占盡東南秀。", "高瞻牛女提封闊，下瞰閭閻烟火富。", "紫青巖壑敞屏幃，金碧樓臺錯紋繡。", "城西半規日欲落，天東一縷雲如鏤。", "人間未覺桂華昇，林梢先見金波溜。", "冰輪冉冉經箕斗，碧落沈沈失星宿。", "清光不斷萬象呈，目極塵寰了無覆。", "扶桑欲曉天雞唱，玉珮丁東咽殘漏。", "西南松桂碧參差，寒金碎玉高低透。", "春和二月融青宙，紅紫千花簇繁囿。", "香潔蜂蝶夜不知，暗和清影凝羅袖。", "暑雨晚隨虹影斷，炎威夜逼餘輝逗。", "南湖拂拂起輕颸，鑑光千里冰紈皺。", "星流一葉高梧下，玉刻千峰晚山瘦。", "桂子香凝零露漙，兔毫冷咽飛泉潄。", "六花舞絕平川壤，萬樹玲瓏綴瑩琇。", "凍雲收盡一輪寒，光華上下清交鬭。", "明眸朗鑒古難偶，許謝登臨亦虛覯。", "勝地埋藏祗自奇，千年林下輸猿狖。", "儒家宗主中郎裔，早掞春華甲英彀。", "量闊難窮渤澥遠，德馨未羨椒蘭臭。", "青雲有路早徊翔，要津策足頻馳驟。", "旒扆傾衷聆玉振，經綸溢耳摐金奏。"]'),
('07e1c88e-b658-400a-afaf-7fb5f3b974e8','田園四時 春 其一','華鎮','宋','宋诗','song-poetry','','[]','曉來風信從東轉，風中春氣生微暖。',64,'全唐诗/poet.song.60000.json','["曉來風信從東轉，風中春氣生微暖。", "隴頭殘雪已全銷，麥苗漸見青青滿。", "土脈膏疏日舒緩，鋤犁但覺塍畦短。", "桑葉生陰布穀鳴，可使流光容易晚。"]');
